def _format_event_date_range(start_date, end_date, start_time=None, end_time=None):
    """Format event date range for display. If start_time exists: 'Thu 30 Apr 2026 18:00 – Sun 03 May 2026 18:00'. Else date only: 'Sat 14 Mar 2026 – Sun 15 Mar 2026'."""
    if not start_date:
        return "—"
    try:
        time_fmt = "%H:%M"
        if hasattr(start_date, "strftime"):
            start_str = start_date.strftime("%a %d %b %Y")
        else:
            start_str = str(start_date)[:10] if start_date else "—"
        if start_time and hasattr(start_time, "strftime"):
            start_str += " " + start_time.strftime(time_fmt)
        if end_date and end_date != start_date:
            if hasattr(end_date, "strftime"):
                end_str = end_date.strftime("%a %d %b %Y")
            else:
                end_str = str(end_date)[:10]
            if end_time and hasattr(end_time, "strftime"):
                end_str += " " + end_time.strftime(time_fmt)
            return f"{start_str} – {end_str}"
        return start_str
    except Exception:
        return str(start_date) if start_date else "—"


# Host separator: SAS scrape may use middle dot · (U+00B7), bullet • (U+2022), or pipe |
# Rule: If host_club_name_raw contains · OR • OR | then SPLIT, take the LAST part, TRIM. Use that for club resolution only.
# Never attempt club matching on the association part. Examples:
#   "LASA (Laser Association of South Africa) · Club Mykonos" -> host_display = "Club Mykonos"
#   "29er Class Association · Saldanha Bay Yacht Club" -> host_display = "Saldanha Bay Yacht Club"
_HOST_SEPARATORS = ("\u00b7", "\u2022", "|")  # · • |


def _parse_host_after_separator(raw: str) -> str:
    """If raw contains · or • or |: split, take LAST part, trim. Use for club resolution only; never match on association. Handles ·, •, |."""
    if not raw or not isinstance(raw, str):
        return (raw or "").strip()
    s = raw.strip().lstrip(">").strip()
    parts = re.split(r"[\u00b7\u2022|]", s)
    if len(parts) > 1:
        last = (parts[-1] or "").strip()
        if last:
            return last
    return s


def _is_association_like(s: str) -> bool:
    """True if string looks like a class/association name rather than a club (e.g. '29er Class Association', 'LASA (Laser...)'). Used to prefer venue_raw as host when host_club_name_raw is association-only."""
    if not s or not isinstance(s, str):
        return False
    h = s.strip().lower()
    return (
        "association" in h or "associat" in h or h.startswith("lasa ") or h == "lasa"
        or "29er class" in h or "laser associat" in h or "dabchick class" in h
    )


def _host_display_from_row(r) -> str:
    """Preferred host_display for a row: use venue_raw when host_club_name_raw parses to association-like; else parsed host_club_name_raw."""
    raw_host = (r.get("host_club_name_raw") or "").strip()
    venue = (r.get("venue_raw") or "").strip()
    part = _parse_host_after_separator(raw_host)
    if _is_association_like(part) and venue:
        return venue
    return part or ""


def _best_club_substring_match(event_lower: str, club_rows, unassigned_id):
    """If event_lower contains a club abbrev or fullname as substring, return (club_id, club_abbrev, club_fullname) for the longest match (same idea as load_events_csv_to_db.resolve_club_from_event_name). Excludes virtual Unassigned."""
    if not event_lower or not event_lower.strip():
        return None
    event_lower = event_lower.strip().lower()
    candidates = []
    for row in club_rows:
        cid = row.get("club_id")
        if cid is None:
            continue
        if unassigned_id is not None and int(cid) == int(unassigned_id):
            continue
        abbr_l = (row.get("abbr_l") or "").strip()
        full_l = (row.get("full_l") or "").strip()
        if abbr_l and abbr_l in event_lower:
            candidates.append((cid, len(abbr_l)))
        if full_l and full_l in event_lower:
            candidates.append((cid, len(full_l)))
    if not candidates:
        return None
    by_club = {}
    for cid, length in candidates:
        by_club[cid] = max(by_club.get(cid, 0), length)
    best_cid = max(by_club.items(), key=lambda x: x[1])[0]
    for row in club_rows:
        if row.get("club_id") == best_cid:
            abbr = (row.get("club_abbrev") or "").strip()
            full = (row.get("club_fullname") or "").strip()
            return (best_cid, abbr, full)
    return None


def _apply_event_title_club_match(cur, upcoming_rows, past_rows):
    """After host/venue equality match: if host_club_id still NULL, resolve club from club name/abbrev appearing inside event_name (then venue/location), same as CSV loader. Reduces spurious Unassigned when SAS omits host but title names the club."""
    if not table_exists("clubs"):
        return
    uid = _get_unassigned_club_id()
    cur.execute(
        """
        SELECT club_id,
               trim(lower(coalesce(club_abbrev, ''))) AS abbr_l,
               trim(lower(coalesce(club_fullname, ''))) AS full_l,
               club_abbrev, club_fullname
        FROM clubs
        WHERE ((club_abbrev IS NOT NULL AND trim(club_abbrev) != '')
            OR (club_fullname IS NOT NULL AND trim(club_fullname) != ''))
          AND lower(trim(coalesce(club_abbrev, ''))) != 'unassigned'
        """
    )
    club_rows = list(cur.fetchall() or [])
    if not club_rows:
        return
    for r in upcoming_rows + past_rows:
        if r.get("host_club_id"):
            continue
        name = (r.get("event_name") or "").strip()
        if not name:
            continue
        blob = " ".join(
            x
            for x in (
                name,
                (r.get("venue_raw") or "").strip(),
                (r.get("location_raw") or "").strip(),
            )
            if x
        ).strip()
        matched = None
        for text in (name.lower(), blob.lower()):
            if not text.strip():
                continue
            matched = _best_club_substring_match(text, club_rows, uid)
            if matched:
                break
        if matched:
            cid, abbr, full = matched
            r["host_club_id"] = cid
            r["club_abbrev"] = abbr
            r["club_fullname"] = full
            r["club_slug"] = _club_slug_from_name(full or abbr)


def _category_to_slug(category: str) -> str:
    """Slug from category: lower, replace spaces with '-', remove non-word characters. Example: Regional Championships → regional-championships."""
    if not category or not isinstance(category, str):
        return ""
    s = category.lower().strip()
    s = re.sub(r"[^a-z0-9\s\-]", "", s)
    s = re.sub(r"\s+", "-", s).strip("-")
    return s or ""


def _event_date_to_iso(d):
    if d is None:
        return ""
    if hasattr(d, "strftime"):
        try:
            return d.strftime("%Y-%m-%d")
        except Exception:
            return str(d)[:10]
    return str(d)[:10]


def _event_date_only(d):
    """Normalize DB date / datetime to date for comparisons."""
    if d is None:
        return None
    if hasattr(d, "date") and callable(d.date):
        try:
            return d.date()
        except Exception:
            pass
    if hasattr(d, "year"):
        from datetime import date as _date

        try:
            return _date(d.year, d.month, d.day)
        except Exception:
            pass
    return None


def _derive_sanction_level(r) -> str:
    """SAS = SA Sailing calendar / official source; CLUB = other. OTHER reserved for edge cases."""
    src = (r.get("source") or "").strip().lower()
    url = ((r.get("source_url") or "") + " " + (r.get("organiser") or "")).lower()
    if src == "sas":
        return "SAS"
    if "sailing.org.za" in url or "sa-sailing" in url.replace(" ", ""):
        return "SAS"
    if "worldsailing" in url or "sailing.org" in url and "sailing.org.za" not in url:
        return "OTHER"
    return "CLUB"


def _derive_event_state(r, is_past_panel: bool) -> str:
    """ACTIVE = today within [start_date, end_date] (inclusive); UPCOMING = future start; PAST = past panel only."""
    from datetime import date as _date

    today = _date.today()
    if is_past_panel:
        return "PAST"
    st = _event_date_only(r.get("start_date"))
    en = _event_date_only(r.get("end_date")) or st
    if not st:
        return "UPCOMING"
    if st <= today <= (en or st):
        return "ACTIVE"
    if st > today:
        return "UPCOMING"
    return "UPCOMING"


def _event_time_to_sort_seconds(t) -> int:
    """Seconds since midnight for sorting; missing/invalid time sorts after real times same day."""
    if t is None:
        return 999999
    s = str(t).strip()
    if not s:
        return 999999
    try:
        parts = s.replace(".", ":").split(":")
        h = int(float(parts[0])) if parts else 0
        m = int(float(parts[1])) if len(parts) > 1 else 0
        sec = int(float(parts[2])) if len(parts) > 2 else 0
        return h * 3600 + m * 60 + sec
    except Exception:
        return 999999


# Shared with /blank hub, /events, /events/type/*, club pages, /yearly-events, GET /api/events/upcoming-window.
UPCOMING_DISPLAY_SORT_VERSION = "upcoming_display_v2"


def _batch_entries_by_regatta_ids(cur, regatta_ids: list) -> dict[str, int]:
    """COUNT(*) raced rows per regatta_id for sort weighting (same idea as public /api/events entries)."""
    if not regatta_ids or not table_exists("results"):
        return {}
    uniq = list({str(r).strip() for r in regatta_ids if r and str(r).strip()})
    if not uniq:
        return {}
    cur.execute(
        """
        SELECT regatta_id::text AS rid, COUNT(*)::int AS n
        FROM results
        WHERE raced IS TRUE AND regatta_id::text = ANY(%s)
        GROUP BY regatta_id
        """,
        (uniq,),
    )
    return {str(row["rid"]): int(row["n"] or 0) for row in (cur.fetchall() or [])}


def _attach_event_card_display_sort_fields(
    cur,
    cards: list,
    *,
    series_max_entries_by_key: dict | None = None,
) -> None:
    """Mutate cards with entries_for_sort + series_years_count (same series keys as /yearly-events).

    entries_for_sort = max(current regatta entries, best historical entries for this series), matching
    yearly-events row ordering (max history entries).
    """
    if not cards:
        return
    if series_max_entries_by_key is None:
        series_max_entries_by_key, _ = _yearly_series_max_and_history_maps()
    rids = [(c.get("regatta_id") or "").strip() for c in cards if (c.get("regatta_id") or "").strip()]
    ent_map = _batch_entries_by_regatta_ids(cur, rids)
    series_map = _yearly_series_distinct_year_counts_map()
    for c in cards:
        rid = (c.get("regatta_id") or "").strip()
        regatta_e = int(ent_map.get(rid, 0))
        key = _yearly_event_series_key((c.get("event_name") or "").strip())
        c["series_years_count"] = int(series_map.get(key, 0)) if key else 0
        smax = int(series_max_entries_by_key.get(key, 0)) if key else 0
        c["entries_for_sort"] = max(regatta_e, smax)


def _sort_event_cards_display_order(cards: list, *, use_start_time: bool) -> list:
    """Established series (≥2 years) first, then entries, series depth, date; live tab ties on start_time."""
    sub = list(cards)
    sub.sort(
        key=lambda c: (
            0 if int(c.get("series_years_count") or 0) >= 2 else 1,
            -int(c.get("entries_for_sort") or 0),
            -int(c.get("series_years_count") or 0),
            c.get("start_date_iso") or "",
            (_event_time_to_sort_seconds(c.get("start_time")) if use_start_time else 0),
            (c.get("event_name") or "").lower(),
            int(c.get("event_id") or 0),
        )
    )
    return sub


def _apply_upcoming_display_sort(
    cur,
    upcoming_only_cards: list,
    *,
    series_max_entries_by_key: dict | None = None,
) -> list:
    """Upcoming tab: same rules on /events, /events/type/*, club SAS calendar."""
    if not upcoming_only_cards:
        return []
    if series_max_entries_by_key is None:
        series_max_entries_by_key, _ = _yearly_series_max_and_history_maps()
    _attach_event_card_display_sort_fields(
        cur, upcoming_only_cards, series_max_entries_by_key=series_max_entries_by_key
    )
    return _sort_event_cards_display_order(upcoming_only_cards, use_start_time=False)


def _apply_live_display_sort(
    cur,
    live_cards: list,
    *,
    series_max_entries_by_key: dict | None = None,
) -> list:
    """Live tab: same weighting as upcoming; same-day ties on start_time."""
    if not live_cards:
        return []
    if series_max_entries_by_key is None:
        series_max_entries_by_key, _ = _yearly_series_max_and_history_maps()
    _attach_event_card_display_sort_fields(
        cur, live_cards, series_max_entries_by_key=series_max_entries_by_key
    )
    return _sort_event_cards_display_order(live_cards, use_start_time=True)


def _compute_hub_upcoming_window_payload(
    items: list[dict],
    today_iso: str | None = None,
    window_days: int = 5,
    limit: int = 10,
) -> dict:
    """Next upcoming anchor + window_days; same ordering as /events upcoming (entries + series years)."""
    today_iso = today_iso or date.today().isoformat()

    def _sd(e: dict) -> str:
        return (e.get("start_date") or "")[:10]

    def _live(e: dict) -> bool:
        s, ed = _sd(e), (e.get("end_date") or e.get("start_date") or "")[:10]
        return bool(s and ed and s <= today_iso <= ed)

    cand = [e for e in items if not _live(e) and _sd(e) >= today_iso]
    empty_sig = hashlib.sha256((UPCOMING_DISPLAY_SORT_VERSION + "\nempty").encode("utf-8")).hexdigest()[:24]
    if not cand:
        return {
            "sort_version": UPCOMING_DISPLAY_SORT_VERSION,
            "sort_signature": empty_sig,
            "anchor_date": None,
            "window_end": None,
            "items": [],
        }
    anchor = min(_sd(e) for e in cand)
    ad = datetime.strptime(anchor, "%Y-%m-%d").date()
    window_end = (ad + timedelta(days=window_days)).isoformat()
    windowed = [e for e in cand if anchor <= _sd(e) <= window_end]

    def _hub_ent(e: dict) -> int:
        if e.get("entries_for_sort") is not None:
            return int(e["entries_for_sort"])
        return max(int(e.get("entries") or 0), int(e.get("entries_max_series") or 0))

    windowed.sort(
        key=lambda e: (
            0 if int(e.get("series_years_count") or 0) >= 2 else 1,
            -_hub_ent(e),
            -int(e.get("series_years_count") or 0),
            _sd(e),
            (e.get("event_name") or "").lower(),
            str(e.get("regatta_id") or ""),
        )
    )
    sl = windowed[:limit]
    sig_src = UPCOMING_DISPLAY_SORT_VERSION + "\n" + "\n".join(
        f"{_sd(e)}|{e.get('event_name') or ''}|{e.get('regatta_id') or ''}|{_hub_ent(e)}|{int(e.get('series_years_count') or 0)}"
        for e in sl
    )
    sig = hashlib.sha256(sig_src.encode("utf-8")).hexdigest()[:24]
    return {
        "sort_version": UPCOMING_DISPLAY_SORT_VERSION,
        "sort_signature": sig,
        "anchor_date": anchor,
        "window_end": window_end,
        "items": sl,
    }


def _sort_past_event_cards(cards: list) -> list:
    order_san = {"SAS": 0, "CLUB": 1, "OTHER": 2}

    def date_key(c):
        return c.get("start_date_iso") or ""

    out = []
    for s in ("SAS", "CLUB", "OTHER"):
        sub = [c for c in cards if (c.get("sanction_level") or "CLUB") == s]
        sub.sort(key=date_key, reverse=True)
        out.extend(sub)
    return out


