def _get_site_stats():
    """Single source for the 4 homepage stats. Cached 5min. Returns active_sailors, classes_sailed, regattas_sailed, races_raced. Used by /api/site-stats and /admin/dashboard-data."""
    cached = get_cached("site_stats", ttl_seconds=300)
    if cached is not None:
        return cached
    conn = None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        # Sailors: same filter as admin_active_sailors (regatta must have a date so badge count = table rows)
        cur.execute("""
            SELECT COUNT(DISTINCT sailor_id) AS active_sailors
            FROM (
                SELECT r.helm_sa_sailing_id AS sailor_id FROM results r
                JOIN regattas reg ON reg.regatta_id = r.regatta_id
                WHERE r.raced = TRUE AND r.helm_sa_sailing_id IS NOT NULL AND r.helm_sa_sailing_id::text != ''
                  AND (reg.end_date IS NOT NULL OR reg.start_date IS NOT NULL)
                UNION ALL
                SELECT r.crew_sa_sailing_id AS sailor_id FROM results r
                JOIN regattas reg ON reg.regatta_id = r.regatta_id
                WHERE r.raced = TRUE AND r.crew_sa_sailing_id IS NOT NULL AND r.crew_sa_sailing_id::text != ''
                  AND (reg.end_date IS NOT NULL OR reg.start_date IS NOT NULL)
            ) u
        """)
        row = cur.fetchone()
        val = row.get("active_sailors") if row else None
        active_sailors = int(val) if val is not None else 0
        # Classes Sailed: distinct class_name in results, excluding Unknown
        cur.execute("""
            SELECT COUNT(DISTINCT c.class_name) AS n
            FROM results r
            JOIN classes c ON c.class_id = r.class_id
            WHERE c.class_name <> 'Unknown'
        """)
        row_cl = cur.fetchone()
        classes_sailed = int(row_cl["n"]) if row_cl and row_cl.get("n") is not None else 0
        # Regattas: only those with results (matches regattas/with-counts list)
        cur.execute("""
            SELECT COUNT(DISTINCT r.regatta_id) AS regattas_sailed
            FROM regattas r
            JOIN results res ON res.regatta_id = r.regatta_id
            WHERE res.raced = TRUE
        """)
        row3 = cur.fetchone()
        val3 = row3.get("regattas_sailed") if row3 else None
        regattas_sailed = int(val3) if val3 is not None else 0
        cur.execute("SELECT COUNT(*) AS races_raced FROM results r WHERE r.raced = TRUE")
        row4 = cur.fetchone()
        val4 = row4.get("races_raced") if row4 else None
        races_raced = int(val4) if val4 is not None else 0
        cur.close()
        result = {"active_sailors": active_sailors, "classes_sailed": classes_sailed, "regattas_sailed": regattas_sailed, "races_raced": races_raced}
        set_cached("site_stats", result, ttl_seconds=300)
        return result
    except Exception as e:
        if conn:
            try:
                conn.rollback()
            except Exception:
                pass
        return {"active_sailors": None, "classes_sailed": None, "regattas_sailed": None, "races_raced": None, "error": str(e)}
    finally:
        if conn:
            return_db_connection(conn)


@app.get("/api/site-stats")
def api_site_stats():
    """Site stats for dashboard. Uses same sources as search. Cached 5min. Delegates to _get_site_stats()."""
    return _get_site_stats()


