@app.get("/api/site-stats-audit")
def api_site_stats_audit():
    """Compare site-stats counts with search-aligned counts. Same sources as /api/search and /api/regattas/with-counts."""
    conn = None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        # Current site-stats: same as _get_site_stats (regatta date filter)
        cur.execute("""
            SELECT COUNT(DISTINCT sailor_id) AS active_sailors
            FROM (
                SELECT r.helm_sa_sailing_id AS sailor_id FROM results r
                JOIN regattas reg ON reg.regatta_id = r.regatta_id
                WHERE r.raced = TRUE AND r.helm_sa_sailing_id IS NOT NULL AND r.helm_sa_sailing_id::text != ''
                  AND (reg.end_date IS NOT NULL OR reg.start_date IS NOT NULL)
                UNION ALL
                SELECT r.crew_sa_sailing_id AS sailor_id FROM results r
                JOIN regattas reg ON reg.regatta_id = r.regatta_id
                WHERE r.raced = TRUE AND r.crew_sa_sailing_id IS NOT NULL AND r.crew_sa_sailing_id::text != ''
                  AND (reg.end_date IS NOT NULL OR reg.start_date IS NOT NULL)
            ) u
        """)
        row = cur.fetchone()
        active_from_results = int(row["active_sailors"]) if row else 0
        # Search-aligned: sailors in sas_id_personal who have at least one result (helm or crew)
        cur.execute("""
            SELECT COUNT(DISTINCT s.sa_sailing_id::text) AS cnt
            FROM sas_id_personal s
            WHERE EXISTS (
                SELECT 1 FROM results r
                WHERE r.raced = TRUE
                  AND (r.helm_sa_sailing_id::text = s.sa_sailing_id::text OR r.crew_sa_sailing_id::text = s.sa_sailing_id::text)
            )
        """)
        row = cur.fetchone()
        searchable_sailors_with_results = int(row["cnt"]) if row else 0
        # Current: all regattas
        cur.execute("SELECT COUNT(*) AS cnt FROM regattas")
        row = cur.fetchone()
        regattas_total = int(row["cnt"]) if row else 0
        # Search-aligned: regattas with at least one result (matches regattas/with-counts)
        cur.execute("""
            SELECT COUNT(DISTINCT r.regatta_id) AS cnt
            FROM regattas r
            JOIN results res ON res.regatta_id = r.regatta_id
            WHERE res.raced = TRUE
        """)
        row = cur.fetchone()
        regattas_with_results = int(row["cnt"]) if row else 0
        cur.close()
        return {
            "site_stats": {"active_sailors": active_from_results, "regattas_sailed": regattas_total},
            "search_aligned": {"sailors_with_results": searchable_sailors_with_results, "regattas_with_results": regattas_with_results},
            "match": active_from_results == searchable_sailors_with_results and regattas_total == regattas_with_results,
        }
    except Exception as e:
        if conn:
            try:
                conn.rollback()
            except Exception:
                pass
        return {"error": str(e)}
    finally:
        if conn:
            return_db_connection(conn)


THUMBNAIL_PROXY_MAX_BYTES = 2 * 1024 * 1024  # 2MB


def _thumbnail_fetch_image(url: str, headers: dict) -> tuple:
    """Fetch URL; if response is image/* return (content, content_type). Else (None, None)."""
    try:
        r = httpx.get(url, timeout=10, follow_redirects=True, headers=headers)
        if r.status_code != 200:
            return (None, None)
        ct = (r.headers.get("content-type") or "").split(";")[0].strip().lower()
        if ct.startswith("image/"):
            body = r.content
            if len(body) > THUMBNAIL_PROXY_MAX_BYTES:
                return (None, None)
            return (body, ct or "image/jpeg")
        return (None, None)
    except Exception:
        return (None, None)


@app.get("/api/thumbnail")
def api_thumbnail(url: str = Query(..., description="Image URL to proxy (any http(s); fetches image or og:image from HTML)")):
    """Proxy thumbnail so it loads (avoids CORS). Fetches URL; if HTML, tries og:image and returns that image."""
    u = (url or "").strip().replace("&amp;", "&").replace("&#38;", "&")
    if not u or not u.startswith(("http://", "https://")):
        raise HTTPException(status_code=400, detail="Invalid url")
    ul = u.lower()
    headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; rv:91.0) Gecko/20100101 Firefox/91.0"}
    if "fbcdn" in ul or "facebook" in ul:
        headers["Referer"] = "https://www.facebook.com/"
    if "instagram" in ul:
        headers["Referer"] = "https://www.instagram.com/"
    content, content_type = _thumbnail_fetch_image(u, headers)
    if content is not None:
        return Response(content=content, media_type=content_type or "image/jpeg")
    try:
        r = httpx.get(u, timeout=10, follow_redirects=True, headers=headers)
        if r.status_code != 200:
            raise HTTPException(status_code=404, detail="Image not found")
        ct = (r.headers.get("content-type") or "").split(";")[0].strip().lower()
        if ct.startswith("image/"):
            body = r.content
            if len(body) <= THUMBNAIL_PROXY_MAX_BYTES:
                return Response(content=body, media_type=ct or "image/jpeg")
        html = r.text
        for pattern in (
            r'<meta[^>]+property=["\']og:image["\'][^>]+content=["\']([^"\']+)["\']',
            r'<meta[^>]+content=["\']([^"\']+)["\'][^>]+property=["\']og:image["\']',
        ):
            m = re.search(pattern, html, re.I)
            if m:
                img_url = m.group(1).strip()
                if img_url and not img_url.startswith("http"):
                    base = str(r.url).rstrip("/")
                    img_url = (base + "/" + img_url.lstrip("/")) if base else img_url
                if img_url and img_url.startswith("http"):
                    content, content_type = _thumbnail_fetch_image(img_url, headers)
                    if content is not None:
                        return Response(content=content, media_type=content_type or "image/jpeg")
                break
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=502, detail=str(e))
    # No image found (e.g. Facebook/Instagram login page). Return placeholder so img doesn't 404.
    _placeholder_svg = b'<svg xmlns="http://www.w3.org/2000/svg" width="160" height="90" viewBox="0 0 160 90"><rect fill="#e5e7eb" width="160" height="90"/><text x="80" y="52" fill="#9ca3af" font-family="sans-serif" font-size="14" text-anchor="middle">Media</text></svg>'
    return Response(content=_placeholder_svg, media_type="image/svg+xml")

# ---------- Sailing news feed (RSS) for Latest News banner ----------
# Cache ts=0 so first request after deploy gets real source URLs (no news.google.com)
_sailing_news_cache = {"items": [], "ts": 0}
SAILING_NEWS_CACHE_SEC = 1800  # 30 min

def _resolve_google_news_url(url: str) -> str:
    """If url is a Google News /rss/articles/ URL, decode the article ID to get the real source URL; else return url."""
    if not url or "news.google.com/rss/articles/" not in url:
        return url
    try:
        # Article ID is base64url-encoded and contains the real URL
        import base64 as b64
        path = url.split("/rss/articles/")[-1].split("?")[0]
        if not path:
            return url
        pad = 4 - len(path) % 4
        if pad != 4:
            path += "=" * pad
        raw = b64.urlsafe_b64decode(path)
        text = raw.decode("utf-8", errors="ignore")
        # First occurrence of https?:// is the real article URL
        m = re.search(r"https?://[^\s\x00-\x1f\"\']+", text)
        if m:
            return m.group(0).rstrip(")\"'")
    except Exception:
        pass
    return url

def _resolve_google_news_redirect(url: str) -> Optional[str]:
    """Resolve Google News redirect to final publisher URL. HEAD first, fallback GET. allow_redirects=True, timeout ≤3s. Returns final response.url or None if fail/still Google."""
    if not url or "news.google.com" not in url:
        return url
    headers = {"User-Agent": "Mozilla/5.0 (compatible; SailingSA/1.0; +https://sailingsa.co.za)"}
    try:
        with httpx.Client(timeout=3.0, follow_redirects=True, headers=headers) as client:
            try:
                r = client.head(url)
            except Exception:
                r = client.get(url)
            final = (r.url and str(r.url)) or ""
            if not final or "news.google.com" in final:
                return None
            return final.strip()
    except Exception:
        return None

def _is_image_logo(url: str) -> bool:
    """Reject og:image if SVG, or URL contains /logo, /icon, /brand, /favicon. Do not show logos as article image."""
    if not url:
        return True
    u = url.lower().strip()
    if ".svg" in u:
        return True
    for bad in ("/logo", "/icon", "/brand", "/favicon"):
        if bad in u:
            return True
    return False

def _fetch_og_image(url: str, validate_no_logo: bool = True) -> Optional[str]:
    """Fetch article page and extract og:image URL. Timeout ≤3s. Returns None on failure or if image is logo."""
    if not url or "news.google.com" in url:
        return None
    try:
        with httpx.Client(timeout=3.0, follow_redirects=True, headers={"User-Agent": "Mozilla/5.0 (compatible; SailingSA/1.0)"}) as client:
            r = client.get(url)
            if r.status_code != 200:
                return None
            # <meta property="og:image" content="...">
            m = re.search(r'<meta[^>]+property=["\']og:image["\'][^>]+content=["\']([^"\']+)["\']', r.text, re.I)
            if m:
                img_url = m.group(1).strip()
            else:
                m = re.search(r'<meta[^>]+content=["\']([^"\']+)["\'][^>]+property=["\']og:image["\']', r.text, re.I)
                img_url = m.group(1).strip() if m else None
            if not img_url:
                return None
            if validate_no_logo and _is_image_logo(img_url):
                return None
            return img_url
    except Exception:
        pass
    return None

def _parse_rss_entries(feed) -> list:
    """Parse feedparser feed into list of {title, url, image_url, source, source_href, published}."""
    out = []
    for e in getattr(feed, "entries", []):
        title = (e.get("title") or "").strip()
        url = (e.get("link") or "").strip()
        if not title or not url:
            continue
        image_url = None
        if e.get("media_content"):
            image_url = e["media_content"][0].get("url")
        if not image_url and e.get("media_thumbnail"):
            thumb = e["media_thumbnail"][0] if isinstance(e["media_thumbnail"], list) else e["media_thumbnail"]
            image_url = thumb.get("url") or thumb.get("href") if isinstance(thumb, dict) else None
        if not image_url and e.get("enclosures"):
            enc = e["enclosures"][0]
            if enc.get("type", "").startswith("image/"):
                image_url = enc.get("href") or enc.get("url")
        if not image_url and e.get("links"):
            for link in e["links"]:
                if isinstance(link, dict):
                    t = (link.get("type") or "").lower()
                    if t.startswith("image/"):
                        image_url = link.get("href") or link.get("url")
                        break
        if not image_url and e.get("summary"):
            m = re.search(r'<img[^>]+src=["\']([^"\']+)["\']', e["summary"])
            if m:
                image_url = m.group(1)
        src_obj = e.get("source")
        source = (src_obj or {}).get("title", "") if isinstance(src_obj, dict) else (getattr(src_obj, "title", None) or "")
        source_href = (src_obj or {}).get("href", "") if isinstance(src_obj, dict) else (getattr(src_obj, "href", None) or "")
        if source_href:
            source_href = (source_href or "").strip()
        published = e.get("published") or e.get("updated") or ""
        out.append({
            "title": title,
            "url": url,
            "image_url": image_url or None,
            "source": source or "News",
            "source_href": source_href or None,
            "published": published,
        })
    return out

def _fetch_sailing_news() -> list:
    """Fetch South African sailing news from multiple RSS queries; merge, dedupe by URL, sort by date."""
    # Multiple queries so we get: general SA sailing, Cape to Rio, youth nationals, etc.
    queries = [
        "South+African+sailing",
        "Cape+to+Rio+sailing",
        "SA+youth+sailing+nationals",
        "youth+nationals+sailing+South+Africa",
    ]
    base = "https://news.google.com/rss/search?q={}&hl=en-ZA&gl=ZA&ceid=ZA:en"
    headers = {"User-Agent": "Mozilla/5.0 (compatible; SailingSA/1.0; +https://sailingsa.co.za)"}
    seen_urls = set()
    merged = []
    try:
        with httpx.Client(timeout=15.0, follow_redirects=True, headers=headers) as client:
            for q in queries:
                try:
                    r = client.get(base.format(q))
                    r.raise_for_status()
                    feed = feedparser.parse(r.content)
                    for item in _parse_rss_entries(feed):
                        raw_url = item.get("url") or ""
                        if not raw_url:
                            continue
                        # Prefer real article URL (decode Google News article ID when it contains embedded URL)
                        real_url = _resolve_google_news_url(raw_url)
                        # Use decoded direct article URL when we have it; else keep raw Google News link so click goes to the actual article (Google redirects)
                        if real_url and "news.google.com" not in real_url:
                            item["url"] = real_url
                        else:
                            item["url"] = raw_url  # Google News URL – click takes user to the article via redirect, not publisher homepage
                        dedupe_key = item["url"]
                        if dedupe_key not in seen_urls:
                            seen_urls.add(dedupe_key)
                            merged.append(item)
                except Exception as e:
                    print(f"[sailing-news] RSS query '{q}' failed: {e}")
    except Exception as e:
        print(f"[sailing-news] RSS fetch failed: {e}")
        return []
    # Sort by published date (most recent first); ISO-like strings sort correctly
    merged.sort(key=lambda x: (x.get("published") or "").strip(), reverse=True)
    merged = merged[:20]
    # Prefer full image from article URL (og:image) over RSS thumbnail for every item
    def _task(tup):
        i, item = tup
        url = _fetch_og_image(item.get("url") or "")
        return (i, url)
    try:
        with ThreadPoolExecutor(max_workers=10) as ex:
            futs = {ex.submit(_task, (i, m)): i for i, m in enumerate(merged)}
            for fut in as_completed(futs, timeout=10):
                i, url = fut.result()
                if url:
                    merged[i]["image_url"] = url
    except Exception as e:
        print(f"[sailing-news] og:image fetch failed: {e}")
    return merged

@app.get("/api/sailing-news")
def api_sailing_news(limit: int = Query(10, ge=1, le=20)):
    """Return recent sailing news for Latest News banner. Headlines link to source. Cached 30 min."""
    global _sailing_news_cache
    now = time.time()
    if now - _sailing_news_cache["ts"] > SAILING_NEWS_CACHE_SEC:
        _sailing_news_cache["items"] = _fetch_sailing_news()
        _sailing_news_cache["ts"] = now
    items = _sailing_news_cache["items"][:limit]
    return {"items": items}

