# Duplicate search endpoint removed - using unified endpoint at line 611
# NOTE: GET /api/clubs is defined ONCE at api_list_clubs (line ~7329) and returns [{code, name, province, slug}].
# Do not add another @app.get("/api/clubs") or it will override and break Club Search.

@app.get("/api/clubs/codes")
def list_clubs_codes():
    """List club codes only (backward compat). Use GET /api/clubs for full objects with slug for Club Search."""
    rows = q("""
        SELECT club_abbrev
        FROM clubs
        WHERE club_abbrev IS NOT NULL
        ORDER BY club_abbrev
    """)
    return [r['club_abbrev'] for r in rows]

@app.get("/api/classes")
def list_classes():
    """List all boat classes - returns object with 'classes' array for backward compatibility"""
    rows = q("""
        SELECT class_name
        FROM classes
        WHERE class_name IS NOT NULL
        ORDER BY class_name
    """)
    return {"classes": [r['class_name'] for r in rows]}


def _parse_class_api_ref(class_ref: str) -> int:
    """Resolve /api/class/{ref} where ref is numeric id, id-slug (5-dabchick), or name slug."""
    s = (class_ref or "").strip()
    if not s:
        raise HTTPException(status_code=404, detail="Class not found")
    if s.isdigit():
        return int(s)
    cid, _ = _resolve_class_slug_to_class_id(s)
    if not cid:
        raise HTTPException(status_code=404, detail="Class not found")
    return int(cid)


@app.head("/api/class/{class_ref}")
def api_class_by_id_head(class_ref: str):
    """HEAD support so curl -sI returns 200 when class exists."""
    class_id = _parse_class_api_ref(class_ref)
    conn = get_db_connection()
    cur = conn.cursor()
    try:
        cur.execute("SELECT 1 FROM classes WHERE class_id = %s", (class_id,))
        if not cur.fetchone():
            raise HTTPException(status_code=404, detail="Class not found")
        return Response(status_code=200)
    finally:
        cur.close()
        return_db_connection(conn)


@app.get("/api/class/{class_ref}")
def api_class_by_id(class_ref: str):
    """
    Read-only: class header + totals + regattas + sailors for class_id.
    All data derived from results.class_id (FK to classes). No class_canonical.
    Zero results -> still return class header with 0s and empty arrays.
    class_ref may be a numeric id, id-slug (e.g. 5-dabchick), or name slug.
    """
    class_id = _parse_class_api_ref(class_ref)
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        # 1) Class header (always from classes)
        cur.execute("""
            SELECT class_id, class_name, COALESCE(_sailors_in_class, 0) AS active_sailors
            FROM classes
            WHERE class_id = %s
        """, (class_id,))
        row = cur.fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="Class not found")
        class_name = row["class_name"] or ""
        active_sailors = int(row["active_sailors"] or 0)

        # 2) Totals from results
        cur.execute("""
            SELECT COUNT(DISTINCT regatta_id) AS total_regattas
            FROM results
            WHERE class_id = %s
        """, (class_id,))
        total_regattas = int((cur.fetchone() or {}).get("total_regattas") or 0)
        cur.execute("""
            SELECT COALESCE(SUM(
                CASE
                    WHEN res.race_scores IS NOT NULL AND res.race_scores::text <> ''
                    THEN (SELECT COUNT(*) FROM json_object_keys(res.race_scores::json) AS k)
                    ELSE 0
                END
            ), 0)::bigint AS total_races
            FROM results res
            WHERE res.class_id = %s AND res.raced = TRUE
        """, (class_id,))
        total_races = int((cur.fetchone() or {}).get("total_races") or 0)

        # 3) Regattas list: class participation from results.class_id only (not regatta_blocks.class_id or fleet_label).
        #    Entries: COALESCE(entries_raced, COUNT(DISTINCT result_id)) so no — when results exist.
        #    Races: regatta_blocks.races_sailed with fallback from race_scores keys.
        cur.execute("""
            SELECT
                r.regatta_id,
                r.event_name AS regatta_name,
                r.regatta_id AS regatta_slug,
                r.start_date,
                r.end_date,
                COALESCE(r.end_date, r.start_date) AS event_date,
                COALESCE(c.club_abbrev, c.club_fullname) AS club_name,
                COALESCE(
                    MAX(rb.entries_raced),
                    COUNT(DISTINCT res.result_id)
                ) AS fleet_size,
                COALESCE(
                    MAX(rb.races_sailed),
                    MAX(
                        CASE
                            WHEN res.race_scores IS NOT NULL
                                 AND res.race_scores::text <> ''
                            THEN (SELECT COUNT(*) FROM json_object_keys(res.race_scores::json) AS k)
                            ELSE NULL
                        END
                    )
                ) AS races
            FROM results res
            JOIN regattas r ON r.regatta_id = res.regatta_id
            LEFT JOIN regatta_blocks rb ON rb.block_id = res.block_id AND rb.regatta_id = res.regatta_id
            LEFT JOIN clubs c ON c.club_id = r.host_club_id
            WHERE res.class_id = %s AND res.raced = TRUE
            GROUP BY r.regatta_id, r.event_name, r.start_date, r.end_date, c.club_abbrev, c.club_fullname
            ORDER BY COALESCE(r.end_date, r.start_date) DESC NULLS LAST, r.regatta_id DESC
        """, (class_id,))
        regatta_rows = cur.fetchall() or []
        def _date_iso(d):
            if d is None:
                return None
            return d.strftime("%Y-%m-%d") if hasattr(d, "strftime") else str(d)

        regattas = []
        for r in regatta_rows:
            regattas.append({
                "regatta_id": r.get("regatta_id"),
                "regatta_name": r.get("regatta_name") or "",
                "regatta_slug": r.get("regatta_slug") or "",
                "start_date": _date_iso(r.get("start_date")),
                "end_date": _date_iso(r.get("end_date")),
                "event_date": _date_iso(r.get("event_date")),
                "club_name": r.get("club_name"),
                "fleet_size": int(r["fleet_size"]) if r.get("fleet_size") is not None else None,
                "races": int(r["races"]) if r.get("races") is not None else None,
            })

        # 4) Clubs sailing this class: Club | Sailors | Races | Last regatta | Date (from results; sailors via result_crew when present)
        clubs_sailing_class = []
        if table_exists("clubs") and column_exists("results", "club_id"):
            try:
                if table_exists("result_crew"):
                    cur.execute("""
                        SELECT
                            c.club_id,
                            c.club_abbrev,
                            c.club_fullname,
                            COUNT(DISTINCT rc.sas_id) AS sailors,
                            COALESCE(SUM(
                                CASE
                                    WHEN res.race_scores IS NOT NULL AND res.race_scores::text <> ''
                                    THEN (SELECT COUNT(*) FROM json_object_keys(res.race_scores::json) AS k)
                                    ELSE 0
                                END
                            ), 0)::bigint AS races,
                            MAX(reg.start_date) AS last_regatta_date,
                            (array_agg(reg.event_name ORDER BY reg.start_date DESC NULLS LAST))[1] AS last_regatta_name,
                            (array_agg(reg.regatta_id ORDER BY reg.start_date DESC NULLS LAST))[1] AS last_regatta_slug
                        FROM results res
                        JOIN regattas reg ON reg.regatta_id = res.regatta_id
                        JOIN clubs c ON c.club_id = res.club_id
                        LEFT JOIN result_crew rc ON rc.result_id = res.result_id AND rc.sas_id IS NOT NULL
                        WHERE res.class_id = %s
                        GROUP BY c.club_id, c.club_abbrev, c.club_fullname
                        ORDER BY sailors DESC, c.club_abbrev
                    """, (class_id,))
                else:
                    cur.execute("""
                        SELECT
                            c.club_id,
                            c.club_abbrev,
                            c.club_fullname,
                            COUNT(DISTINCT COALESCE(res.helm_sa_sailing_id::text, res.crew_sa_sailing_id::text)) AS sailors,
                            COALESCE(SUM(
                                CASE
                                    WHEN res.race_scores IS NOT NULL AND res.race_scores::text <> ''
                                    THEN (SELECT COUNT(*) FROM json_object_keys(res.race_scores::json) AS k)
                                    ELSE 0
                                END
                            ), 0)::bigint AS races,
                            MAX(reg.start_date) AS last_regatta_date,
                            (array_agg(reg.event_name ORDER BY reg.start_date DESC NULLS LAST))[1] AS last_regatta_name,
                            (array_agg(reg.regatta_id ORDER BY reg.start_date DESC NULLS LAST))[1] AS last_regatta_slug
                        FROM results res
                        JOIN regattas reg ON reg.regatta_id = res.regatta_id
                        JOIN clubs c ON c.club_id = res.club_id
                        WHERE res.class_id = %s
                        GROUP BY c.club_id, c.club_abbrev, c.club_fullname
                        ORDER BY sailors DESC, c.club_abbrev
                    """, (class_id,))
                club_rows = cur.fetchall() or []
                for r in club_rows:
                    name = (r.get("club_abbrev") or r.get("club_fullname") or "").strip()
                    clubs_sailing_class.append({
                        "club_code": (r.get("club_abbrev") or "").strip(),
                        "club_name": (r.get("club_fullname") or "").strip(),
                        "club_slug": _club_slug_from_name(name) if name else "",
                        "sailors": int(r.get("sailors") or 0),
                        "races": int(r.get("races") or 0),
                        "last_regatta_date": _date_iso(r.get("last_regatta_date")) if r.get("last_regatta_date") is not None else None,
                        "last_regatta_name": (r.get("last_regatta_name") or "").strip() or None,
                        "last_regatta_slug": (r.get("last_regatta_slug") or "").strip() or None,
                    })
            except Exception as e:
                print(f"[api/class] clubs_sailing_class: {e}")
                clubs_sailing_class = []

        # 5) Sailors list: races = sum of race_scores keys; regattas = COUNT(DISTINCT regatta_id). When result_crew exists, use it so all crew get participation.
        if table_exists("result_crew"):
            cur.execute("""
                WITH base AS (
                    SELECT
                        rc.sas_id::text AS sas_id,
                        r.regatta_id,
                        r.block_id,
                        r.rank AS rank_in_regatta,
                        CASE
                            WHEN r.race_scores IS NOT NULL AND r.race_scores::text <> ''
                            THEN (SELECT COUNT(*) FROM json_object_keys(r.race_scores::json) AS k)
                            ELSE 0
                        END AS races_this_result
                    FROM result_crew rc
                    JOIN results r ON r.result_id = rc.result_id
                    WHERE r.class_id = %s
                      AND r.raced = TRUE
                      AND rc.sas_id IS NOT NULL
                ),
                races AS (
                    SELECT sas_id,
                           SUM(races_this_result)::int AS races_in_class,
                           COUNT(DISTINCT regatta_id)::int AS regattas_in_class
                    FROM base
                    GROUP BY sas_id
                ),
                last_regatta AS (
                    SELECT DISTINCT ON (b.sas_id)
                        b.sas_id,
                        reg.regatta_id AS last_regatta_slug,
                        reg.event_name AS last_regatta_name,
                        b.rank_in_regatta AS last_result_rank,
                        rb.entries_raced AS last_fleet_size
                    FROM base b
                    JOIN regattas reg ON reg.regatta_id = b.regatta_id
                    LEFT JOIN regatta_blocks rb ON rb.block_id = b.block_id AND rb.regatta_id = b.regatta_id
                    ORDER BY b.sas_id, COALESCE(reg.end_date, reg.start_date) DESC NULLS LAST, b.regatta_id DESC
                )
                SELECT
                    r.sas_id,
                    r.races_in_class,
                    r.regattas_in_class,
                    lr.last_regatta_slug,
                    lr.last_regatta_name,
                    lr.last_result_rank,
                    lr.last_fleet_size
                FROM races r
                LEFT JOIN last_regatta lr ON lr.sas_id = r.sas_id
                ORDER BY r.races_in_class DESC, r.regattas_in_class DESC, r.sas_id ASC
                LIMIT 5000
            """, (class_id,))
        else:
            cur.execute("""
                WITH base AS (
                    SELECT
                        COALESCE(r.helm_sa_sailing_id, r.crew_sa_sailing_id)::text AS sas_id,
                        r.regatta_id,
                        r.block_id,
                        r.rank AS rank_in_regatta,
                        CASE
                            WHEN r.race_scores IS NOT NULL AND r.race_scores::text <> ''
                            THEN (SELECT COUNT(*) FROM json_object_keys(r.race_scores::json) AS k)
                            ELSE 0
                        END AS races_this_result
                    FROM results r
                    WHERE r.class_id = %s
                      AND r.raced = TRUE
                      AND COALESCE(r.helm_sa_sailing_id, r.crew_sa_sailing_id) IS NOT NULL
                ),
                races AS (
                    SELECT sas_id,
                           SUM(races_this_result)::int AS races_in_class,
                           COUNT(DISTINCT regatta_id)::int AS regattas_in_class
                    FROM base
                    GROUP BY sas_id
                ),
                last_regatta AS (
                    SELECT DISTINCT ON (b.sas_id)
                        b.sas_id,
                        reg.regatta_id AS last_regatta_slug,
                        reg.event_name AS last_regatta_name,
                        b.rank_in_regatta AS last_result_rank,
                        rb.entries_raced AS last_fleet_size
                    FROM base b
                    JOIN regattas reg ON reg.regatta_id = b.regatta_id
                    LEFT JOIN regatta_blocks rb ON rb.block_id = b.block_id AND rb.regatta_id = b.regatta_id
                    ORDER BY b.sas_id, COALESCE(reg.end_date, reg.start_date) DESC NULLS LAST, b.regatta_id DESC
                )
                SELECT
                    r.sas_id,
                    r.races_in_class,
                    r.regattas_in_class,
                    lr.last_regatta_slug,
                    lr.last_regatta_name,
                    lr.last_result_rank,
                    lr.last_fleet_size
                FROM races r
                LEFT JOIN last_regatta lr ON lr.sas_id = r.sas_id
                ORDER BY r.races_in_class DESC, r.regattas_in_class DESC, r.sas_id ASC
                LIMIT 5000
            """, (class_id,))
        sailor_rows = cur.fetchall() or []
        sas_ids = [s["sas_id"] for s in sailor_rows if s.get("sas_id")]
        slug_map = _batch_sailor_slugs_for_sas_ids(sas_ids) if sas_ids else {}
        # Names and club from sas_id_personal (and clubs if we have club_id there)
        name_map = {}
        club_map = {}
        if sas_ids:
            cur.execute("""
                SELECT p.sa_sailing_id::text AS sas_id,
                       COALESCE(TRIM(p.full_name), TRIM(p.first_name || ' ' || COALESCE(p.last_name, ''))) AS sailor_name
                FROM sas_id_personal p
                WHERE p.sa_sailing_id::text = ANY(%s)
            """, (sas_ids,))
            for r in cur.fetchall() or []:
                name_map[r["sas_id"]] = (r.get("sailor_name") or "").strip()
        sailors = []
        for s in sailor_rows:
            sid = s.get("sas_id")
            sailors.append({
                "sas_id": int(sid) if sid and str(sid).isdigit() else sid,
                "sailor_name": name_map.get(sid, ""),
                "sailor_slug": slug_map.get(sid) if slug_map else None,
                "club_name": club_map.get(sid) if club_map else None,
                "races_in_class": int(s.get("races_in_class") or 0),
                "regattas_in_class": int(s.get("regattas_in_class") or 0),
                "last_regatta_slug": s.get("last_regatta_slug"),
                "last_regatta_name": s.get("last_regatta_name"),
                "last_result_rank": int(s["last_result_rank"]) if s.get("last_result_rank") is not None else None,
                "last_fleet_size": int(s["last_fleet_size"]) if s.get("last_fleet_size") is not None else None,
            })

        return {
            "class_id": class_id,
            "class_name": class_name,
            "active_sailors": active_sailors,
            "total_regattas": total_regattas,
            "total_races": total_races,
            "regattas": regattas,
            "clubs_sailing_class": clubs_sailing_class,
            "sailors": sailors,
        }
    finally:
        cur.close()
        return_db_connection(conn)


@app.get("/test/class/{class_id}", response_class=HTMLResponse)
def test_class_aggregate_page(class_id: int):
    """
    Internal test HTML: sailors (helm/crew via result_crew when present), clubs, boat/sail numbers,
    regattas — all with links per URL_STANDARD (relative /sailor/, /club/, /regatta/.../class-...).
    Example: /test/class/7 for International 420 when class_id=7 (check DB for your 420 row).
    Layout matches club/events: event-card matrix + swipe carousel (club-events-dashboard).
    """
    from urllib.parse import quote

    try:
        data = api_class_by_id(str(class_id))
    except HTTPException as e:
        return HTMLResponse(
            f"<html><body><p>{html_module.escape(str(e.detail or 'Not found'))}</p></body></html>",
            status_code=int(getattr(e, "status_code", 404) or 404),
        )

    class_name = (data.get("class_name") or "").strip()
    cslug = _class_canonical_slug(class_name)
    class_path = f"/class/{class_id}-{cslug}" if cslug else f"/class/{class_id}"
    base = _canonical_base_url()

    def a(rel: str, label: str) -> str:
        return f'<a href="{html_module.escape(rel)}">{html_module.escape(label)}</a>'

    regattas_j: list = []
    for rg in data.get("regattas") or []:
        slug = (rg.get("regatta_slug") or rg.get("regatta_id") or "").strip()
        rname = (rg.get("regatta_name") or "").strip()
        ed = (rg.get("event_date") or rg.get("end_date") or "").strip()
        club = (rg.get("club_name") or "").strip()
        fs = rg.get("fleet_size")
        rc = rg.get("races")
        if slug and cslug:
            href = f"/regatta/{quote(str(slug), safe='')}/class-{quote(cslug, safe='')}"
        elif slug:
            href = f"/regatta/{quote(str(slug), safe='')}"
        else:
            href = ""
        regattas_j.append({
            "title": rname or "—",
            "href": href,
            "date": ed or "—",
            "host": club or "—",
            "entries": str(fs if fs is not None else "—"),
            "races": str(rc if rc is not None else "—"),
        })

    clubs_j: list = []
    for c in data.get("clubs_sailing_class") or []:
        cslug_u = (c.get("club_slug") or "").strip()
        lab = (c.get("club_code") or "") + (" — " + c.get("club_name") if c.get("club_name") else "")
        lab = lab.strip(" —") or "—"
        lr_slug = (c.get("last_regatta_slug") or "").strip()
        lr_name = (c.get("last_regatta_name") or "").strip()
        club_href = f"/club/{quote(cslug_u, safe='')}" if cslug_u else ""
        last_href = ""
        if lr_slug and cslug and lr_name:
            last_href = f"/regatta/{quote(lr_slug, safe='')}/class-{quote(cslug, safe='')}"
        elif lr_slug and lr_name:
            last_href = f"/regatta/{quote(lr_slug, safe='')}"
        clubs_j.append({
            "title": lab,
            "href": club_href,
            "sailors": str(c.get("sailors") if c.get("sailors") is not None else "—"),
            "races": str(c.get("races") if c.get("races") is not None else "—"),
            "last_name": lr_name,
            "last_href": last_href,
            "last_date": str(c.get("last_regatta_date") or "—"),
        })

    sailors_j: list = []
    for s in data.get("sailors") or []:
        name = (s.get("sailor_name") or "").strip() or str(s.get("sas_id") or "")
        sslug = (s.get("sailor_slug") or "").strip()
        lr_slug = (s.get("last_regatta_slug") or "").strip()
        lr_name = (s.get("last_regatta_name") or "").strip()
        sailor_href = f"/sailor/{quote(sslug, safe='')}" if sslug else ""
        last_href = ""
        if lr_slug and cslug and lr_name:
            last_href = f"/regatta/{quote(lr_slug, safe='')}/class-{quote(cslug, safe='')}"
        elif lr_slug and lr_name:
            last_href = f"/regatta/{quote(lr_slug, safe='')}"
        sailors_j.append({
            "title": name,
            "href": sailor_href,
            "races": str(s.get("races_in_class") if s.get("races_in_class") is not None else "—"),
            "regattas": str(s.get("regattas_in_class") if s.get("regattas_in_class") is not None else "—"),
            "last_name": lr_name,
            "last_href": last_href,
        })

    helm_j: list = []
    helm_error: Optional[str] = None
    show_helm = bool(table_exists("result_crew"))
    if show_helm:
        conn_h = None
        try:
            conn_h = get_db_connection()
            cur = conn_h.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
            cur.execute(
                """
                SELECT rc.role::text AS role, rc.sas_id::text AS sas_id,
                       COUNT(DISTINCT r.regatta_id)::int AS regattas_in_class
                FROM result_crew rc
                INNER JOIN results r ON r.result_id = rc.result_id
                WHERE r.class_id = %s AND r.raced = TRUE AND rc.sas_id IS NOT NULL
                GROUP BY rc.role, rc.sas_id
                ORDER BY role NULLS LAST, regattas_in_class DESC
                LIMIT 5000
                """,
                (class_id,),
            )
            role_rows = cur.fetchall() or []
            cur.close()
            sas_ids = list({r["sas_id"] for r in role_rows if r.get("sas_id")})
            slug_m = _batch_sailor_slugs_for_sas_ids(sas_ids) if sas_ids else {}
            cur = conn_h.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
            name_m: Dict[str, str] = {}
            if sas_ids:
                cur.execute(
                    """
                    SELECT p.sa_sailing_id::text AS sas_id,
                           COALESCE(TRIM(p.full_name), TRIM(p.first_name || ' ' || COALESCE(p.last_name, ''))) AS sailor_name
                    FROM sas_id_personal p
                    WHERE p.sa_sailing_id::text = ANY(%s)
                    """,
                    (sas_ids,),
                )
                for row in cur.fetchall() or []:
                    name_m[row["sas_id"]] = (row.get("sailor_name") or "").strip()
            cur.close()
            for r in role_rows:
                sid = r.get("sas_id")
                role = (r.get("role") or "—").strip()
                nm = name_m.get(sid, "") or str(sid or "")
                sl = slug_m.get(sid) if slug_m else None
                sailor_href = f"/sailor/{quote(str(sl), safe='')}" if sl else ""
                helm_j.append({
                    "role": role,
                    "title": nm,
                    "href": sailor_href,
                    "regattas": str(r.get("regattas_in_class") or "—"),
                })
        except Exception as ex:
            helm_error = str(ex)
        finally:
            if conn_h:
                return_db_connection(conn_h)

    boats_j: list = []
    boat_err: Optional[str] = None
    conn_b = None
    try:
        conn_b = get_db_connection()
        cur = conn_b.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        cur.execute(
            """
            SELECT COALESCE(NULLIF(TRIM(sail_number::text), ''), '') AS sn,
                   COALESCE(NULLIF(TRIM(boat_name::text), ''), '') AS bn,
                   COUNT(*)::int AS result_rows,
                   COUNT(DISTINCT regatta_id)::int AS regattas,
                   MAX(regatta_id) AS sample_regatta_id
            FROM results
            WHERE class_id = %s
            GROUP BY sail_number, boat_name
            ORDER BY COUNT(*) DESC
            LIMIT 500
            """,
            (class_id,),
        )
        boat_rows = cur.fetchall() or []
        cur.close()
        for b in boat_rows:
            sn = (b.get("sn") or "").strip() or "—"
            bn = (b.get("bn") or "").strip() or "—"
            samp = b.get("sample_regatta_id")
            if samp and cslug:
                samp_href = f"/regatta/{quote(str(samp), safe='')}/class-{quote(cslug, safe='')}"
            elif samp:
                samp_href = f"/regatta/{quote(str(samp), safe='')}"
            else:
                samp_href = ""
            boats_j.append({
                "title": f"{bn} · {sn}",
                "boat": bn,
                "sail": sn,
                "result_rows": str(b.get("result_rows") or 0),
                "regattas": str(b.get("regattas") or 0),
                "sample_href": samp_href,
                "sample_label": str(samp) if samp else "—",
            })
    except Exception as ex:
        boat_err = str(ex)
    finally:
        if conn_b:
            return_db_connection(conn_b)

    payload = {
        "regattas": regattas_j,
        "clubs": clubs_j,
        "sailors": sailors_j,
        "helm": helm_j,
        "helm_error": helm_error,
        "show_helm": show_helm,
        "boats": boats_j,
        "boat_error": boat_err,
    }
    json_safe = json.dumps(payload).replace("</", "<\\/")

    css_block = (
        _SECTION_HEADING_ROW_UNIFIED_CSS
        + _EVENTS_TOOLBAR_SEARCH_CSS
        + _EVENTS_CARD_MATRIX_CSS
        + _CLUB_EVENTS_CAROUSEL_CSS
        + """
.class-test-page .event-card .event-title-link { font-weight: 700; text-decoration: underline; }
.class-test-page .event-card h3 { font-size: 0.95rem; font-weight: 700; margin: 0 0 0.2rem 0; line-height: 1.25; }
.class-test-page .event-card .event-date { font-size: 0.8rem; margin: 0; display: block; }
.class-test-page .test-card-line { font-size: 0.8rem; margin: 0.15rem 0 0 0; line-height: 1.35; }
.class-test-page .test-card-line a { color: #1e3a8a; font-weight: 600; text-decoration: underline; }
.class-test-intro { font-size: 0.9rem; color: #475569; margin: 0 0 0.75rem 0; line-height: 1.4; }
.class-test-list-footer { margin: 0.75rem 0 0 0 !important; padding-top: 0.25rem; border-top: 1px solid #e5e7eb; clear: both; }
.class-test-list-section { margin-bottom: 0.5rem; padding-bottom: 0.75rem; }
/* List carousels: do not clip tall rows (sample regatta link etc.) */
.class-test-page .club-events-dashboard .events-carousel-wrap { overflow-x: hidden; overflow-y: visible; max-height: none; }
.class-test-page .club-events-dashboard .events-carousel { overflow-x: auto; overflow-y: visible; -webkit-overflow-scrolling: touch; }
.class-test-page .club-events-dashboard .events-page { min-height: auto; overflow: visible; align-items: stretch; }
.class-test-page .club-events-dashboard .events-page .class-test-list { list-style: none; margin: 0; padding: 0; width: 100%; box-sizing: border-box; }
.class-test-list { list-style: none; margin: 0; padding: 0; }
.class-test-list li { border-bottom: 1px solid #e5e7eb; padding: 0.65rem 0; font-size: 0.95rem; line-height: 1.45; color: #1a2750; word-wrap: break-word; overflow-wrap: anywhere; }
.class-test-list li:last-child { border-bottom: none; }
.class-test-list .test-num { color: #64748b; font-weight: 600; margin-right: 0.35rem; }
.class-test-list a { color: #1e3a8a; font-weight: 600; text-decoration: underline; }
"""
    )

    parts = [
        '<!DOCTYPE html><html lang="en"><head><meta charset="utf-8">'
        '<meta name="viewport" content="width=device-width, initial-scale=1">',
        f"<title>Test — {html_module.escape(class_name)} | SailingSA</title>",
        '<link rel="stylesheet" href="/css/main.css?v=13">',
        '<style>',
        css_block,
        "</style></head><body class=\"class-test-page\">",
        '<div class="container">',
        '<div class="card"><h1 class="section-title">Class test aggregate</h1>',
        f"<p><strong>{html_module.escape(class_name)}</strong> (class_id={class_id}) · "
        f"{a(class_path, 'Canonical class page')} · "
        f"{a('/classes', 'Directory')}</p>",
        "<p>Internal test page — not linked from site nav. <strong>Regattas</strong>: swipe cards. "
        "<strong>Lists</strong>: 5 rows per screen, search + swipe. Data from <code>GET /api/class/{id}</code> plus boat/sail and helm/crew queries.</p>",
        "</div>",
        '<div class="card stats-section club-events-dashboard">'
        '<div class="events-section-heading-row">'
        f'<h2 class="section-title">Regattas ({len(regattas_j)})</h2>'
        '<input type="search" class="events-dashboard-search" id="test-search-regattas" placeholder="Search…" '
        'aria-label="Search regattas" autocomplete="off" autocapitalize="off" spellcheck="false" />'
        "</div>"
        '<p class="class-test-intro">Regatta events for this class (swipe for more).</p>'
        + _test_class_carousel_controls_html("test-regattas")
        + "</div>",
        _test_class_list_section_html("clubs", "Clubs (sailors in this class)", len(clubs_j), "Search clubs…"),
        _test_class_list_section_html("sailors", "Sailors (aggregated)", len(sailors_j), "Search sailors…"),
    ]
    if show_helm:
        parts.append(
            _test_class_list_section_html("helm", "Helm / crew (result_crew)", len(helm_j), "Search helm / crew…"),
        )
    parts.extend(
        [
            _test_class_list_section_html("boats", "Boat / sail (from results)", len(boats_j), "Search boat / sail…"),
            f'<script type="application/json" id="test-class-data">{json_safe}</script>',
            """
<script>
(function(){
  var MATRIX = ['ec-past-club','ec-past-sas','ec-past-other','ec-upcoming-club','ec-upcoming-sas'];
  function matrixClass(i){ return MATRIX[i % MATRIX.length]; }
  function esc(s){ var d=document.createElement("div"); d.textContent=s==null?"":String(s); return d.innerHTML; }
  function wireEventsCarousel(panelId){
    var carousel = document.getElementById("cards-" + panelId);
    var controls = document.getElementById("events-controls-" + panelId);
    var prevBtn = document.getElementById("events-prev-" + panelId);
    var nextBtn = document.getElementById("events-next-" + panelId);
    var dotsWrap = document.getElementById("events-dots-" + panelId);
    if(!carousel || !prevBtn || !nextBtn || !dotsWrap) return;
    function pageCount(){ return carousel.querySelectorAll(".events-page").length; }
    function currentPage(){
      var w = carousel.clientWidth || 1;
      var n = pageCount();
      if (n <= 1) return 0;
      var idx = Math.floor((carousel.scrollLeft + w * 0.25) / w);
      if (idx < 0) idx = 0;
      if (idx > n - 1) idx = n - 1;
      return idx;
    }
    function syncNav(){
      var n = pageCount();
      if (n <= 1) { if(controls) controls.style.display = "none"; return; }
      if(controls) controls.style.display = "";
      var cur = currentPage();
      prevBtn.disabled = (cur <= 0);
      nextBtn.disabled = (cur >= n - 1);
      dotsWrap.querySelectorAll(".events-dot").forEach(function(d, i){
        d.classList.toggle("is-active", i === cur);
      });
    }
    function scrollToPage(idx){
      var n = pageCount();
      idx = Math.max(0, Math.min(idx, n - 1));
      carousel.scrollTo({ left: idx * carousel.clientWidth, behavior: "smooth" });
    }
    prevBtn.onclick = function(){ scrollToPage(currentPage() - 1); };
    nextBtn.onclick = function(){ scrollToPage(currentPage() + 1); };
    carousel.addEventListener("scroll", function(){ syncNav(); }, { passive: true });
    window.addEventListener("resize", function(){ syncNav(); });
    dotsWrap.addEventListener("click", function(ev){
      var t = ev.target;
      if(t && t.getAttribute && t.getAttribute("data-page") !== null)
        scrollToPage(parseInt(t.getAttribute("data-page"), 10));
    });
    syncNav();
  }
  function fillCarousel(panelId, list, renderOne){
    var carousel = document.getElementById("cards-" + panelId);
    var controls = document.getElementById("events-controls-" + panelId);
    var dotsWrap = document.getElementById("events-dots-" + panelId);
    if(!carousel) return;
    if(!list || !list.length){
      carousel.innerHTML = '<div class="events-page" role="group"><div class="event-card ec-past-other"><div class="event-card-header"><h3>No data</h3><span class="event-date">—</span></div></div></div>';
      if(controls) controls.style.display = "none";
      return;
    }
    carousel.innerHTML = "";
    var n = list.length;
    for(var i = 0; i < n; i++){
      var pageEl = document.createElement("div");
      pageEl.className = "events-page";
      pageEl.setAttribute("role", "group");
      pageEl.innerHTML = renderOne(list[i], i, n);
      carousel.appendChild(pageEl);
    }
    if(dotsWrap){
      dotsWrap.innerHTML = "";
      for(var k = 0; k < n; k++){
        var b = document.createElement("button");
        b.type = "button";
        b.className = "events-dot" + (k === 0 ? " is-active" : "");
        b.setAttribute("data-page", String(k));
        b.setAttribute("aria-label", "Item " + (k+1) + " of " + n);
        dotsWrap.appendChild(b);
      }
    }
    if(n <= 1){ if(controls) controls.style.display = "none"; }
    else { if(controls) controls.style.display = ""; }
    wireEventsCarousel(panelId);
  }
  function cardShell(mc, titleHtml, dateLine, innerHtml, index1, totalN){
    var idxAria = totalN > 0 ? ' aria-label="Item ' + index1 + ' of ' + totalN + '"' : "";
    var indexBadge = '<span class="event-card-index"' + idxAria + '">' + index1 + '</span>';
    var footer = '<div class="event-card-result-row"><div class="event-result-slot"></div><div class="event-card-actions">' + indexBadge + '</div></div>';
    return '<div class="event-card ' + mc + '"><div class="event-card-header"><h3>' + titleHtml + '</h3><span class="event-date">' + esc(dateLine) + '</span></div><div class="event-card-body"><div class="event-card-body-inner">' + innerHtml + footer + '</div></div></div>';
  }
  var raw = document.getElementById("test-class-data");
  var DATA = raw ? JSON.parse(raw.textContent) : {};
  var ALL_REGATTAS = DATA.regattas || [];
  function filterByQuery(list, q, haystackFn){
    q = (q || "").trim().toLowerCase();
    if(!q) return list.slice();
    return list.filter(function(item){ return haystackFn(item).toLowerCase().indexOf(q) !== -1; });
  }
  function getSearchQ(inputId){
    var e = document.getElementById(inputId);
    return e ? (e.value || "") : "";
  }
  function renderRegattaCards(list){
    fillCarousel("test-regattas", list, function(r, i, n){
      var mc = matrixClass(i);
      var titleH = r.href ? '<a href="'+esc(r.href)+'" class="event-title-link">'+esc(r.title)+'</a>' : esc(r.title);
      var inner = '<div class="event-type-line"><span class="event-type">Regatta</span></div>'
        + '<span class="event-club"><strong>Host:</strong> '+esc(r.host)+'</span>'
        + '<p class="test-card-line">Entries: '+esc(r.entries)+' · Races: '+esc(r.races)+'</p>';
      return cardShell(mc, titleH, r.date, inner, i + 1, n);
    });
  }
  function regattaHaystack(r){ return [r.title, r.date, r.host, r.entries, r.races].join(" "); }
  renderRegattaCards(ALL_REGATTAS);
  var regSearchEl = document.getElementById("test-search-regattas");
  if(regSearchEl) regSearchEl.addEventListener("input", function(){
    renderRegattaCards(filterByQuery(ALL_REGATTAS, getSearchQ("test-search-regattas"), regattaHaystack));
  });

  var LIST_PAGE = 5;
  function fillListPaged(panelId, list, renderLi){
    var carousel = document.getElementById("cards-" + panelId);
    var controls = document.getElementById("events-controls-" + panelId);
    var dotsWrap = document.getElementById("events-dots-" + panelId);
    if(!carousel) return;
    if(!list || !list.length){
      carousel.innerHTML = '<div class="events-page" role="group"><ol class="class-test-list"><li><span class="test-num">—</span> No matches</li></ol></div>';
      if(controls) controls.style.display = "none";
      return;
    }
    carousel.innerHTML = "";
    var pages = [];
    for(var p = 0; p < list.length; p += LIST_PAGE) pages.push(list.slice(p, p + LIST_PAGE));
    for(var pi = 0; pi < pages.length; pi++){
      var chunk = pages[pi];
      var lis = [];
      for(var j = 0; j < chunk.length; j++){
        var globalIdx = pi * LIST_PAGE + j;
        lis.push(renderLi(chunk[j], globalIdx));
      }
      var pageEl = document.createElement("div");
      pageEl.className = "events-page";
      pageEl.setAttribute("role", "group");
      pageEl.innerHTML = '<ol class="class-test-list">' + lis.join("") + '</ol>';
      carousel.appendChild(pageEl);
    }
    var n = pages.length;
    if(dotsWrap){
      dotsWrap.innerHTML = "";
      for(var k = 0; k < n; k++){
        var b = document.createElement("button");
        b.type = "button";
        b.className = "events-dot" + (k === 0 ? " is-active" : "");
        b.setAttribute("data-page", String(k));
        b.setAttribute("aria-label", "Page " + (k+1) + " of " + n);
        dotsWrap.appendChild(b);
      }
    }
    if(n <= 1){ if(controls) controls.style.display = "none"; }
    else { if(controls) controls.style.display = ""; }
    wireEventsCarousel(panelId);
  }
  var ALL_CLUBS = DATA.clubs || [];
  function clubHaystack(c){ return [c.title,c.sailors,c.races,c.last_name,c.last_date].join(" "); }
  function clubLi(c, idx){
    var title = c.href ? '<a href="'+esc(c.href)+'">'+esc(c.title)+'</a>' : esc(c.title);
    var last = '';
    if (c.last_name && c.last_href) last = ' · Last: <a href="'+esc(c.last_href)+'">'+esc(c.last_name)+'</a> ('+esc(c.last_date)+')';
    else if (c.last_name) last = ' · Last: '+esc(c.last_name)+' ('+esc(c.last_date)+')';
    return '<li><span class="test-num">'+(idx+1)+'.</span> '+title+' · Sailors '+esc(c.sailors)+' · Races '+esc(c.races)+last+'</li>';
  }
  function paintClubs(){ fillListPaged("test-clubs", filterByQuery(ALL_CLUBS, getSearchQ("test-search-clubs"), clubHaystack), clubLi); }
  paintClubs();
  var cs = document.getElementById("test-search-clubs");
  if(cs) cs.addEventListener("input", paintClubs);

  var ALL_SAILORS = DATA.sailors || [];
  function sailorHaystack(s){ return [s.title,s.races,s.regattas,s.last_name].join(" "); }
  function sailorLi(s, idx){
    var name = s.href ? '<a href="'+esc(s.href)+'">'+esc(s.title)+'</a>' : esc(s.title);
    var last = '';
    if (s.last_name && s.last_href) last = ' · Last: <a href="'+esc(s.last_href)+'">'+esc(s.last_name)+'</a>';
    else if (s.last_name) last = ' · Last: '+esc(s.last_name);
    return '<li><span class="test-num">'+(idx+1)+'.</span> '+name+' · Races '+esc(s.races)+' · Regattas '+esc(s.regattas)+last+'</li>';
  }
  function paintSailors(){ fillListPaged("test-sailors", filterByQuery(ALL_SAILORS, getSearchQ("test-search-sailors"), sailorHaystack), sailorLi); }
  paintSailors();
  var ss = document.getElementById("test-search-sailors");
  if(ss) ss.addEventListener("input", paintSailors);

  if (DATA.show_helm) {
    if (DATA.helm_error) {
      var hcar = document.getElementById("cards-test-helm");
      var hctl = document.getElementById("events-controls-test-helm");
      if(hcar) hcar.innerHTML = '<div class="events-page" role="group"><ol class="class-test-list"><li><span class="test-num">!</span> '+esc(DATA.helm_error)+' (helm/crew query failed)</li></ol></div>';
      if(hctl) hctl.style.display = "none";
    } else {
      var ALL_HELM = DATA.helm || [];
      function helmHaystack(h){ return [h.title,h.role,h.regattas].join(" "); }
      function helmLi(h, idx){
        var name = h.href ? '<a href="'+esc(h.href)+'">'+esc(h.title)+'</a>' : esc(h.title);
        return '<li><span class="test-num">'+(idx+1)+'.</span> '+esc(h.role)+' — '+name+' · Regattas '+esc(h.regattas)+'</li>';
      }
      function paintHelm(){ fillListPaged("test-helm", filterByQuery(ALL_HELM, getSearchQ("test-search-helm"), helmHaystack), helmLi); }
      paintHelm();
      var hs = document.getElementById("test-search-helm");
      if(hs) hs.addEventListener("input", paintHelm);
    }
  }

  var boatErr = DATA.boat_error || '';
  if (boatErr) {
    var bcar = document.getElementById("cards-test-boats");
    var bctl = document.getElementById("events-controls-test-boats");
    if(bcar) bcar.innerHTML = '<div class="events-page" role="group"><ol class="class-test-list"><li><span class="test-num">!</span> '+esc(boatErr)+' (boat/sail query failed)</li></ol></div>';
    if(bctl) bctl.style.display = "none";
  } else {
    var ALL_BOATS = DATA.boats || [];
    function boatHaystack(b){ return [b.boat,b.sail,b.result_rows,b.regattas,b.sample_label].join(" "); }
    function boatLi(b, idx){
      var samp = b.sample_href ? '<a href="'+esc(b.sample_href)+'">'+esc(b.sample_label)+'</a>' : esc(b.sample_label);
      return '<li><span class="test-num">'+(idx+1)+'.</span> Boat '+esc(b.boat)+' · Sail '+esc(b.sail)
        +' · Rows '+esc(b.result_rows)+' · Regattas '+esc(b.regattas)+' · Sample '+samp+'</li>';
    }
    function paintBoats(){ fillListPaged("test-boats", filterByQuery(ALL_BOATS, getSearchQ("test-search-boats"), boatHaystack), boatLi); }
    paintBoats();
    var bs = document.getElementById("test-search-boats");
    if(bs) bs.addEventListener("input", paintBoats);
  }
})();
</script>""",
            f'<p class="card"><small>Canonical base for reference: {html_module.escape(base)}</small></p>',
            "</div></body></html>",
        ]
    )

    return HTMLResponse("".join(parts))


@app.get("/api/sa-id-stats")
def sa_id_stats():
    """Get statistics about SA Sailing IDs"""
    with psycopg2.connect(DB_URL) as conn:
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            cur.execute("SELECT COUNT(*) as total FROM sailing_id")
            sas_count = cur.fetchone()['total']
            
            cur.execute("SELECT COUNT(*) as total FROM temp_people")
            temp_count = cur.fetchone()['total']
            
            # Return format compatible with old member-finder HTML
            # Get last scrape info
            cur.execute("""
                SELECT before_scrape_count, after_scrape_count, added_count, timestamp 
                FROM scrape_log 
                WHERE status = 'SUCCESS' 
                ORDER BY timestamp DESC 
                LIMIT 1
            """)
            last_scrape = cur.fetchone()
            
            if last_scrape:
                before_scrape, after_scrape, added_count, scrape_time = last_scrape
                return {
                    "total_count": sas_count + temp_count,
                    "total_sas_ids": sas_count,
                    "total_temp_ids": temp_count,
                    "last_scrape": str(scrape_time),
                    "before_scrape": before_scrape,
                    "after_scrape": after_scrape,
                    "added_count": added_count
                }
            else:
                return {
                    "total_count": sas_count + temp_count,
                    "total_sas_ids": sas_count,
                    "total_temp_ids": temp_count,
                    "last_scrape": None,
                    "before_scrape": 0,
                    "after_scrape": sas_count,
                    "added_count": 0
                }

@app.post("/api/scrape-log/pre-scrape")
def log_pre_scrape():
    """Log the state before starting a scrape"""
    try:
        with psycopg2.connect(DB_URL) as conn:
            with conn.cursor() as cur:
                # Get current max SAS ID count
                cur.execute("SELECT COUNT(*) FROM sailing_id WHERE first_name != 'No Record'")
                before_count = cur.fetchone()[0]
                
                # Insert pre-scrape log entry
                cur.execute("""
                    INSERT INTO scrape_log (before_scrape_count, after_scrape_count, added_count, status, message)
                    VALUES (%s, %s, %s, %s, %s)
                    RETURNING id
                """, (before_count, 0, 0, 'STARTED', 'Pre-scrape logged'))
                
                log_id = cur.fetchone()[0]
                conn.commit()
                
                return {"success": True, "log_id": log_id, "before_count": before_count}
    except Exception as e:
        return {"success": False, "error": str(e)}

@app.post("/api/run-daily-scrape")
def run_daily_scrape():
    """Run the daily scrape process with all rules applied. Uses sailing_id if present, else sas_id_personal (live)."""
    import requests
    from bs4 import BeautifulSoup
    import time

    use_sas_id_personal = not table_exists("sailing_id") and table_exists("sas_id_personal")
    target_table = "sas_id_personal" if use_sas_id_personal else "sailing_id"
    id_col = "sa_sailing_id"

    try:
        with psycopg2.connect(DB_URL) as conn:
            with conn.cursor() as cur:
                log_id, before_count = None, 0
                if table_exists("scrape_log"):
                    cur.execute("""
                        SELECT id, before_scrape_count FROM scrape_log
                        WHERE status = 'STARTED' ORDER BY id DESC LIMIT 1
                    """)
                    log_entry = cur.fetchone()
                    if log_entry:
                        log_id, before_count = log_entry
                    elif not use_sas_id_personal:
                        return {"success": False, "error": "No pre-scrape log found. Call pre-scrape first."}
                if before_count == 0 and use_sas_id_personal:
                    cur.execute("SELECT COUNT(*) FROM sas_id_personal")
                    before_count = cur.fetchone()[0]

                # Get current max SAS ID to start from
                if use_sas_id_personal:
                    cur.execute("""
                        SELECT COALESCE(MAX(NULLIF(TRIM(sa_sailing_id), '')::int), 0)
                        FROM sas_id_personal WHERE sa_sailing_id ~ '^[0-9]+$'
                    """)
                else:
                    cur.execute("SELECT MAX(sa_sailing_id) FROM sailing_id")
                max_id = cur.fetchone()[0] or 0
                start_id = int(max_id) + 1

                new_records = []
                consecutive_no_record = 0
                max_consecutive_no_record = 10
                current_id = start_id

                while consecutive_no_record < max_consecutive_no_record:
                    cur.execute(f"SELECT 1 FROM {target_table} WHERE {id_col}::text = %s", (str(current_id),))
                    if cur.fetchone():
                        current_id += 1
                        continue

                    url = f"https://www.sailing.org.za/member-finder?parentBodyID={current_id}&firstname=&surname="
                    headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"}
                    try:
                        response = requests.get(url, headers=headers, timeout=10)
                        response.raise_for_status()
                        soup = BeautifulSoup(response.content, "html.parser")

                        if "SA Sailing ID:" in response.text and str(current_id) in response.text:
                            for elem in soup.find_all("b"):
                                name_text = elem.get_text().strip()
                                if not name_text or name_text == str(current_id) or "SA Sailing ID:" in name_text:
                                    continue
                                name_text = name_text.replace(",,", ",")
                                if "," in name_text:
                                    parts = name_text.split(",", 1)
                                    last_name = parts[0].strip()
                                    first_name = parts[1].strip().split()[0] if parts[1].strip() else ""
                                else:
                                    name_parts = name_text.split()
                                    first_name = name_parts[0] if name_parts else name_text
                                    last_name = name_parts[-1] if len(name_parts) >= 2 else ""
                                birth_year = None
                                for born_text in soup.find_all(string=lambda t: t and "Born" in str(t)):
                                    try:
                                        birth_year = int(str(born_text).strip().split("Born")[-1].strip()[:4])
                                        break
                                    except (ValueError, IndexError):
                                        pass

                                if use_sas_id_personal:
                                    cur.execute("""
                                        INSERT INTO sas_id_personal (sa_sailing_id, first_name, last_name, full_name, year_of_birth)
                                        VALUES (%s, %s, %s, %s, %s)
                                        ON CONFLICT (sa_sailing_id) DO UPDATE SET
                                            first_name = EXCLUDED.first_name,
                                            last_name = EXCLUDED.last_name,
                                            full_name = EXCLUDED.full_name,
                                            year_of_birth = EXCLUDED.year_of_birth
                                    """, (str(current_id), first_name, last_name, name_text, birth_year))
                                else:
                                    cur.execute("""
                                        INSERT INTO sailing_id (sa_sailing_id, first_name, last_name, birth_year, display_name)
                                        VALUES (%s, %s, %s, %s, %s)
                                    """, (current_id, first_name, last_name, birth_year, name_text))

                                new_records.append({
                                    "sa_sailing_id": current_id,
                                    "first_name": first_name,
                                    "last_name": last_name,
                                    "display_name": name_text,
                                    "birth_year": birth_year,
                                })
                                consecutive_no_record = 0
                                break
                            else:
                                consecutive_no_record += 1
                        else:
                            consecutive_no_record += 1
                        time.sleep(0.5)
                        current_id += 1
                    except Exception as e:
                        print(f"Error scraping {current_id}: {e}")
                        consecutive_no_record += 1
                        current_id += 1

                cur.execute(f"SELECT COUNT(*) FROM {target_table}")
                after_count = cur.fetchone()[0]
                added_count = after_count - before_count if log_id is not None else len(new_records)

                if table_exists("scrape_log") and log_id is not None:
                    cur.execute("""
                        UPDATE scrape_log
                        SET after_scrape_count = %s, added_count = %s, status = 'SUCCESS', message = %s
                        WHERE id = %s
                    """, (after_count, added_count, f"Found {len(new_records)} new members", log_id))

                conn.commit()
                return {
                    "success": True,
                    "new_members": len(new_records),
                    "before_count": before_count,
                    "after_count": after_count,
                    "added_count": added_count,
                    "members": new_records,
                    "target_table": target_table,
                }
    except Exception as e:
        return {"success": False, "error": str(e)}

@app.post("/api/scrape-log/post-scrape")
def log_post_scrape():
    """Log the state after completing a scrape"""
    try:
        with psycopg2.connect(DB_URL) as conn:
            with conn.cursor() as cur:
                # Get the most recent successful scrape
                cur.execute("""
                    SELECT before_scrape_count, after_scrape_count, added_count, timestamp 
                    FROM scrape_log 
                    WHERE status = 'SUCCESS' 
                    ORDER BY timestamp DESC 
                    LIMIT 1
                """)
                
                result = cur.fetchone()
                if result:
                    before_count, after_count, added_count, timestamp = result
                    return {
                        "success": True,
                        "before_count": before_count,
                        "after_count": after_count,
                        "added_count": added_count,
                        "timestamp": timestamp.isoformat()
                    }
                else:
                    return {"success": False, "error": "No successful scrape found"}
                    
    except Exception as e:
        return {"success": False, "error": str(e)}

@app.get("/api/search")
def api_search(
    q: Optional[str] = None,
    sas_id: Optional[str] = None,
    first_names: Optional[str] = None,
    surname: Optional[str] = None,
    class_name: Optional[str] = None,
    club: Optional[str] = None,
    age_exact: Optional[int] = None,
    age_min: Optional[int] = None,
    age_max: Optional[int] = None,
    request: Request = None,
    age_under: Optional[int] = None,
    age_over: Optional[int] = None,
    limit: int = 200,
    hub: int = Query(0, description="1 = landing/hub search: higher cap, multi-word fuzzy on names"),
):
    """Search for members (SA IDs and Temp IDs) with last regatta info"""
    request_id = getattr(request.state, 'request_id', None) if request else None
    if not request_id:
        request_id = get_request_id()
    
    # Search analytics: log sailor search when q present
    if q and (q_ := (q or "").strip()):
        try:
            _log_analytics_event("search", {"search_type": "sailor", "query": q_}, session_id=request.cookies.get("session") if request else None, sas_id=None)
        except Exception:
            pass
    
    max_cap = 500 if int(hub or 0) == 1 else 200
    limit = min(max(1, int(limit or 200)), max_cap)
    
    rows = []
    
    conn = None
    try:
        conn = get_db_connection(request_id)
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                # Wrap cursor with query tracing
                trace_query(cur, request_id)
                # Build WHERE conditions
                conditions = []
                params = []
                
                # Track if we need sail/boat name search (handled via JOIN, not WHERE EXISTS)
                needs_sail_boat_search = False
                if q:
                    q_trimmed = q.strip()
                    # Free text search on names, sail numbers, boat names - but exclude if it's just "T" (temp ID search)
                    if q_trimmed.upper() != "T":
                        # STAGE 12 OPTIMIZATION: Require minimum 2 characters for free text search
                        # Single character searches like "t" cause full table scans and return thousands of results
                        if len(q_trimmed) < 2:
                            # For single character, return empty or use exact SA ID match only
                            if q_trimmed.isdigit():
                                # If it's a digit, try exact SA ID match
                                conditions.append("s.sa_sailing_id::text = %s")
                                params.append(q_trimmed)
                            else:
                                # Single letter - return empty to avoid 7-18 second scans
                                return []
                        else:
                            # STAGE 12: Removed EXISTS clause - use LEFT JOIN with pre-filtered results instead
                            needs_sail_boat_search = True
                            tokens = [t for t in q_trimmed.lower().split() if t]
                            hub_on = int(hub or 0) == 1

                            def _append_sailor_token_sql(tok: str, include_clubs: bool) -> None:
                                """One search token must match name, SA ID, and optionally club/class (escaped for LIKE)."""
                                if not tok:
                                    return
                                esc = _escape_like(tok)
                                if len(tok) == 1:
                                    p = f"{esc}%"
                                    conditions.append("""
                                        (
                                         LOWER(COALESCE(s.first_name,'')) LIKE %s
                                         OR LOWER(COALESCE(s.last_name,'')) LIKE %s
                                         OR LOWER(TRIM(COALESCE(s.first_name,'') || ' ' || COALESCE(s.last_name,''))) LIKE %s
                                         OR LOWER(TRIM(COALESCE(s.last_name,'') || ' ' || COALESCE(s.first_name,''))) LIKE %s
                                         OR CAST(s.sa_sailing_id AS TEXT) LIKE %s
                                        )
                                    """)
                                    params.extend([p, p, p, p, p])
                                    return
                                p = f"%{esc}%"
                                frag = """
                                        (
                                         LOWER(COALESCE(s.first_name,'')) LIKE %s
                                         OR LOWER(COALESCE(s.last_name,'')) LIKE %s
                                         OR LOWER(COALESCE(s.first_name,'') || ' ' || COALESCE(s.last_name,'')) LIKE %s
                                         OR LOWER(COALESCE(s.last_name,'') || ' ' || COALESCE(s.first_name,'')) LIKE %s
                                         OR CAST(s.sa_sailing_id AS TEXT) LIKE %s"""
                                plist = [p, p, p, p, p]
                                if include_clubs:
                                    frag += """
                                         OR LOWER(COALESCE(s.primary_club,'')) LIKE %s
                                         OR LOWER(COALESCE(s.club_1,'')) LIKE %s
                                         OR LOWER(COALESCE(s.primary_class,'')) LIKE %s"""
                                    plist.extend([p, p, p])
                                frag += "\n                                        )"
                                conditions.append(frag)
                                params.extend(plist)

                            # Multi-word: each token must match somewhere (fixes "tim wea" vs "Timothy Weaving").
                            if len(tokens) >= 2:
                                for tok in tokens:
                                    _append_sailor_token_sql(tok, include_clubs=True)
                            elif hub_on and tokens:
                                _append_sailor_token_sql(tokens[0], include_clubs=True)
                            else:
                                # Single token: prefix on names + substring on full-name strings + SA ID (legacy)
                                conditions.append("""
                                (LOWER(s.last_name) LIKE %s 
                                 OR LOWER(s.first_name) LIKE %s
                                 OR LOWER(s.last_name || ' ' || s.first_name) LIKE %s
                                 OR LOWER(s.first_name || ' ' || s.last_name) LIKE %s
                                 OR s.sa_sailing_id::text LIKE %s)
                            """)
                                q_lower = f"{q_trimmed.lower()}%"
                                q_lower_space = f"%{q_trimmed.lower()}%"
                                params.extend([q_lower, q_lower, q_lower_space, q_lower_space, f"%{q_trimmed}%"])
                
                if sas_id:
                    # If sas_id is "T" or starts with "TMP", don't filter SA IDs (will show temp IDs instead)
                    if sas_id.strip().upper() not in ["T", "TMP"] and not sas_id.upper().startswith("TMP:"):
                        conditions.append("s.sa_sailing_id::text = %s")
                        params.append(sas_id)
                    # Otherwise, let temp ID query handle it
                
                if first_names:
                    # Match from start of first name (not anywhere in the name)
                        conditions.append("LOWER(COALESCE(s.first_name, '')) LIKE %s")
                        params.append(f"{first_names.lower()}%")
                
                if surname:
                    # Match from start of last name (not anywhere in the name)
                        conditions.append("LOWER(COALESCE(s.last_name, '')) LIKE %s")
                        params.append(f"{surname.lower()}%")
                
                if class_name:
                    conditions.append("LOWER(COALESCE(s.primary_class, '')) LIKE %s")
                    params.append(f"%{class_name.lower()}%")
                
                if club:
                    conditions.append("(LOWER(COALESCE(s.primary_club, '')) = LOWER(%s) OR LOWER(COALESCE(s.club_1, '')) = LOWER(%s))")
                    params.extend([club, club])
                
                # Age filters
                current_year = 2025
                if age_exact:
                    conditions.append("s.year_of_birth = %s")
                    params.append(current_year - age_exact)
                if age_min:
                    conditions.append("s.year_of_birth <= %s")
                    params.append(current_year - age_min)
                if age_max:
                    conditions.append("s.year_of_birth >= %s")
                    params.append(current_year - age_max)
                if age_under:
                    conditions.append("s.year_of_birth > %s")
                    params.append(current_year - age_under)
                if age_over:
                    conditions.append("s.year_of_birth < %s")
                    params.append(current_year - age_over)
                
                where_clause = " AND " + " AND ".join(conditions) if conditions else ""
                
                # Check if we should skip SA ID query (if searching for temp IDs only)
                skip_sa_query = (sas_id and (sas_id.strip().upper() == "T" or sas_id.upper().startswith("TMP")))
                
                # Query for SA IDs (skip if searching for temp IDs only)
                sa_rows = []
                if not skip_sa_query:
                    # STAGE 12: Optimized query - removed LATERAL JOINs and EXISTS clauses
                    # Uses pre-aggregated LEFT JOINs instead of per-row subqueries
                    # Pattern: Single pass through sas_id_personal with pre-computed result flags
                    
                    # Build sail/boat name search JOIN if needed (replaces EXISTS clause)
                    sail_boat_join = ""
                    sail_boat_filter = ""
                    sail_boat_params = []
                    if needs_sail_boat_search and q and len(q.strip()) >= 2:
                        # Only do sail/boat search for 2+ character queries to avoid slow scans
                        sail_boat_join = """
                            LEFT JOIN (
                                SELECT DISTINCT 
                                    COALESCE(res.helm_sa_sailing_id::text, res.crew_sa_sailing_id::text) as sailor_id
                                FROM public.results res
                                WHERE (res.sail_number::text LIKE %s OR LOWER(COALESCE(res.boat_name, '')) LIKE %s)
                            ) sail_boat_match ON sail_boat_match.sailor_id = s.sa_sailing_id::text
                        """
                        sail_boat_filter = "OR sail_boat_match.sailor_id IS NOT NULL"
                        q_trimmed = q.strip()
                        q_lower = f"%{q_trimmed.lower()}%"
                        sail_boat_params = [f"%{q_trimmed}%", q_lower]
                    
                    # STAGE 12 FIX: Removed expensive CTEs that scan entire results table
                    # These were causing 7-18 second delays on every search
                    # Simple query is much faster - role defaults to 'helm' which is fine
                    sql_sa = f"""
                        SELECT DISTINCT
                            s.sa_sailing_id::text as sas_id,
                            s.last_name as surname,
                            s.first_name as first_names,
                            s.primary_class as class_name,
                            'helm' as role,
                            COALESCE(s.primary_club, s.club_1) as club,
                            (
                                SELECT TRIM(COALESCE(cfu.club_fullname, ''))
                                FROM public.clubs cfu
                                WHERE TRIM(COALESCE(s.primary_club, s.club_1, '')) <> ''
                                  AND UPPER(TRIM(COALESCE(cfu.club_abbrev, ''))) = UPPER(TRIM(COALESCE(s.primary_club, s.club_1, '')))
                                LIMIT 1
                            ) AS club_fullname,
                            s.province,
                            NULL::text as last_regatta_name,
                            NULL::integer as rank,
                            NULL::text as regatta_date,
                            NULL::text as regatta_number,
                            NULL::text as sail_number,
                            NULL::text as boat_name,
                            NULL::text as bow_no,
                            s.year_of_birth as born
                        FROM public.sas_id_personal s
                        {sail_boat_join}
                        WHERE 1=1 {where_clause}{" " + sail_boat_filter if sail_boat_filter else ""}
                        ORDER BY surname NULLS LAST, first_names NULLS LAST, sas_id
                        LIMIT %s
                    """
                    # Combine params: sail_boat_params first (for JOIN), then existing params, then limit
                    final_params = sail_boat_params + params + [limit]
                    cur.execute(sql_sa, final_params)
                    sa_rows = cur.fetchall()
                
                # Query for Temp IDs
                temp_conditions = []
                temp_params = []
                temp_rows = []  # Initialize to avoid UnboundLocalError
                
                # Include temp IDs if:
                # 1. sas_id parameter is "T" or "TMP" or starts with "TMP:"
                # 2. q is "T" or starts with "TMP"
                # 3. q is empty (show all)
                should_show_temp_ids = (
                    (sas_id and (sas_id.strip().upper() == "T" or sas_id.upper().startswith("TMP"))) or
                    (not q or q.strip() == "" or q.strip().upper() == "T" or q.upper().startswith("TMP"))
                )
                
                if should_show_temp_ids:
                    # Show all temp IDs unless filtered
                    # Check sas_id first (more specific)
                    if sas_id:
                        if sas_id.upper().startswith("TMP:") and ":" in sas_id:
                            # Specific temp ID like TMP:1 from sas_id parameter
                            tmp_num = sas_id.split(":")[-1].strip()
                            if tmp_num.isdigit():
                                temp_conditions.append("t.temp_id = %s")
                                temp_params.append(int(tmp_num))
                        # Otherwise "T" or "TMP" shows all temp IDs
                    elif q and q.upper().startswith("TMP:") and ":" in q:
                        # Specific temp ID like TMP:1 from q parameter
                        tmp_num = q.split(":")[-1].strip()
                        if tmp_num.isdigit():
                            temp_conditions.append("t.temp_id = %s")
                            temp_params.append(int(tmp_num))
                    
                    # Apply name filter if q is not a temp ID pattern (multi-word: each token must match full_name)
                    if q and not q.upper().startswith("TMP") and q.strip().upper() != "T" and len(q.strip()) >= 2:
                        qt = q.strip()
                        tokens_t = [t for t in qt.lower().split() if t]
                        q_lower = f"%{qt.lower()}%"
                        exists_tail = """
                             OR EXISTS (
                                 SELECT 1 FROM public.results res 
                                 WHERE (res.helm_temp_id = 'TMP:' || t.temp_id::text 
                                        OR res.crew_temp_id = 'TMP:' || t.temp_id::text)
                                 AND (res.sail_number::text LIKE %s OR LOWER(COALESCE(res.boat_name, '')) LIKE %s)
                             ))"""
                        if len(tokens_t) >= 2:
                            name_ands = []
                            for tok in tokens_t:
                                esc = _escape_like(tok)
                                pat = f"%{esc}%" if len(tok) > 1 else f"{esc}%"
                                name_ands.append("LOWER(COALESCE(t.full_name,'')) LIKE %s")
                                temp_params.append(pat)
                            temp_conditions.append("((" + " AND ".join(name_ands) + ")" + exists_tail)
                            temp_params.extend([f"%{qt}%", q_lower])
                        else:
                            temp_conditions.append("(LOWER(t.full_name) LIKE %s" + exists_tail)
                            temp_params.extend([q_lower, f"%{qt}%", q_lower])
                elif q:
                    # Name / sail / boat (not temp-ID listing). Single digit keeps legacy LIKE; multi-word uses AND on tokens.
                    qt = q.strip()
                    exists_tail = """
                         OR EXISTS (
                             SELECT 1 FROM public.results res 
                             WHERE (res.helm_temp_id = 'TMP:' || t.temp_id::text 
                                    OR res.crew_temp_id = 'TMP:' || t.temp_id::text)
                             AND (res.sail_number::text LIKE %s OR LOWER(COALESCE(res.boat_name, '')) LIKE %s)
                         ))"""
                    if len(qt) < 2:
                        if qt.isdigit():
                            q_lower = f"%{qt.lower()}%"
                            temp_conditions.append("(LOWER(t.full_name) LIKE %s" + exists_tail)
                            temp_params.extend([q_lower, f"%{qt}%", q_lower])
                    else:
                        tokens_t = [t for t in qt.lower().split() if t]
                        q_lower = f"%{qt.lower()}%"
                        if len(tokens_t) >= 2:
                            name_ands = []
                            for tok in tokens_t:
                                esc = _escape_like(tok)
                                pat = f"%{esc}%" if len(tok) > 1 else f"{esc}%"
                                name_ands.append("LOWER(COALESCE(t.full_name,'')) LIKE %s")
                                temp_params.append(pat)
                            temp_conditions.append("((" + " AND ".join(name_ands) + ")" + exists_tail)
                            temp_params.extend([f"%{qt}%", q_lower])
                        else:
                            temp_conditions.append("(LOWER(t.full_name) LIKE %s" + exists_tail)
                            temp_params.extend([q_lower, f"%{qt}%", q_lower])
                
                # Apply first_names and surname filters to temp IDs too
                if first_names:
                    # Extract first name from full_name for temp IDs
                    temp_conditions.append("""
                        LOWER(COALESCE(t.first_name, 
                            CASE 
                                WHEN POSITION(' ' IN t.full_name) > 0 
                                THEN SUBSTRING(t.full_name FROM 1 FOR POSITION(' ' IN t.full_name) - 1)
                                ELSE t.full_name
                            END
                        )) LIKE %s
                    """)
                    temp_params.append(f"{first_names.lower()}%")
                
                if surname:
                    # Extract last name from full_name for temp IDs
                    temp_conditions.append("""
                        LOWER(COALESCE(t.last_name,
                            CASE 
                                WHEN POSITION(' ' IN t.full_name) > 0 
                                THEN SUBSTRING(t.full_name FROM POSITION(' ' IN t.full_name) + 1)
                                ELSE ''
                            END
                        )) LIKE %s
                    """)
                    temp_params.append(f"{surname.lower()}%")
                
                # Apply other filters to temp IDs too (club, class)
                # These need to be filtered from results table, not temp_people
                if club:
                    # Filter by club from results table
                    temp_conditions.append("EXISTS (SELECT 1 FROM public.results res JOIN public.clubs c ON c.club_id = res.club_id WHERE (res.helm_temp_id = 'TMP:' || t.temp_id::text OR res.crew_temp_id = 'TMP:' || t.temp_id::text OR res.crew2_temp_id = 'TMP:' || t.temp_id::text OR res.crew3_temp_id = 'TMP:' || t.temp_id::text) AND LOWER(c.club_abbrev) = LOWER(%s))")
                    temp_params.append(club)
                
                if class_name:
                    # Filter by class from results table
                    temp_conditions.append("EXISTS (SELECT 1 FROM public.results res JOIN public.classes c ON c.class_id = res.class_id WHERE (res.helm_temp_id = 'TMP:' || t.temp_id::text OR res.crew_temp_id = 'TMP:' || t.temp_id::text OR res.crew2_temp_id = 'TMP:' || t.temp_id::text OR res.crew3_temp_id = 'TMP:' || t.temp_id::text) AND LOWER(c.class_name) LIKE LOWER(%s))")
                    temp_params.append(f"%{class_name}%")

                temp_where = " AND " + " AND ".join(temp_conditions) if temp_conditions else ""

                sql_temp = f"""
                    SELECT
                        'TMP:' || t.temp_id::text as sas_id,
                        COALESCE(t.last_name, 
                            CASE 
                                WHEN POSITION(' ' IN t.full_name) > 0 
                                THEN SUBSTRING(t.full_name FROM POSITION(' ' IN t.full_name) + 1)
                                ELSE ''
                            END
                        ) as surname,
                        COALESCE(t.first_name,
                            CASE 
                                WHEN POSITION(' ' IN t.full_name) > 0 
                                THEN SUBSTRING(t.full_name FROM 1 FOR POSITION(' ' IN t.full_name) - 1)
                                ELSE t.full_name
                            END
                        ) as first_names,
                        COALESCE(t.primary_class, 'N/A') as class_name,
                        CASE 
                            WHEN EXISTS(SELECT 1 FROM public.results res WHERE res.helm_temp_id = 'TMP:' || t.temp_id::text) THEN 'helm'
                            WHEN EXISTS(SELECT 1 FROM public.results res WHERE res.crew_temp_id = 'TMP:' || t.temp_id::text) THEN 'crew'
                            ELSE 'helm'
                        END as role,
                        COALESCE(t.primary_club, t.club_1, 'N/A') as club,
                        COALESCE(last_regatta.event_name, 'N/A') as last_regatta_name,
                        last_regatta.rank,
                        last_regatta.end_date::text as regatta_date,
                        last_regatta.regatta_number,
                        last_regatta.sail_number,
                        most_common.boat_name,
                        most_common.bow_no,
                        t.year_of_birth as born
                    FROM public.temp_people t
                    LEFT JOIN LATERAL (
                        SELECT res.rank, r.event_name, r.end_date, r.regatta_number, res.sail_number
                        FROM public.results res
                        JOIN public.regattas r ON r.regatta_id = res.regatta_id
                        WHERE (res.helm_temp_id = 'TMP:' || t.temp_id::text
                           OR res.crew_temp_id = 'TMP:' || t.temp_id::text
                           OR res.crew2_temp_id = 'TMP:' || t.temp_id::text
                           OR res.crew3_temp_id = 'TMP:' || t.temp_id::text)
                          AND res.raced = TRUE
                          AND (r.end_date IS NULL OR r.end_date <= CURRENT_DATE)
                        ORDER BY r.end_date DESC NULLS LAST, r.start_date DESC NULLS LAST
                        LIMIT 1
                    ) last_regatta ON true
                    LEFT JOIN LATERAL (
                        SELECT 
                            (SELECT res2.boat_name FROM public.results res2 
                             WHERE (res2.helm_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew2_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew3_temp_id = 'TMP:' || t.temp_id::text)
                               AND res2.raced = TRUE
                               AND res2.boat_name IS NOT NULL AND res2.boat_name != ''
                             GROUP BY res2.boat_name
                             ORDER BY COUNT(*) DESC
                             LIMIT 1) as boat_name,
                            (SELECT res2.bow_no FROM public.results res2 
                             WHERE (res2.helm_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew2_temp_id = 'TMP:' || t.temp_id::text
                                    OR res2.crew3_temp_id = 'TMP:' || t.temp_id::text)
                               AND res2.raced = TRUE
                               AND res2.bow_no IS NOT NULL AND res2.bow_no != ''
                             GROUP BY res2.bow_no
                             ORDER BY COUNT(*) DESC
                             LIMIT 1) as bow_no
                    ) most_common ON true
                    WHERE 1=1 {temp_where}
                    ORDER BY COALESCE(t.last_name, t.full_name), COALESCE(t.first_name, ''), t.temp_id
                    LIMIT %s
                """
                temp_params.append(limit)
                if temp_where:
                    cur.execute(sql_temp, temp_params)
                else:
                    cur.execute(sql_temp, [limit])
                temp_rows = cur.fetchall()
                
                # Combine results
                for row in sa_rows:
                    rows.append(dict(row))
                for row in temp_rows:
                    rows.append(dict(row))
                
                return rows[:limit]
    except Exception as e:
        import traceback
        traceback.print_exc()
        return []
    finally:
        if conn:
            return_db_connection(conn)

@app.get("/api/isp-codes")
def api_isp_codes():
    """Return list of World Sailing ISP (International Sailing Penalty) codes"""
    return [
        {"code": "DNC", "description": "Did Not Compete"},
        {"code": "DNS", "description": "Did Not Start"},
        {"code": "DNF", "description": "Did Not Finish"},
        {"code": "RET", "description": "Retired"},
        {"code": "DSQ", "description": "Disqualified"},
        {"code": "OCS", "description": "On Course Side"},
        {"code": "BFD", "description": "Black Flag Disqualification"},
        {"code": "UFD", "description": "U Flag Disqualification"},
        {"code": "DPI", "description": "Discretionary Penalty Imposed"}
    ]

# Class name resolution: full phrase -> also match aliases (e.g. Laser -> ILCA). Use full phrase so "Optimist A" matches only that class.
CLASS_SEARCH_ALIASES = {
    "laser": ["laser", "ilca"],
    "ilca": ["ilca", "laser"],
    "ilca 4": ["ilca 4", "ilca4", "laser 4", "laser4", "radial"],
    "ilca 6": ["ilca 6", "ilca6", "laser standard", "laser radial"],
    "ilca 7": ["ilca 7", "ilca7", "laser"],
    "optimist": ["optimist", "opti"],
    "opti": ["opti", "optimist"],
    "optimist a": ["optimist a"],
    "optimist b": ["optimist b"],
    "optimist c": ["optimist c"],
}

# Single-letter / short abbreviations -> full word so the filter NARROWS (e.g. "Y nationals" = Youth nationals only).
SEARCH_TERM_ABBREVIATIONS = {
    "y": "youth",
    "j": "junior",
}

def _escape_like(s: str) -> str:
    """Escape % and _ for use in SQL LIKE patterns."""
    if not s:
        return s
    return s.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")


def _parse_search_terms_and_year(q: str) -> tuple:
    """Parse search query into (search_terms, year). Strips 19xx/20xx as year. Groups known class phrases (e.g. 'Optimist A' -> one term 'optimist a') so narrow searches like 'HYC Classic 2025 Optimist A' return one result."""
    if not q or not q.strip():
        return ([], None)
    words = q.strip().split()
    raw_terms = []
    year = None
    for w in words:
        if len(w) == 4 and w.isdigit():
            y = int(w, 10)
            if 1900 <= y <= 2099 and (w.startswith("19") or w.startswith("20")):
                year = y
                continue
        raw_terms.append(w)
    # Group consecutive words that form a known class phrase (e.g. "Optimist" + "A" -> "optimist a") so "HYC Classic 2025 Optimist A" narrows correctly
    phrase_keys = sorted([k for k in CLASS_SEARCH_ALIASES.keys() if " " in k], key=len, reverse=True)
    terms = []
    i = 0
    while i < len(raw_terms):
        merged = False
        for phrase in phrase_keys:
            n = len(phrase.split())
            if i + n <= len(raw_terms):
                candidate = " ".join(raw_terms[i : i + n]).lower()
                if candidate == phrase:
                    terms.append(phrase)
                    i += n
                    merged = True
                    break
        if not merged:
            terms.append(raw_terms[i].lower())
            i += 1
    return (terms, year)


def _effective_search_term(term: str) -> str:
    """Narrow filter: expand abbreviations so 'y' -> 'youth', etc. Returns full word to match (fewer, more relevant results)."""
    if not term:
        return ""
    t = term.lower().strip()
    return SEARCH_TERM_ABBREVIATIONS.get(t, t)


def _regatta_name_term_match_sql(term: str, params: list, escape: bool = True) -> str:
    """Build SQL condition: regatta r has the term in event_name or host_club_name. Appends to params. Uses abbreviation expansion so filter narrows."""
    t = _effective_search_term(term)
    if not t:
        return "1=1"
    pat = f"%{_escape_like(t) if escape else t}%"
    params.append(pat)
    params.append(pat)
    return "(LOWER(COALESCE(r.event_name, '')) LIKE %s OR LOWER(COALESCE(r.host_club_name, '')) LIKE %s)"


def _result_row_term_match_sql(term: str, params: list, escape: bool = True) -> str:
    """Build SQL condition: this result row has the term in at least one of class, sail_number, boat_name, club, event. Uses abbreviation expansion (y->youth) and CLASS_SEARCH_ALIASES so filter narrows."""
    t = _effective_search_term(term)
    if not t:
        return "1=1"
    pat = _escape_like(t) if escape else t
    pat = f"%{pat}%"
    # Class: expand via aliases so "opti" matches Optimist; effective term (e.g. youth) used for narrowing
    class_aliases = CLASS_SEARCH_ALIASES.get(t, [t])
    class_aliases = list(dict.fromkeys(class_aliases))
    conds = []
    # sail_number (cast to text for ILIKE), boat_name
    conds.append("(res.sail_number::text ILIKE %s OR LOWER(COALESCE(res.boat_name, '')) LIKE %s)")
    params.extend([pat, pat])
    # regatta host/name only: "HYC" matches regattas HOSTED by HYC or with HYC in event name, NOT where a sailor from HYC sailed
    conds.append("(LOWER(COALESCE(r2.host_club_name, '')) LIKE %s OR LOWER(COALESCE(r2.event_name, '')) LIKE %s)")
    params.extend([pat, pat])
    # class: match any alias
    for a in class_aliases:
        apat = f"%{(_escape_like(a) if escape else a)}%"
        conds.append("(LOWER(COALESCE(c_class.class_name, res.class_original, '')) LIKE %s OR LOWER(COALESCE(res.class_original, '')) LIKE %s)")
        params.extend([apat, apat])
    return "(" + " OR ".join(conds) + ")"


def _match_reason_from_row(row: dict, terms: list) -> tuple:
    """From one result row that matched all terms, return (reason_label, term_to_highlight) e.g. ('Boat = Co-ordination', 'nati'). Only use boat/class/club — never event_name/host (that would just repeat the regatta name)."""
    if not row or not terms:
        return (None, None)
    # Only result-row fields that explain why this regatta matched; do NOT use event_name/host_club_name (redundant with regatta title)
    fields = [
        ("boat_name", "Boat"),
        ("class_name", "Class"),
        ("class_canonical", "Class"),
        ("class_original", "Class"),
        ("club_abbrev", "Club"),
        ("club_fullname", "Club"),
        ("club_raw", "Club"),
    ]
    for col, label in fields:
        val = row.get(col)
        if not val:
            continue
        # Club display: always abbrev or fullname, never raw fullname alone
        if label == "Club":
            display = (row.get("club_abbrev") or row.get("club_fullname") or row.get("club_raw") or val or "").strip()
        else:
            display = str(val).strip()
        if not display:
            continue
        low_val = display.lower()
        for term in terms:
            effective = _effective_search_term(term)
            if not effective:
                continue
            if effective.lower() in low_val:
                return (f"{label} = {display}", term)
    return (None, None)


@app.get("/api/regattas/with-counts")
def api_regattas_with_counts(
    search_q: Optional[str] = Query(None, alias="q"),
    year: Optional[int] = None,
    class_name: Optional[str] = Query(None, description="Filter regattas that sailed this class (e.g. 'Optimist A')"),
    request: Request = None,
    limit: int = Query(150, ge=1, le=400, description="Max regattas returned (hub search uses higher values)"),
):
    """Return regattas with entry counts. q = Google-like: any word matches event name, host, or class (with aliases e.g. Laser=ILCA)."""
    # Search analytics: log regatta search when q present
    if search_q and (q_ := (search_q or "").strip()):
        try:
            _log_analytics_event("search", {"search_type": "regatta", "query": q_}, session_id=request.cookies.get("session") if request else None, sas_id=None)
        except Exception:
            pass
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    
    try:
        conditions = []
        params = []
        
        # Search levels (more terms = narrower):
        # - "HYC" (wide): any regatta with HYC in name OR any regatta with a sailor from club HYC.
        # - "HYC optimist" (medium): HYC-hosted regatta where Optimist sailed, OR any regatta where an HYC member sailed Optimist (both terms in same result row).
        # - "HYC Classic 2025 Optimist A" (narrow): only regattas matching ALL terms in same row/name + year 2025; "Optimist A" kept as one phrase so it returns one result.
        # Regatta Results table is the source of truth; fallback: regatta event_name/host_club_name match all terms.
        name_match_params = []
        name_match_sql = None
        if search_q and search_q.strip():
            terms, parsed_year = _parse_search_terms_and_year(search_q)
            # Year in search text always wins: "Y Nationals 2025" must filter to 2025 only (exclude 2024)
            if parsed_year is not None:
                year = parsed_year
            if terms:
                term_conds = []
                for t in terms:
                    term_conds.append(_result_row_term_match_sql(t, params))
                results_subquery = """r.regatta_id IN (
                    SELECT DISTINCT res.regatta_id FROM results res
                    LEFT JOIN clubs c ON c.club_id = res.club_id
                    LEFT JOIN classes c_class ON c_class.class_id = res.class_id
                    JOIN regattas r2 ON r2.regatta_id = res.regatta_id
                    WHERE """
                results_subquery += " AND ".join(term_conds) + ")"
                # Regatta-level name match (same terms) so we don't miss regattas that match by name
                name_conds = [_regatta_name_term_match_sql(t, name_match_params) for t in terms]
                name_match_sql = "(" + " AND ".join(name_conds) + ")"
                conditions.append("(" + results_subquery + " OR " + name_match_sql + ")")
                params.extend(name_match_params)
            else:
                # Only year was in query; no text terms
                pass
        
        # Year filter: ONLY actual regatta date (start_date, end_date). Do NOT use r.year — it can be import/capture year and wrong.
        if year:
            conditions.append("(EXTRACT(YEAR FROM r.start_date) = %s OR EXTRACT(YEAR FROM r.end_date) = %s)")
            params.extend([year, year])
        
        # Legacy: single class_name filter — must be in results table for that regatta
        if class_name and class_name.strip():
            conditions.append("""r.regatta_id IN (
                SELECT res.regatta_id FROM results res
                LEFT JOIN classes c ON c.class_id = res.class_id
                WHERE LOWER(COALESCE(c.class_name, res.class_original, '')) LIKE %s
                   OR LOWER(COALESCE(res.class_original, '')) LIKE %s
            )""")
            class_pattern = f"%{class_name.strip().lower()}%"
            params.extend([class_pattern, class_pattern])
        
        where_clause = " AND " + " AND ".join(conditions) if conditions else ""
        
        # Exclude aggregate "Classic Series" (and similar Series > Class > Overall) — not real standalone regattas
        # Use %% so literal % is not interpreted as a placeholder by psycopg2
        exclude_series = """ AND NOT (
            LOWER(COALESCE(r.event_name, '')) LIKE '%%classic series%%'
            OR ( LOWER(COALESCE(r.event_name, '')) LIKE '%%series%%' AND LOWER(COALESCE(r.event_name, '')) LIKE '%%> overall%%' )
        ) """
        # When we have a name match, add is_best_match so frontend can show "Best match" first and "Contains HYC Club sailors" for others
        select_best_match = ""
        if name_match_sql is not None:
            select_best_match = ", (CASE WHEN " + name_match_sql + " THEN 1 ELSE 0 END) AS is_best_match"
        base_sql = """
            SELECT 
                r.regatta_id,
                r.event_name,
                r.year,
                r.regatta_number,
                r.start_date,
                r.end_date,
                r.host_club_name,
                COALESCE(c.club_abbrev, r.host_club_name) as host_club_code,
                COUNT(DISTINCT res.result_id) as entries_count
        """ + select_best_match + """
            FROM regattas r
            LEFT JOIN results res ON res.regatta_id = r.regatta_id
            LEFT JOIN clubs c ON c.club_id = r.host_club_id
            WHERE 1=1
        """ + exclude_series + """
        """
        
        # Include regattas with 0 results when they matched by name, or when regatta_number >= 375 (recent batch: 377-385)
        having_clause = "HAVING (COUNT(DISTINCT res.result_id) > 0 OR r.regatta_number >= 375)"
        if name_match_sql is not None:
            having_clause = "HAVING (COUNT(DISTINCT res.result_id) > 0 OR " + name_match_sql + " OR r.regatta_number >= 375)"
            params.extend(name_match_params)
        # Sort best match (regatta name matches all terms) first, then by regatta number/date
        order_best_first = ""
        if name_match_sql is not None:
            order_best_first = " (CASE WHEN " + name_match_sql + " THEN 0 ELSE 1 END),"
            params.extend(name_match_params)
        _lim = max(1, min(400, int(limit)))
        sql = base_sql + where_clause + """
            GROUP BY r.regatta_id, r.event_name, r.year, r.regatta_number, 
                     r.start_date, r.end_date, r.host_club_name, c.club_abbrev
        """ + having_clause + """
            ORDER BY
        """ + order_best_first + """
            r.regatta_number DESC NULLS LAST, r.year DESC NULLS LAST, r.start_date DESC NULLS LAST
            LIMIT """ + str(_lim) + """
        """

        # SELECT and ORDER BY placeholders for name_match come first in SQL string, so prepend their params
        if name_match_sql is not None:
            params = list(name_match_params) + params
        if params:
            cur.execute(sql, tuple(params))
        else:
            cur.execute(sql)
        
        rows = cur.fetchall()
        terms_for_reason = []
        if search_q and search_q.strip():
            terms_for_reason, _ = _parse_search_terms_and_year(search_q)
        # For also_matched regattas, get one result row per regatta to determine actual match (e.g. Boat = Co-ordination for "nati")
        match_detail_by_regatta = {}
        if terms_for_reason:
            also_ids = [r["regatta_id"] for r in rows if r.get("is_best_match", 0) != 1]
            if also_ids:
                match_params = []
                match_conds = [_result_row_term_match_sql(t, match_params) for t in terms_for_reason]
                try:
                    match_sql = """
                    SELECT DISTINCT ON (res.regatta_id) res.regatta_id,
                        res.boat_name, c_class.class_name AS class_canonical, res.class_original, res.club_raw,
                        c.club_abbrev, c.club_fullname, r2.event_name, r2.host_club_name
                    FROM results res
                    LEFT JOIN clubs c ON c.club_id = res.club_id
                    LEFT JOIN classes c_class ON c_class.class_id = res.class_id
                    JOIN regattas r2 ON r2.regatta_id = res.regatta_id
                    WHERE res.regatta_id = ANY(%s) AND """ + " AND ".join(match_conds) + """
                    ORDER BY res.regatta_id
                    """
                    cur.execute(match_sql, (also_ids,) + tuple(match_params))
                    for m in cur.fetchall():
                        rid = m["regatta_id"]
                        reason, term = _match_reason_from_row(m, terms_for_reason)
                        if reason:
                            match_detail_by_regatta[rid] = {"match_reason": reason, "match_reason_term": term}
                except Exception:
                    pass
        out = []
        for row in rows:
            d = dict(row)
            is_best = d.pop("is_best_match", 0) if "is_best_match" in d else 0
            if terms_for_reason:
                if is_best:
                    d["match_reason"] = "Best match"
                    d["match_reason_term"] = None
                else:
                    detail = match_detail_by_regatta.get(d["regatta_id"])
                    if detail:
                        d["match_reason"] = detail["match_reason"]
                        d["match_reason_term"] = detail.get("match_reason_term")
                    else:
                        d["match_reason"] = "Host or event name match"
                        d["match_reason_term"] = None
            else:
                d["match_reason"] = None
                d["match_reason_term"] = None
            out.append(d)

        # Deduplicate by regatta_number: each regatta number appears once. Entries = full regatta total (all classes).
        total_entries_by_num = {}
        for d in out:
            num = d.get("regatta_number")
            key = num if num is not None else d.get("regatta_id", "")
            total_entries_by_num[key] = total_entries_by_num.get(key, 0) + (d.get("entries_count") or 0)
        by_regatta_number = {}
        for d in out:
            num = d.get("regatta_number")
            key = num if num is not None else d.get("regatta_id", "")
            name_len = len((d.get("event_name") or "").strip())
            is_best = d.get("match_reason") == "Best match"
            if key not in by_regatta_number:
                chosen = dict(d)
                chosen["entries_count"] = total_entries_by_num.get(key, d.get("entries_count") or 0)
                by_regatta_number[key] = chosen
            else:
                existing = by_regatta_number[key]
                cur_best = existing.get("match_reason") == "Best match"
                cur_len = len((existing.get("event_name") or "").strip())
                if (is_best and not cur_best) or (is_best == cur_best and name_len < cur_len):
                    chosen = dict(d)
                    chosen["entries_count"] = total_entries_by_num.get(key, d.get("entries_count") or 0)
                    by_regatta_number[key] = chosen
        out = list(by_regatta_number.values())

        # Overwrite entries_count with actual total from results (full regatta, all classes) so Entries is never 0 when regatta has results
        if out:
            regatta_numbers = [r["regatta_number"] for r in out if r.get("regatta_number") is not None]
            null_num_ids = [r["regatta_id"] for r in out if r.get("regatta_id") and r.get("regatta_number") is None]
            total_by_num = {}
            total_by_id = {}
            try:
                if regatta_numbers:
                    cur.execute("""
                        SELECT r.regatta_number, COUNT(DISTINCT res.result_id) AS cnt
                        FROM regattas r
                        LEFT JOIN results res ON res.regatta_id = r.regatta_id
                        WHERE r.regatta_number = ANY(%s)
                        GROUP BY r.regatta_number
                    """, (regatta_numbers,))
                    for r in cur.fetchall():
                        total_by_num[r["regatta_number"]] = r.get("cnt") or 0
                if null_num_ids:
                    cur.execute("""
                        SELECT regatta_id, COUNT(DISTINCT result_id) AS cnt
                        FROM results
                        WHERE regatta_id = ANY(%s)
                        GROUP BY regatta_id
                    """, (null_num_ids,))
                    for r in cur.fetchall():
                        total_by_id[r["regatta_id"]] = r.get("cnt") or 0
                for d in out:
                    num = d.get("regatta_number")
                    rid = d.get("regatta_id")
                    if num is not None:
                        d["entries_count"] = total_by_num.get(num, d.get("entries_count") or 0)
                    else:
                        d["entries_count"] = total_by_id.get(rid, d.get("entries_count") or 0)
            except Exception:
                pass

        # Sort: best match first, then by regatta_number desc, year desc
        if name_match_sql is not None and terms_for_reason:
            out.sort(key=lambda x: (0 if x.get("match_reason") == "Best match" else 1, -(x.get("regatta_number") or 0), -(x.get("year") or 0), str(x.get("start_date") or "")))
        else:
            out.sort(key=lambda x: (-(x.get("regatta_number") or 0), -(x.get("year") or 0), str(x.get("start_date") or "")))

        # Add slug for /regatta/{slug} URLs (same logic as _get_regatta_by_slug)
        for d in out:
            name = (d.get("event_name") or "").strip()
            if name:
                s = re.sub(r"[^\w\s\-]", "", name).strip().lower()
                d["slug"] = re.sub(r"\s+", "-", s).strip("-")
            else:
                d["slug"] = ""

        return out
    except Exception as e:
        print(f"Error fetching regattas: {e}")
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        cur.close()
        conn.close()

@app.get("/api/regatta/{regatta_id}/class-entries")
def api_regatta_class_entries(regatta_id: str):
    """Return class entry counts for a regatta (only raced=TRUE entries)"""
    t0 = time.time()
    print(f"[TRACE] getRegattaClassEntries({regatta_id}) START")
    rows = q("""
        SELECT 
            COALESCE(c.class_name, rb.class_canonical, rb.class_original) as class_name,
            COUNT(DISTINCT res.result_id) as entries
        FROM regatta_blocks rb
        LEFT JOIN results res ON res.block_id = rb.block_id AND res.raced = TRUE
        LEFT JOIN classes c ON c.class_id = rb.class_id
        WHERE rb.regatta_id = %s
        GROUP BY COALESCE(c.class_id, 0), COALESCE(c.class_name, rb.class_canonical, rb.class_original)
        HAVING COUNT(DISTINCT res.result_id) > 0
        ORDER BY COALESCE(c.class_name, rb.class_canonical, rb.class_original)
    """, (regatta_id,))
    
    # Return as object with class names as keys
    result = {}
    for row in rows:
        class_name = row['class_name']
        entries = row['entries']
        result[class_name.lower()] = {
            'name': class_name,
            'entries': entries
        }
    
    t1 = time.time()
    print(f"[TRACE] getRegattaClassEntries({regatta_id}) took {t1-t0:.3f}s ({len(result)} classes)")
    return result

@app.get("/api/regatta/{regatta_id}")
def api_regatta(regatta_id: str, request: Request = None):
    """Return all regatta data including blocks and results"""
    t0 = time.time()
    print(f"[TRACE] getRegatta({regatta_id}) START")
    try:
        rows = q("""
            SELECT 
                r.regatta_id,
                r.event_name,
                r.year,
                r.regatta_number,
                r.start_date,
                r.end_date,
                r.regatta_type,
                COALESCE(NULLIF(TRIM(r.result_status), ''), NULLIF(TRIM(res.result_status), ''), 'Final') AS result_status,
                COALESCE(r.as_at_time::timestamptz, res.as_at_time::timestamptz) AS as_at_time,
                r.host_club_id,
            c.club_abbrev as host_club_code,
            COALESCE(c.club_abbrev, c.club_fullname) as host_club_name,
            rb.block_id,
            rb.fleet_label,
            rb.class_canonical,
                rb.class_original,
                rb.races_sailed,
                rb.discard_count,
                rb.to_count,
                rb.scoring_system,
                res.result_id,
                res.rank,
                res.helm_name,
                res.crew_name,
                res.sail_number,
                res.club_raw,
                res.club_id,
                c2.club_abbrev as club_abbrev,
                COALESCE(c2.club_abbrev, c2.club_fullname) as club_fullname,
                res.race_scores,
                res.total_points_raw,
                res.nett_points_raw,
                res.helm_sa_sailing_id,
                res.crew_sa_sailing_id,
                res.helm_temp_id,
                res.crew_temp_id,
                res.boat_name,
                res.jib_no,
                res.bow_no,
                res.hull_no,
                res.raced,
                COALESCE(res.class_id, rb.class_id) as result_class_id,
                res.class_original as result_class_original,
                COALESCE(cls_res.class_name, res.class_original, rb.class_canonical, rb.class_original) as class_name
            FROM regattas r
            LEFT JOIN clubs c ON c.club_id = r.host_club_id
            LEFT JOIN regatta_blocks rb ON rb.regatta_id = r.regatta_id
            LEFT JOIN results res ON res.block_id = rb.block_id
            LEFT JOIN clubs c2 ON c2.club_id = res.club_id
            LEFT JOIN classes cls_res ON cls_res.class_id = COALESCE(res.class_id, rb.class_id)
            WHERE r.regatta_id = %s
            ORDER BY rb.block_id, COALESCE(res.rank, 99999), res.result_id
        """, (regatta_id,))
        
        # If slug-like regatta_id (e.g. from sailor profile "334-2025-overberg-champs"), try regatta_number
        if not rows and regatta_id and "-" in str(regatta_id).strip():
            try:
                first_part = str(regatta_id).strip().split("-")[0]
                if first_part.isdigit():
                    rows = q("""
                        SELECT r.regatta_id FROM regattas r WHERE r.regatta_number::text = %s LIMIT 1
                    """, (first_part,))
                    if rows and rows[0]:
                        resolved_id = str(rows[0].get("regatta_id") or first_part)
                        rows = q("""
                            SELECT 
                                r.regatta_id, r.event_name, r.year, r.regatta_number,
                                COALESCE(NULLIF(TRIM(r.result_status), ''), NULLIF(TRIM(res.result_status), ''), 'Final') AS result_status,
                                COALESCE(r.as_at_time::timestamptz, res.as_at_time::timestamptz) AS as_at_time,
                                r.host_club_id,
                                c.club_abbrev as host_club_code, COALESCE(c.club_abbrev, c.club_fullname) as host_club_name,
                                rb.block_id, rb.fleet_label, rb.class_canonical, rb.class_original, rb.races_sailed, rb.discard_count, rb.to_count, rb.scoring_system,
                                res.result_id, res.rank, res.helm_name, res.crew_name, res.sail_number, res.club_raw, res.club_id, c2.club_abbrev as club_abbrev,
                                COALESCE(c2.club_abbrev, c2.club_fullname) as club_fullname,
                                res.race_scores, res.total_points_raw, res.nett_points_raw, res.helm_sa_sailing_id, res.crew_sa_sailing_id, res.helm_temp_id, res.crew_temp_id,
                                res.boat_name, res.jib_no, res.bow_no, res.hull_no, res.raced,
                                COALESCE(res.class_id, rb.class_id) as result_class_id, res.class_original as result_class_original,
                                COALESCE(cls_res.class_name, res.class_original, rb.class_canonical, rb.class_original) as class_name
                            FROM regattas r
                            LEFT JOIN clubs c ON c.club_id = r.host_club_id
                            LEFT JOIN regatta_blocks rb ON rb.regatta_id = r.regatta_id
                            LEFT JOIN results res ON res.block_id = rb.block_id
                            LEFT JOIN clubs c2 ON c2.club_id = res.club_id
                            LEFT JOIN classes cls_res ON cls_res.class_id = COALESCE(res.class_id, rb.class_id)
                            WHERE r.regatta_id = %s
                            ORDER BY rb.block_id, COALESCE(res.rank, 99999), res.result_id
                        """, (resolved_id,))
            except Exception:
                pass
        if not rows:
            # Safe empty response: class-results iframe and other clients must not trigger 500 from indexing [0].
            print(
                f"[api_regatta] no data for regatta_id={regatta_id!r} (no matching regatta row; returning empty list)",
                flush=True,
            )
            return []

        # SPECIAL CASE: For Regatta 374, sort by master standings for all classes that have standings
        first_row = rows[0]
        regatta_number = first_row.get('regatta_number')
        if regatta_number == '374' or (isinstance(regatta_number, int) and regatta_number == 374):
            # Group rows by class
            class_blocks = {}  # {class_name: {block_id: [rows]}}
            other_rows = []
            
            for row in rows:
                if row.get('result_id'):  # Only process result rows, not header rows
                    block_id = row.get('block_id')
                    class_name = (row.get('class_name') or row.get('class_original') or '').strip()
                    if not class_name:
                        other_rows.append(row)
                        continue
                    
                    # Normalize class name (remove "Fleet" suffix, normalize case)
                    normalized_class = class_name.replace(' Fleet', '').strip()
                    # Store original for lookup, but use normalized for grouping
                    normalized_key = normalized_class.upper()  # Use uppercase for consistent matching
                    
                    if normalized_key not in class_blocks:
                        class_blocks[normalized_key] = {'original_name': normalized_class, 'blocks': {}}
                    if block_id not in class_blocks[normalized_key]['blocks']:
                        class_blocks[normalized_key]['blocks'][block_id] = []
                    class_blocks[normalized_key]['blocks'][block_id].append(row)
                else:
                    other_rows.append(row)  # Keep header rows
            
            # Check which classes have standings in database (case-insensitive)
            conn_standings = None
            try:
                conn_standings = get_db_connection()
                with conn_standings.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                    if class_blocks:
                        # Get all class names from database and create case-insensitive lookup
                        cur.execute("""
                            SELECT DISTINCT class_name, UPPER(class_name) as upper_name
                            FROM standing_list
                        """)
                        db_classes = {row['upper_name']: row['class_name'] for row in cur.fetchall()}
                    else:
                        db_classes = {}
            except Exception as e:
                print(f"[WARNING] Failed to check database for standings: {e}")
                db_classes = {}
            finally:
                if conn_standings:
                    return_db_connection(conn_standings)
            
            # Sort each class that has standings
            sorted_class_rows = []
            unsorted_class_rows = []
            
            for normalized_key, class_data in class_blocks.items():
                original_class_name = class_data.get('original_name', normalized_key)
                blocks = class_data.get('blocks', {})
                
                # Check if this class has standings (case-insensitive)
                db_class_name = db_classes.get(normalized_key)
                if db_class_name:
                    # Get master standings from database (use database class name)
                    conn_standings = None
                    try:
                        conn_standings = get_db_connection()
                        with conn_standings.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                            cur.execute("""
                                SELECT 
                                    sl.sailor_id,
                                    sl.rank as main_rank
                                FROM standing_list sl
                                WHERE sl.class_name = %s
                                ORDER BY sl.rank ASC
                            """, (db_class_name,))
                            
                            master_rank_map = {}
                            for row in cur.fetchall():
                                sid = str(row['sailor_id'])
                                master_rank_map[sid] = row['main_rank']
                            
                            print(f"[REGATTA 374] Sorting {original_class_name} by master standings (found {len(master_rank_map)} sailors in standings)")
                            
                            # Sort each block by master standings
                            for block_id, block_rows in blocks.items():
                                # Sort by master rank (99999 for sailors not in master standings)
                                block_rows.sort(key=lambda r: master_rank_map.get(
                                    str(r.get('helm_sa_sailing_id') or r.get('helm_temp_id') or ''), 99999
                                ))
                                
                                # Reassign ranks 1-N based on master standings order
                                for i, row in enumerate(block_rows, 1):
                                    old_rank = row.get('rank')
                                    row['rank'] = i
                                    sailor_id = str(row.get('helm_sa_sailing_id') or row.get('helm_temp_id') or '')
                                    master_rank = master_rank_map.get(sailor_id, 'N/A')
                                    if i <= 5:  # Log first 5 for debugging
                                        print(f"[REGATTA 374] {original_class_name} Rank {i}: {row.get('helm_name')} (ID: {sailor_id}, Master Rank: {master_rank}, Old Rank: {old_rank})")
                                
                                sorted_class_rows.extend(block_rows)
                    except Exception as e:
                        import traceback
                        traceback.print_exc()
                        print(f"[WARNING] Failed to sort Regatta 374 {db_class_name} by master standings: {e}")
                        # Fall back to unsorted
                        for block_rows in blocks.values():
                            unsorted_class_rows.extend(block_rows)
                    finally:
                        if conn_standings:
                            return_db_connection(conn_standings)
                else:
                    # No standings for this class, keep original order
                    print(f"[REGATTA 374] ⚠️  No standings found for {original_class_name} (normalized: {normalized_key}, available: {list(db_classes.keys())[:10]})")
                    for block_rows in blocks.values():
                        unsorted_class_rows.extend(block_rows)
            
            # Rebuild rows: header rows first, then sorted classes, then unsorted classes
            new_rows = [r for r in rows if not r.get('result_id')]  # Header rows
            new_rows.extend(sorted_class_rows)  # Sorted by master standings
            new_rows.extend(unsorted_class_rows)  # Other classes (no standings or error)
            new_rows.extend([r for r in other_rows if r.get('result_id')])  # Other rows
            
            rows = new_rows
        
        # Calculate totals for first row
        first_row = rows[0]
        entries_total = len([r for r in rows if r.get('result_id')])
        helms_total = len([r for r in rows if r.get('result_id') and r.get('helm_name')])
        crews_total = len([r for r in rows if r.get('result_id') and r.get('crew_name')])
        sailors_total = helms_total + crews_total
        
        # Add totals to first row
        first_row['entries_total'] = entries_total
        first_row['helms_total'] = helms_total
        first_row['crews_total'] = crews_total
        first_row['sailors_total'] = sailors_total

        # Add club_slug and host_club_slug for /club/{slug} links
        host_club_slug = _get_club_slug_by_id(first_row.get('host_club_id')) if first_row.get('host_club_id') else ''
        # Add helm_slug and crew_slug so frontend can render real /sailor/<slug> links. Only sailors in sas_id_personal get a slug (no broken URLs for Google crawl).
        sailor_ids = []
        for r in rows:
            if r.get('helm_sa_sailing_id') is not None:
                sailor_ids.append(r['helm_sa_sailing_id'])
            if r.get('crew_sa_sailing_id') is not None:
                sailor_ids.append(r['crew_sa_sailing_id'])
        slug_map = _batch_sailor_slugs_for_sas_ids(sailor_ids) if sailor_ids else {}
        for r in rows:
            name = (r.get('club_abbrev') or r.get('club_fullname') or r.get('club_raw') or '').strip()
            r['club_slug'] = _club_slug_from_name(name) if name else ''
            r['host_club_slug'] = host_club_slug or ''
            hid = r.get('helm_sa_sailing_id')
            r['helm_slug'] = slug_map.get(str(hid)) if hid is not None else None
            cid = r.get('crew_sa_sailing_id')
            r['crew_slug'] = slug_map.get(str(cid)) if cid is not None else None

        # Internal analytics: regatta_view (dedupe 5s per session)
        try:
            rid = str(first_row.get("regatta_id") or regatta_id or "")
            if rid:
                _log_analytics_event("regatta_view", {"regatta_id": rid}, session_id=request.cookies.get("session") if request else None, sas_id=None)
        except Exception:
            pass
        return rows
    except Exception as e:
        import traceback
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=str(e))


@app.get("/api/regatta/{regatta_id}/podium.png")
def api_regatta_podium_png(regatta_id: str, class_name: str = Query(..., alias="class")):
    """Generate podium PNG for regatta class (overlays top 3 on master-podium.png)."""
    _proj = os.path.dirname(os.path.abspath(__file__))
    if _proj not in sys.path:
        sys.path.insert(0, _proj)
    try:
        from scripts.generate_podium import render_podium_to_bytes, regatta_rows_to_podium_data
    except ImportError as e:
        print(f"[podium] Import error: {e}")
        raise HTTPException(status_code=503, detail=f"Podium generation unavailable: {e}")

    try:
        rows = api_regatta(regatta_id)
    except HTTPException:
        raise
    except Exception as e:
        print(f"[podium] api_regatta error: {e}")
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=f"Failed to load regatta: {e}")

    data_by_place = regatta_rows_to_podium_data(rows, class_name)
    if not data_by_place:
        raise HTTPException(status_code=404, detail=f"No podium data for class '{class_name}'")

    try:
        png_bytes = render_podium_to_bytes(data_by_place)
    except FileNotFoundError as e:
        print(f"[podium] FileNotFoundError: {e}")
        raise HTTPException(status_code=503, detail=str(e))
    except Exception as e:
        print(f"[podium] render_podium_to_bytes error: {e}")
        traceback.print_exc()
        raise HTTPException(status_code=500, detail=f"Podium image generation failed: {e}")

    return Response(content=png_bytes, media_type="image/png")


def _filter_regatta_rows_by_class(rows: list, class_id: str):
    """Filter regatta rows (from api_regatta) to those matching class_id.

    class_id may be: regatta_blocks.block_id, classes.class_id (numeric — same as
    /api/events podium_class_id), or a class name fragment.
    """
    if not rows or not class_id:
        return []
    class_id = str(class_id).strip()
    class_id_lower = class_id.lower()
    out = []
    for r in rows:
        if not r.get("result_id"):
            continue
        block_id = (r.get("block_id") or "").strip()
        class_canonical = (r.get("class_name") or r.get("class_original") or "").strip()
        res_cls = r.get("result_class_id")
        if res_cls is not None and str(res_cls).strip() == class_id:
            out.append(r)
            continue
        if block_id == class_id:
            out.append(r)
            continue
        if class_canonical.lower() == class_id_lower:
            out.append(r)
            continue
        if class_id_lower in class_canonical.lower() or class_canonical.lower() in class_id_lower:
            out.append(r)
    out.sort(key=lambda x: (int(x.get("rank")) if x.get("rank") is not None and str(x.get("rank")).isdigit() else 9999, x.get("result_id") or 0))
    return out


def _resolve_regatta_internal_id(regatta_id: str) -> Optional[str]:
    """Map public regatta id / slug prefix to regattas.regatta_id for fast SQL paths."""
    if not regatta_id or not str(regatta_id).strip():
        return None
    s = str(regatta_id).strip()
    rows = q("SELECT regatta_id::text AS rid FROM regattas WHERE regatta_id::text = %s LIMIT 1", (s,))
    if rows and rows[0].get("rid") is not None:
        return str(rows[0]["rid"])
    if "-" in s:
        fp = s.split("-")[0]
        if fp.isdigit():
            rows = q(
                "SELECT regatta_id::text AS rid FROM regattas WHERE regatta_number::text = %s LIMIT 1",
                (fp,),
            )
            if rows and rows[0].get("rid") is not None:
                return str(rows[0]["rid"])
    return None


def _podium_rows_fast_numeric_class(regatta_internal_id: str, class_id_txt: str) -> list:
    """Top 3 for classes.class_id match — avoids loading full api_regatta."""
    rows = q(
        """
        SELECT
            res.result_id,
            res.rank,
            res.helm_name,
            res.crew_name,
            res.nett_points_raw,
            res.total_points_raw,
            COALESCE(res.class_id, rb.class_id) AS result_class_id,
            rb.block_id,
            COALESCE(cls.class_name, res.class_original, rb.class_canonical, rb.class_original) AS class_name,
            res.class_original AS result_class_original
        FROM results res
        INNER JOIN regatta_blocks rb ON rb.block_id = res.block_id
        LEFT JOIN classes cls ON cls.class_id = COALESCE(res.class_id, rb.class_id)
        WHERE rb.regatta_id::text = %s
          AND res.raced = TRUE
          AND res.result_id IS NOT NULL
          AND COALESCE(res.class_id, rb.class_id)::text = %s
        ORDER BY
          CASE WHEN res.rank::text ~ '^[0-9]+$' THEN res.rank::integer ELSE 999999 END,
          res.result_id
        LIMIT 3
        """,
        (regatta_internal_id, str(class_id_txt).strip()),
    )
    if not rows:
        return []
    return [dict(r) for r in rows if r.get("result_id")]


@app.get("/api/regattas/{regatta_id}/classes/{class_id}/results")
def api_regattas_class_results(regatta_id: str, class_id: str):
    """Return class results for a regatta. Matches frontend getClassResults(regattaId, classId)."""
    try:
        rows = api_regatta(regatta_id)
    except HTTPException:
        raise
    filtered = _filter_regatta_rows_by_class(rows, class_id)
    if not filtered:
        raise HTTPException(status_code=404, detail="Class not found or no results")
    return filtered


@app.get("/api/regattas/{regatta_id}/classes/{class_id}/podium")
def api_regattas_class_podium(regatta_id: str, class_id: str):
    """Return top 3 (podium) for a regatta class. Matches frontend getPodium(regattaId, classId)."""
    cid = str(class_id).strip()
    if cid.isdigit():
        rid = _resolve_regatta_internal_id(regatta_id)
        if rid:
            try:
                fast = _podium_rows_fast_numeric_class(rid, cid)
                if len(fast) >= 1:
                    return fast
            except Exception as e:
                print(f"[podium_fast] fallback to full regatta: {e}", flush=True)
    try:
        rows = api_regatta(regatta_id)
    except HTTPException:
        raise
    filtered = _filter_regatta_rows_by_class(rows, class_id)
    podium = [r for r in filtered[:3] if r.get("result_id")]
    if not podium:
        raise HTTPException(status_code=404, detail="Class not found or no podium results")
    return podium


@app.get("/api/regattas/class/podium/overall/{overall_id}/class/{class_id}/regatta/{regatta_id}")
def api_regattas_class_podium_alt(overall_id: str, class_id: str, regatta_id: str):
    """Alternate path: class/podium/overall/.../class/{class_id}/regatta/{regatta_id}. Returns podium JSON."""
    return api_regattas_class_podium(regatta_id, class_id)


@app.get("/api/regattas/class/results/overall/{overall_id}/class/{class_id}/regatta/{regatta_id}")
def api_regattas_class_results_alt(overall_id: str, class_id: str, regatta_id: str):
    """Alternate path: class/results/overall/.../class/{class_id}/regatta/{regatta_id}. Returns results JSON."""
    return api_regattas_class_results(regatta_id, class_id)


# Must be before /api/sailor/{sailor_id} so "resolve" is not matched as sailor_id
def _resolve_response(sas_id: str, name: str, slug: str, base_url: str) -> dict:
    """Build resolve response dict; add bio when available (add-only, does not change existing keys)."""
    out = {"sas_id": sas_id, "name": name, "slug": slug, "canonical_url": f"{base_url}/sailor/{slug}"}
    if build_sailor_bio_from_db and sas_id:
        try:
            out["bio"] = build_sailor_bio_from_db(sas_id)
        except Exception:
            pass
    return out


@app.get("/api/sailor/resolve")
def api_sailor_resolve(
    slug: Optional[str] = Query(None, alias="slug"),
    sas_id: Optional[str] = Query(None, alias="sas_id"),
):
    """Resolve /sailor/<slug> to sailor identity, or get canonical slug for sas_id. Returns { sas_id, name, slug, canonical_url } and optionally bio."""
    base_url = _canonical_base_url()
    if sas_id and str(sas_id).strip().isdigit():
        full_name, canonical_slug = _get_sailor_by_sas_id_for_redirect(str(sas_id).strip())
        if full_name is not None and canonical_slug:
            return _resolve_response(str(sas_id).strip(), full_name, canonical_slug, base_url)
        # Fallback: sailor in results but not sas_id_personal
        name_from_res, canon_from_res = _get_sailor_name_from_results(str(sas_id).strip())
        if name_from_res and canon_from_res:
            return _resolve_response(str(sas_id).strip(), name_from_res, canon_from_res, base_url)
        raise HTTPException(status_code=404, detail="sailor not found")
    if not slug or not slug.strip():
        raise HTTPException(status_code=400, detail="slug or sas_id required")
    slug = slug.strip()
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            m = re.match(r"^(.+)-(\d+)$", slug)
            if m:
                name_part, sid = m.group(1), m.group(2)
                cur.execute("""
                    SELECT sa_sailing_id::text AS sas_id,
                        COALESCE(TRIM(full_name), TRIM(first_name || ' ' || COALESCE(last_name, ''))) AS full_name
                    FROM public.sas_id_personal WHERE sa_sailing_id::text = %s LIMIT 1
                """, (sid,))
                row = cur.fetchone()
                if row:
                    name = (row.get("full_name") or "").strip()
                    canonical_slug = _sailor_canonical_slug(name, sid, True)
                    return _resolve_response(sid, name, canonical_slug, base_url)
                # Fallback: sailor in results but not sas_id_personal
                name_from_res, canon_from_res = _get_sailor_name_from_results(sid)
                if name_from_res and canon_from_res:
                    return _resolve_response(sid, name_from_res, canon_from_res, base_url)
            # Normalize slug to comparable name: hyphens and spaces both become single space (so "mia-strydom-wallis" matches "Mia Strydom-Wallis")
            name_from_slug = re.sub(r"\s+", " ", slug.replace("-", " ").strip()).lower()
            if not name_from_slug:
                raise HTTPException(status_code=404, detail="sailor not found")
            cur.execute("""
                SELECT sa_sailing_id::text AS sas_id,
                    COALESCE(TRIM(full_name), TRIM(first_name || ' ' || COALESCE(last_name, ''))) AS full_name
                FROM public.sas_id_personal
                WHERE REGEXP_REPLACE(LOWER(TRIM(REPLACE(COALESCE(full_name, first_name || ' ' || COALESCE(last_name, '')), '-', ' '))), '\\s+', ' ', 'g') = %s
                LIMIT 2
            """, (name_from_slug,))
            rows = cur.fetchall()
            if not rows:
                # Fallback: name-only slug from results (regatta page links)
                name_from_res, sid_from_res = _get_sailor_by_name_slug_from_results(slug)
                if name_from_res and sid_from_res:
                    canon = _sailor_canonical_slug(name_from_res, sid_from_res, True)
                    return _resolve_response(sid_from_res, name_from_res, canon, base_url)
                raise HTTPException(status_code=404, detail="sailor not found")
            if len(rows) == 1:
                r = rows[0]
                sid = str(r.get("sas_id") or "")
                name = (r.get("full_name") or "").strip()
                canonical_slug = _sailor_canonical_slug(name, sid, False)
                return _resolve_response(sid, name, canonical_slug, base_url)
            for r in rows:
                sid = str(r.get("sas_id") or "")
                name = (r.get("full_name") or "").strip()
                cand = _sailor_canonical_slug(name, sid, True)
                if cand == slug:
                    return _resolve_response(sid, name, cand, base_url)
            r = rows[0]
            sid = str(r.get("sas_id") or "")
            name = (r.get("full_name") or "").strip()
            canonical_slug = _sailor_canonical_slug(name, sid, True)
            return _resolve_response(sid, name, canonical_slug, base_url)
        finally:
            cur.close()
            conn.close()
    except HTTPException:
        raise
    except Exception as e:
        print(f"[SEO] api_sailor_resolve: {e}")
        traceback.print_exc()
        raise HTTPException(status_code=500, detail="resolve failed")


def _normalize_name_for_slug_match(name: str) -> str:
    """Normalize name to match slug lookup (same logic as _slug_from_name but space-separated)."""
    if not name or not isinstance(name, str):
        return ""
    s = name.strip().lower().replace("&", " and ")
    s = re.sub(r"[^\w\s\-]", "", s)
    s = re.sub(r"\s+", " ", s).strip()
    return s


# First-name variants for slug/name match (Tom/Thomas, Tim/Timothy, spelling variants like Simamkele/Simankele)
_FIRST_NAME_VARIANTS = {"tom": "thomas", "thomas": "tom", "tim": "timothy", "timothy": "tim", "jim": "james", "james": "jim", "mike": "michael", "michael": "mike", "simamkele": "simankele", "simankele": "simamkele"}


def _get_name_from_sas_id_personal(sas_id: str) -> str:
    """Return canonical name from sas_id_personal so slugs match official name. Empty if not found."""
    if not sas_id or not str(sas_id).strip().isdigit():
        return ""
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT COALESCE(TRIM(full_name), TRIM(first_name || ' ' || COALESCE(last_name, ''))) AS full_name
                FROM sas_id_personal WHERE sa_sailing_id::text = %s LIMIT 1
            """, (str(sas_id).strip(),))
            row = cur.fetchone()
            return (row.get("full_name") or "").strip() if row else ""
        finally:
            cur.close()
            conn.close()
    except Exception:
        return ""


def _get_sailor_by_name_slug_from_results(slug: str):
    """Fallback: resolve name-only slug from results (helm/crew) when not in sas_id_personal.
    Returns (name, sas_id) or (None, None). Tries sas_id_personal with first-name variants if results have no SA ID."""
    if not slug or not slug.strip():
        return None, None
    norm = _normalize_name_for_slug_match(slug.replace("-", " "))
    if not norm:
        return None, None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            # Helm with SA ID
            cur.execute("""
                SELECT TRIM(helm_name) AS name, helm_sa_sailing_id::text AS sas_id
                FROM results WHERE helm_sa_sailing_id IS NOT NULL AND helm_name IS NOT NULL AND TRIM(helm_name) != ''
                  AND REGEXP_REPLACE(REGEXP_REPLACE(LOWER(TRIM(REPLACE(REPLACE(helm_name,'/',' '),'&',' and '))),'[^a-z0-9 ]',' ','g'),'\\s+',' ','g') = %s
                LIMIT 1
            """, (norm,))
            row = cur.fetchone()
            if row and row.get("name") and row.get("sas_id"):
                sid = str(row.get("sas_id") or "")
                name = _get_name_from_sas_id_personal(sid) or (row.get("name") or "").strip()
                return name, sid
            # Crew with SA ID
            cur.execute("""
                SELECT TRIM(crew_name) AS name, crew_sa_sailing_id::text AS sas_id
                FROM results WHERE crew_sa_sailing_id IS NOT NULL AND crew_name IS NOT NULL AND TRIM(crew_name) != ''
                  AND REGEXP_REPLACE(REGEXP_REPLACE(LOWER(TRIM(REPLACE(REPLACE(crew_name,'/',' '),'&',' and '))),'[^a-z0-9 ]',' ','g'),'\\s+',' ','g') = %s
                LIMIT 1
            """, (norm,))
            row = cur.fetchone()
            if row and row.get("name") and row.get("sas_id"):
                sid = str(row.get("sas_id") or "")
                name = _get_name_from_sas_id_personal(sid) or (row.get("name") or "").strip()
                return name, sid
            # Helm/crew in results but no SA ID: try sas_id_personal with first-name variant (Tom<->Thomas)
            cur.execute("SELECT 1 FROM results WHERE helm_name IS NOT NULL AND helm_name != '' AND REGEXP_REPLACE(REGEXP_REPLACE(LOWER(TRIM(REPLACE(REPLACE(helm_name,'/',' '),'&',' and '))),'[^a-z0-9 ]',' ','g'),'\\s+',' ','g') = %s UNION SELECT 1 FROM results WHERE crew_name IS NOT NULL AND crew_name != '' AND REGEXP_REPLACE(REGEXP_REPLACE(LOWER(TRIM(REPLACE(REPLACE(crew_name,'/',' '),'&',' and '))),'[^a-z0-9 ]',' ','g'),'\\s+',' ','g') = %s LIMIT 1", (norm, norm))
            if cur.fetchone() and len(norm.split()) >= 2:
                first, last = norm.split()[0], " ".join(norm.split()[1:])
                variant = _FIRST_NAME_VARIANTS.get(first)
                if variant:
                    cur.execute("""
                        SELECT sa_sailing_id::text AS sas_id, COALESCE(TRIM(full_name), TRIM(first_name||' '||COALESCE(last_name,''))) AS full_name
                        FROM sas_id_personal
                        WHERE LOWER(COALESCE(last_name,'')) = LOWER(%s)
                          AND (LOWER(COALESCE(first_name,'')) IN (LOWER(%s),LOWER(%s)) OR LOWER(COALESCE(nickname,'')) IN (LOWER(%s),LOWER(%s)))
                        ORDER BY (LOWER(COALESCE(first_name,'')) = LOWER(%s) OR LOWER(COALESCE(nickname,'')) = LOWER(%s)) DESC
                        LIMIT 1
                    """, (last, first, variant, first, variant, first, first))
                    row = cur.fetchone()
                    if row and row.get("sas_id"):
                        return (row.get("full_name") or "").strip(), str(row.get("sas_id") or "")
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[api] _get_sailor_by_name_slug_from_results: {e}")
    return None, None


def _get_sailor_name_from_results(sas_id: str):
    """Fallback: get sailor name from results (helm/crew) when not in sas_id_personal. Returns (name, slug) or (None, None).
    Prefers name from sas_id_personal when available so slug matches official name."""
    if not sas_id or not str(sas_id).strip().isdigit():
        return None, None
    sid = str(sas_id).strip()
    name = _get_name_from_sas_id_personal(sid)
    if name:
        return name, _sailor_canonical_slug(name, sid, True)
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT COALESCE(TRIM(helm_name), '') AS helm_name
                FROM results
                WHERE helm_sa_sailing_id::text = %s AND helm_name IS NOT NULL AND TRIM(helm_name) != ''
                LIMIT 1
            """, (sid,))
            row = cur.fetchone()
            if row and row.get("helm_name"):
                name = (row.get("helm_name") or "").strip()
                if name:
                    return name, _sailor_canonical_slug(name, sid, True)
            cur.execute("""
                SELECT COALESCE(TRIM(crew_name), '') AS crew_name
                FROM results
                WHERE crew_sa_sailing_id::text = %s AND crew_name IS NOT NULL AND TRIM(crew_name) != ''
                LIMIT 1
            """, (sid,))
            row = cur.fetchone()
            if row and row.get("crew_name"):
                name = (row.get("crew_name") or "").strip()
                if name:
                    return name, _sailor_canonical_slug(name, sid, True)
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[api] _get_sailor_name_from_results: {e}")
    return None, None


def _get_sas_id_by_slug(slug: str):
    """Return sas_id for slug or None. Used by /api/sailor/results/{slug} and /api/regatta/results/{slug}.
    Falls back to results table when sailor not in sas_id_personal (links from regatta pages)."""
    if not slug or not slug.strip():
        return None
    slug = slug.strip()
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            m = re.match(r"^(.+)-(\d+)$", slug)
            if m:
                sid = m.group(2)
                cur.execute(
                    "SELECT sa_sailing_id::text AS sas_id FROM public.sas_id_personal WHERE sa_sailing_id::text = %s LIMIT 1",
                    (sid,),
                )
                row = cur.fetchone()
                if row:
                    return str(row.get("sas_id") or "")
                # Fallback: sailor in results but not sas_id_personal
                cur.execute(
                    "SELECT 1 FROM results WHERE helm_sa_sailing_id::text = %s OR crew_sa_sailing_id::text = %s LIMIT 1",
                    (sid, sid),
                )
                if cur.fetchone():
                    return sid
                return None
            name_from_slug = re.sub(r"\s+", " ", slug.replace("-", " ").strip()).lower()
            if not name_from_slug:
                return None
            cur.execute("""
                SELECT sa_sailing_id::text AS sas_id FROM public.sas_id_personal
                WHERE REGEXP_REPLACE(LOWER(TRIM(REPLACE(COALESCE(full_name, first_name || ' ' || COALESCE(last_name, '')), '-', ' '))), '\\s+', ' ', 'g') = %s
                LIMIT 1
            """, (name_from_slug,))
            row = cur.fetchone()
            if row:
                return str(row.get("sas_id") or "")
            # Fallback: name-only slug from results (regatta page links)
            _, sid = _get_sailor_by_name_slug_from_results(slug)
            return sid if sid else None
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[api] _get_sas_id_by_slug: {e}")
        return None


@app.get("/api/sailor/results/{slug}")
def api_sailor_results_by_slug(slug: str, request: Request):
    """Results by sailor slug – used by result sheet popup. Resolves slug to sas_id then returns member results."""
    sas_id = _get_sas_id_by_slug(slug)
    if not sas_id:
        raise HTTPException(status_code=404, detail="sailor not found")
    return api_member_results(sas_id, request)


