_WC_COLUMN_PREF_KEYS = (
    "rank",
    "fleet",
    "class",
    "sail_no",
    "boat_name",
    "jib",
    "bow",
    "hull",
    "club",
    "helm",
    "crew",
    "race_scores",
    "total",
    "nett",
)


def _wc_regatta_column_prefs_json_path() -> Path:
    return Path(_static_dir()) / "data" / "wc_regatta_column_prefs.json"


def _default_wc_column_prefs() -> dict:
    return {k: True for k in _WC_COLUMN_PREF_KEYS}


def _read_wc_regatta_column_prefs_raw() -> dict:
    p = _wc_regatta_column_prefs_json_path()
    if not p.is_file():
        return {}
    try:
        o = json.loads(p.read_text(encoding="utf-8"))
        return o if isinstance(o, dict) else {}
    except Exception:
        return {}


def _merge_wc_column_prefs_for_regatta(regatta_id: str) -> dict:
    rid = str(regatta_id).strip()
    out = _default_wc_column_prefs()
    raw = _read_wc_regatta_column_prefs_raw().get(rid)
    if not isinstance(raw, dict):
        return out
    for k in _WC_COLUMN_PREF_KEYS:
        if k in raw:
            out[k] = bool(raw[k])
    return out


def _write_wc_regatta_column_prefs_for_regatta(regatta_id: str, prefs: dict) -> None:
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise ValueError("column prefs only for WC pilot regatta")
    all_d = dict(_read_wc_regatta_column_prefs_raw())
    merged = _merge_wc_column_prefs_for_regatta(rid)
    for k in _WC_COLUMN_PREF_KEYS:
        if k in prefs:
            merged[k] = bool(prefs[k])
    all_d[rid] = merged
    p = _wc_regatta_column_prefs_json_path()
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(all_d, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")


def _wc_regatta_header_icon_urls(regatta_id: str) -> tuple:
    """(left_url, right_url) for WC pilot slug only; else (None, None)."""
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        return None, None
    raw = _read_wc_regatta_header_icons().get(rid)
    if not isinstance(raw, dict):
        return None, None
    lu = raw.get("left")
    ru = raw.get("right")
    ls = lu.strip() if isinstance(lu, str) else None
    rs = ru.strip() if isinstance(ru, str) else None
    return (ls or None, rs or None)


def _wc_regatta_host_club_abbrev_for_regatta(regatta_id: str) -> Optional[str]:
    """Host club abbrev for regatta (for club logo path); WC pilot uses regattas.host_club_id → clubs.club_abbrev."""
    rid = str(regatta_id).strip()
    if not rid or not table_exists("regattas") or not table_exists("clubs"):
        return None
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        cur.execute(
            """
            SELECT c.club_abbrev FROM regattas r
            LEFT JOIN clubs c ON c.club_id = r.host_club_id
            WHERE r.regatta_id = %s
            LIMIT 1
            """,
            (rid,),
        )
        row = cur.fetchone()
        if not row:
            return None
        ab = row.get("club_abbrev")
        s = str(ab).strip() if ab is not None else ""
        return s or None
    finally:
        cur.close()
        return_db_connection(conn)


def _wc_regatta_header_icon_set(regatta_id: str, slot: str, url: Optional[str]) -> None:
    rid = str(regatta_id).strip()
    if slot not in ("left", "right"):
        raise ValueError("slot must be left or right")
    all_d = dict(_read_wc_regatta_header_icons())
    entry = dict(all_d.get(rid)) if isinstance(all_d.get(rid), dict) else {}
    if url is None or (isinstance(url, str) and not url.strip()):
        entry.pop(slot, None)
    else:
        entry[slot] = str(url).strip()
    if not entry:
        all_d.pop(rid, None)
    else:
        all_d[rid] = entry
    _write_wc_regatta_header_icons(all_d)


_HUB_UPLOAD_CT = {
    "image/jpeg": ".jpg",
    "image/jpg": ".jpg",
    "image/pjpeg": ".jpg",
    "image/png": ".png",
    "image/webp": ".webp",
    "image/gif": ".gif",
    "image/heic": ".heic",
    "image/heif": ".heif",
}
_HUB_UPLOAD_MAX = 4 * 1024 * 1024


def _hub_upload_extension(content_type: Optional[str], filename: Optional[str]) -> Optional[str]:
    """Resolve file extension from MIME (iPhone HEIC) or filename (empty MIME on some mobile browsers)."""
    ct = (content_type or "").split(";")[0].strip().lower()
    if ct in _HUB_UPLOAD_CT:
        return _HUB_UPLOAD_CT[ct]
    fn = (filename or "").strip().lower()
    for suf, ext in (
        (".heic", ".heic"),
        (".heif", ".heif"),
        (".jpeg", ".jpg"),
        (".jpg", ".jpg"),
        (".png", ".png"),
        (".webp", ".webp"),
        (".gif", ".gif"),
    ):
        if fn.endswith(suf):
            return ext
    if ct == "application/octet-stream" and fn:
        return _hub_upload_extension(None, fn)
    return None


@app.post("/api/admin/hub/hero/upload")
async def api_admin_hub_hero_upload(request: Request, file: UploadFile = File(...)):
    """Super admin: store image under static assets/hub/ and return public path."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    ext = _hub_upload_extension(file.content_type, file.filename)
    if not ext:
        raise HTTPException(
            status_code=400,
            detail="Use a photo file (JPEG, PNG, WebP, GIF, HEIC). If this persists on iPhone, try “Most Compatible” in Camera settings.",
        )
    dest_dir = Path(_static_dir()) / "assets" / "hub"
    dest_dir.mkdir(parents=True, exist_ok=True)
    name = f"hero-{uuid.uuid4().hex[:16]}{ext}"
    dest = dest_dir / name
    size = 0
    try:
        with open(dest, "wb") as out:
            while True:
                chunk = await file.read(65536)
                if not chunk:
                    break
                size += len(chunk)
                if size > _HUB_UPLOAD_MAX:
                    out.close()
                    dest.unlink(missing_ok=True)
                    raise HTTPException(status_code=400, detail="file too large (max 4MB)")
                out.write(chunk)
    except HTTPException:
        raise
    except Exception as e:
        dest.unlink(missing_ok=True)
        raise HTTPException(status_code=500, detail=str(e))
    url_path = f"/assets/hub/{name}"
    return {"ok": True, "image_url": url_path}


@app.post("/api/admin/hub/wc-header-icon/{slot}")
async def api_admin_hub_wc_header_icon_upload(
    request: Request,
    slot: str,
    file: UploadFile = File(...),
    apply_host_club_logo: Optional[str] = Query(None),
):
    """WC regatta header icons: same request shape as /api/admin/hub/hero/upload (file field only). Slot path: left | right.
    Optional query apply_host_club_logo=1 (right slot only): copy into artwork/Club Logo/{abbrev}.ext for /api/club-logo/ and clear WC right override."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    sl = (slot or "").strip().lower()
    if sl not in ("left", "right"):
        raise HTTPException(status_code=400, detail="slot must be left or right")
    rid = WC_DINGHY_CHAMPS_REGATTA_SLUG
    want_club_logo = str(apply_host_club_logo or "").strip().lower() in ("1", "true", "yes")
    if want_club_logo and sl != "right":
        raise HTTPException(status_code=400, detail="apply_host_club_logo is only valid for the right slot")
    ext = _hub_upload_extension(file.content_type, file.filename)
    if not ext:
        raise HTTPException(
            status_code=400,
            detail="Use a photo file (JPEG, PNG, WebP, GIF, HEIC). If this persists on iPhone, try “Most Compatible” in Camera settings.",
        )
    dest_dir = Path(_static_dir()) / "assets" / "hub"
    dest_dir.mkdir(parents=True, exist_ok=True)
    name = f"wc-hdr-{sl}-{uuid.uuid4().hex[:14]}{ext}"
    dest = dest_dir / name
    size = 0
    try:
        with open(dest, "wb") as out:
            while True:
                chunk = await file.read(65536)
                if not chunk:
                    break
                size += len(chunk)
                if size > _HUB_UPLOAD_MAX:
                    out.close()
                    dest.unlink(missing_ok=True)
                    raise HTTPException(status_code=400, detail="file too large (max 4MB)")
                out.write(chunk)
    except HTTPException:
        raise
    except Exception as e:
        dest.unlink(missing_ok=True)
        raise HTTPException(status_code=500, detail=str(e))

    if want_club_logo:
        abbrev = _wc_regatta_host_club_abbrev_for_regatta(rid)
        if not abbrev:
            dest.unlink(missing_ok=True)
            raise HTTPException(status_code=400, detail="Set host club on this regatta before saving as club logo.")
        ext_l = dest.suffix.lower()
        if ext_l not in (".png", ".jpg", ".jpeg"):
            dest.unlink(missing_ok=True)
            raise HTTPException(
                status_code=400,
                detail="To save as host club logo for all result pages, use PNG or JPEG (not HEIC/WebP/GIF here).",
            )
        safe = re.sub(r"[^\w\-]", "", abbrev)
        if not safe:
            dest.unlink(missing_ok=True)
            raise HTTPException(status_code=400, detail="Invalid host club code for club logo filename.")
        try:
            os.makedirs(CLUB_LOGO_DIR, exist_ok=True)
        except OSError as e:
            dest.unlink(missing_ok=True)
            raise HTTPException(status_code=500, detail=f"Could not create club logo directory: {e}")
        for old_ext in ("jpg", "png", "jpeg"):
            oldp = os.path.join(CLUB_LOGO_DIR, safe + "." + old_ext)
            if os.path.isfile(oldp):
                try:
                    os.unlink(oldp)
                except OSError:
                    pass
        club_dest = os.path.join(CLUB_LOGO_DIR, safe + ext_l)
        try:
            shutil.copy2(str(dest), club_dest)
            dest.unlink(missing_ok=True)
        except OSError as e:
            dest.unlink(missing_ok=True)
            raise HTTPException(status_code=500, detail=f"Could not write club logo file: {e}")
        try:
            _wc_regatta_header_icon_set(rid, "right", None)
        except OSError as e:
            try:
                os.unlink(club_dest)
            except OSError:
                pass
            cfg = _wc_regatta_header_icons_json_path()
            raise HTTPException(
                status_code=500,
                detail=f"Saved club logo but could not update WC config ({cfg}): {e}",
            )
        except Exception as e:
            try:
                os.unlink(club_dest)
            except OSError:
                pass
            raise HTTPException(status_code=500, detail=f"Could not update WC config: {e}")
        api_logo = f"/api/club-logo/{safe}"
        return {
            "ok": True,
            "slot": sl,
            "club_logo_saved": True,
            "club_logo_code": safe,
            "club_logo_url": api_logo,
        }

    url_path = f"/assets/hub/{name}"
    try:
        _wc_regatta_header_icon_set(rid, sl, url_path)
    except OSError as e:
        dest.unlink(missing_ok=True)
        cfg = _wc_regatta_header_icons_json_path()
        raise HTTPException(
            status_code=500,
            detail=f"Saved image but could not write config (check disk permissions on {cfg}): {e}",
        )
    except Exception as e:
        dest.unlink(missing_ok=True)
        raise HTTPException(status_code=500, detail=f"Could not save header icon mapping: {e}")
    return {"ok": True, "url": url_path, "slot": sl, "club_logo_saved": False}


_HUB_VIDEO_CT = {
    "video/mp4": ".mp4",
    "video/webm": ".webm",
    "video/quicktime": ".mov",
    "video/x-m4v": ".mp4",
    "video/mpeg": ".mp4",
}
_HUB_VIDEO_MAX = 48 * 1024 * 1024


def _hub_video_extension(content_type: Optional[str], filename: Optional[str]) -> Optional[str]:
    ct = (content_type or "").split(";")[0].strip().lower()
    if ct in _HUB_VIDEO_CT:
        return _HUB_VIDEO_CT[ct]
    fn = (filename or "").strip().lower()
    for suf, ext in (
        (".mp4", ".mp4"),
        (".webm", ".webm"),
        (".mov", ".mov"),
        (".m4v", ".mp4"),
    ):
        if fn.endswith(suf):
            return ext
    return None


@app.post("/api/admin/hub/hero/upload-video")
async def api_admin_hub_hero_upload_video(request: Request, file: UploadFile = File(...)):
    """Super admin: store video under static assets/hub/ and return public path."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    ext = _hub_video_extension(file.content_type, file.filename)
    if not ext:
        raise HTTPException(
            status_code=400,
            detail="Use MP4, WebM, or MOV.",
        )
    dest_dir = Path(_static_dir()) / "assets" / "hub"
    dest_dir.mkdir(parents=True, exist_ok=True)
    name = f"hero-vid-{uuid.uuid4().hex[:16]}{ext}"
    dest = dest_dir / name
    size = 0
    try:
        with open(dest, "wb") as out:
            while True:
                chunk = await file.read(65536)
                if not chunk:
                    break
                size += len(chunk)
                if size > _HUB_VIDEO_MAX:
                    out.close()
                    dest.unlink(missing_ok=True)
                    raise HTTPException(status_code=400, detail="file too large (max 48MB)")
                out.write(chunk)
    except HTTPException:
        raise
    except Exception as e:
        dest.unlink(missing_ok=True)
        raise HTTPException(status_code=500, detail=str(e))
    url_path = f"/assets/hub/{name}"
    return {"ok": True, "url": url_path, "type": "video"}


@app.get("/api/admin/hub/assets")
async def api_admin_hub_assets(request: Request):
    """Super admin: list existing files in assets/hub/ for album picker."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    dest_dir = Path(_static_dir()) / "assets" / "hub"
    items = []
    image_ext = {".jpg", ".jpeg", ".png", ".webp", ".gif", ".heic", ".heif"}
    video_ext = {".mp4", ".webm", ".mov", ".m4v"}
    if dest_dir.is_dir():
        for p in sorted(dest_dir.iterdir()):
            if not p.is_file():
                continue
            suf = p.suffix.lower()
            if suf in image_ext:
                kind = "image"
            elif suf in video_ext:
                kind = "video"
            else:
                continue
            items.append({"name": p.name, "url": f"/assets/hub/{p.name}", "kind": kind})
    return {"items": items}


@app.patch("/api/super-admin/regatta/{regatta_id}/event-name")
async def api_super_admin_regatta_event_name_patch(request: Request, regatta_id: str, body: dict = Body(...)):
    """Super admin only. Pilot: update regattas.event_name for WC Dinghy Champs slug only."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise HTTPException(status_code=403, detail="not editable for this regatta yet")
    if not isinstance(body, dict):
        raise HTTPException(status_code=400, detail="JSON object expected")
    en = body.get("event_name")
    if en is not None and not isinstance(en, str):
        raise HTTPException(status_code=400, detail="event_name must be a string")
    name = (en or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="event_name required")
    if len(name) > 500:
        raise HTTPException(status_code=400, detail="event_name too long (max 500)")
    if not table_exists("regattas"):
        raise HTTPException(status_code=500, detail="regattas table missing")
    conn = get_db_connection()
    cur = conn.cursor()
    try:
        cur.execute("UPDATE regattas SET event_name = %s WHERE regatta_id = %s", (name, rid))
        n = cur.rowcount
        if n == 0:
            conn.rollback()
            raise HTTPException(status_code=404, detail="regatta not found")
        conn.commit()
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        print(f"[api_super_admin_regatta_event_name_patch] {e}", flush=True)
        raise HTTPException(status_code=500, detail="database error")
    finally:
        cur.close()
        return_db_connection(conn)
    return {"ok": True, "event_name": name}


@app.get("/api/super-admin/clubs-search")
async def api_super_admin_clubs_search(
    request: Request,
    q: str = Query("", description="Substring on abbrev or full name; empty = first clubs alphabetically"),
    limit: int = Query(80, ge=1, le=150),
):
    """Super admin: search clubs by abbrev/name; returns club_id + slug for WC result-cell picker."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    qn = (q or "").strip()
    lim = max(1, min(150, int(limit)))
    if not table_exists("clubs"):
        raise HTTPException(status_code=500, detail="clubs table missing")
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        if len(qn) < 1:
            cur.execute(
                """
                SELECT club_id,
                       TRIM(COALESCE(club_abbrev, '')) AS code,
                       TRIM(COALESCE(club_fullname, '')) AS name
                FROM public.clubs
                WHERE COALESCE(TRIM(COALESCE(club_abbrev, club_fullname, '')), '') <> ''
                  AND lower(trim(COALESCE(club_abbrev, ''))) <> 'unassigned'
                ORDER BY UPPER(TRIM(COALESCE(club_abbrev, club_fullname, '')))
                LIMIT %s
                """,
                (lim,),
            )
        else:
            pat = f"%{_escape_like(qn.lower())}%"
            cur.execute(
                """
                SELECT club_id,
                       TRIM(COALESCE(club_abbrev, '')) AS code,
                       TRIM(COALESCE(club_fullname, '')) AS name
                FROM public.clubs
                WHERE COALESCE(TRIM(COALESCE(club_abbrev, club_fullname, '')), '') <> ''
                  AND lower(trim(COALESCE(club_abbrev, ''))) <> 'unassigned'
                  AND (
                    LOWER(COALESCE(club_abbrev::text, '')) LIKE %s
                    OR LOWER(COALESCE(club_fullname::text, '')) LIKE %s
                  )
                ORDER BY club_abbrev NULLS LAST, club_fullname NULLS LAST
                LIMIT %s
                """,
                (pat, pat, lim),
            )
        rows = cur.fetchall() or []
    finally:
        cur.close()
        return_db_connection(conn)
    qlower = qn.lower()
    out = []
    for r in rows:
        cid = r.get("club_id")
        if cid is None:
            continue
        code = (r.get("code") or "").strip()
        name = (r.get("name") or "").strip()
        slug = _club_slug_from_name(code or name)
        out.append({"club_id": int(cid), "code": code, "name": name, "slug": slug or ""})
    if qlower and len(out) > 1:

        def _club_sort_key(item: dict):
            c = (item.get("code") or "").strip().lower()
            n = (item.get("name") or "").strip().lower()
            if c == qlower:
                tier = 0
            elif c.startswith(qlower):
                tier = 1
            elif qlower in c:
                tier = 2
            elif qlower in n:
                tier = 3
            else:
                tier = 4
            return (tier, c or n, n)

        out.sort(key=_club_sort_key)
    return {"clubs": out}


@app.patch("/api/super-admin/sailor/{sa_id}/home-club")
async def api_super_admin_sailor_home_club_patch(request: Request, sa_id: str, body: dict = Body(...)):
    """Super admin: set sailor home club from clubs table; stores club_abbrev only (primary_club + home_club_code)."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    sid = str(sa_id).strip()
    if not sid.isdigit():
        raise HTTPException(status_code=400, detail="numeric sa_id required")
    if not isinstance(body, dict):
        raise HTTPException(status_code=400, detail="JSON object expected")
    try:
        cid = int(body.get("club_id"))
    except (TypeError, ValueError):
        raise HTTPException(status_code=400, detail="club_id required")
    if not table_exists("clubs"):
        raise HTTPException(status_code=500, detail="clubs table missing")
    if not table_exists("sas_id_personal"):
        raise HTTPException(status_code=500, detail="sas_id_personal missing")
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    abbrev = ""
    try:
        cur.execute(
            "SELECT TRIM(COALESCE(club_abbrev, '')) AS code, TRIM(COALESCE(club_fullname, '')) AS fullname FROM public.clubs WHERE club_id = %s LIMIT 1",
            (cid,),
        )
        row = cur.fetchone()
        abbrev = (row.get("code") or "").strip() if row else ""
        club_fullname_out = (row.get("fullname") or "").strip() if row else ""
        if not abbrev:
            raise HTTPException(status_code=400, detail="club has no code — pick a club with a code")
        sa_int = int(sid)
        if column_exists("sas_id_personal", "club_1"):
            cur.execute(
                "UPDATE public.sas_id_personal SET primary_club = %s, club_1 = NULL WHERE sa_sailing_id = %s",
                (abbrev, sa_int),
            )
        else:
            cur.execute(
                "UPDATE public.sas_id_personal SET primary_club = %s WHERE sa_sailing_id = %s",
                (abbrev, sa_int),
            )
        n = cur.rowcount
        if n == 0:
            conn.rollback()
            raise HTTPException(status_code=404, detail="sailor not found")
        if table_exists("sailing_id") and column_exists("sailing_id", "home_club_code"):
            cur.execute(
                "UPDATE public.sailing_id SET home_club_code = %s WHERE sa_sailing_id = %s",
                (abbrev, sa_int),
            )
        conn.commit()
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        print(f"[api_super_admin_sailor_home_club_patch] {e}", flush=True)
        raise HTTPException(status_code=500, detail="database error")
    finally:
        cur.close()
        return_db_connection(conn)
    return {"ok": True, "club_code": abbrev, "club_fullname": club_fullname_out}


@app.get("/api/super-admin/classes-search")
async def api_super_admin_classes_search(
    request: Request,
    q: str = Query("", description="Substring on class name; empty = first classes A–Z"),
    limit: int = Query(80, ge=1, le=150),
):
    """Super admin: search classes by name; returns class_id + path for WC cell picker."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    qn = (q or "").strip()
    if not table_exists("classes") or not column_exists("classes", "class_id"):
        raise HTTPException(status_code=500, detail="classes table missing")
    name_col = "class_name" if column_exists("classes", "class_name") else (
        "class_canonical" if column_exists("classes", "class_canonical") else None
    )
    if not name_col:
        return {"classes": []}
    lim = max(1, min(150, int(limit)))
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        if len(qn) < 1:
            cur.execute(
                f"""
                SELECT class_id, TRIM(COALESCE({name_col}::text, '')) AS class_name
                FROM public.classes
                WHERE TRIM(COALESCE({name_col}::text, '')) <> ''
                ORDER BY TRIM(COALESCE({name_col}::text, ''))
                LIMIT %s
                """,
                (lim,),
            )
        else:
            pat = f"%{_escape_like(qn.lower())}%"
            cur.execute(
                f"""
                SELECT class_id, TRIM(COALESCE({name_col}::text, '')) AS class_name
                FROM public.classes
                WHERE TRIM(COALESCE({name_col}::text, '')) <> ''
                  AND LOWER(TRIM(COALESCE({name_col}::text, ''))) LIKE %s
                ORDER BY TRIM(COALESCE({name_col}::text, ''))
                LIMIT %s
                """,
                (pat, lim),
            )
        rows = cur.fetchall() or []
    finally:
        cur.close()
        return_db_connection(conn)
    out = []
    for r in rows:
        cid = r.get("class_id")
        if cid is None:
            continue
        cname = (r.get("class_name") or "").strip()
        canon = _class_canonical_slug(cname)
        cid_int = int(cid)
        class_path = f"/class/{cid_int}-{canon}" if canon else f"/class/{cid_int}"
        out.append({"class_id": cid_int, "class_name": cname, "class_path": class_path})
    if qn and len(out) > 1:
        ql = qn.lower()

        def _cls_key(item: dict):
            nm = (item.get("class_name") or "").strip().lower()
            if nm == ql:
                t = 0
            elif nm.startswith(ql):
                t = 1
            elif ql in nm:
                t = 2
            else:
                t = 3
            return (t, nm)

        out.sort(key=_cls_key)
    return {"classes": out}


