@app.get("/api/super-admin/regatta/{regatta_id}/wc-fleets")
async def api_super_admin_regatta_wc_fleets(request: Request, regatta_id: str):
    """WC pilot: list regatta_blocks for this regatta (fleet picker)."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise HTTPException(status_code=403, detail="not editable for this regatta yet")
    if not table_exists("regatta_blocks"):
        raise HTTPException(status_code=500, detail="regatta_blocks missing")
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        cur.execute(
            """
            SELECT rb.block_id,
                   TRIM(COALESCE(rb.fleet_label, '')) AS fleet_label,
                   TRIM(COALESCE(rb.class_canonical, '')) AS class_canonical,
                   TRIM(COALESCE(rb.class_original, '')) AS class_original,
                   rb.class_id,
                   TRIM(COALESCE(c.class_name, '')) AS linked_class_name
            FROM public.regatta_blocks rb
            LEFT JOIN public.classes c ON c.class_id = rb.class_id
            WHERE rb.regatta_id = %s
            ORDER BY rb.block_id
            """,
            (rid,),
        )
        rows = cur.fetchall() or []
    finally:
        cur.close()
        return_db_connection(conn)
    fleets = []
    for r in rows:
        fleets.append(
            {
                "block_id": (r.get("block_id") or "").strip(),
                "fleet_label": (r.get("fleet_label") or "").strip(),
                "class_canonical": (r.get("class_canonical") or "").strip(),
                "class_original": (r.get("class_original") or "").strip(),
                "class_id": int(r["class_id"]) if r.get("class_id") is not None else None,
                "linked_class_name": (r.get("linked_class_name") or "").strip(),
            }
        )
    return {"ok": True, "fleets": fleets}


@app.patch("/api/super-admin/regatta/{regatta_id}/wc-fleet-block")
async def api_super_admin_regatta_wc_fleet_block_patch(request: Request, regatta_id: str, body: dict = Body(...)):
    """WC pilot: set linked class on a regatta block (and sync labels); or set custom fleet labels if class not listed."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise HTTPException(status_code=403, detail="not editable for this regatta yet")
    if not isinstance(body, dict):
        raise HTTPException(status_code=400, detail="JSON object expected")
    block_id = (body.get("block_id") or "").strip()
    if not block_id:
        raise HTTPException(status_code=400, detail="block_id required")
    if not table_exists("regatta_blocks") or not table_exists("results"):
        raise HTTPException(status_code=500, detail="database schema error")
    class_id = body.get("class_id")
    custom_fl = (body.get("fleet_label") or "").strip() if body.get("fleet_label") is not None else None
    custom_cc = (body.get("class_canonical") or "").strip() if body.get("class_canonical") is not None else None
    custom_orig = (body.get("class_original") or "").strip() if body.get("class_original") is not None else None
    use_custom = body.get("custom_labels") is True

    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        cur.execute(
            "SELECT block_id FROM public.regatta_blocks WHERE regatta_id = %s AND block_id = %s LIMIT 1",
            (rid, block_id),
        )
        if not cur.fetchone():
            raise HTTPException(status_code=404, detail="block not found for this regatta")

        if use_custom:
            if not custom_fl or not custom_cc:
                raise HTTPException(status_code=400, detail="fleet_label and class_canonical required when custom_labels is true")
            fl = custom_fl[:240]
            cc = custom_cc[:240]
            co = (custom_orig or cc)[:240]
            cur.execute(
                """
                UPDATE public.regatta_blocks
                SET fleet_label = %s, class_canonical = %s, class_original = %s, class_id = NULL
                WHERE regatta_id = %s AND block_id = %s
                """,
                (fl, cc, co, rid, block_id),
            )
            cur.execute(
                """
                UPDATE public.results
                SET fleet_label = %s, class_original = %s, class_id = NULL
                WHERE regatta_id = %s AND block_id = %s
                """,
                (fl, co, rid, block_id),
            )
        else:
            if class_id is None or (isinstance(class_id, str) and not str(class_id).strip().isdigit()):
                raise HTTPException(status_code=400, detail="class_id required unless custom_labels with fleet_label and class_canonical")
            try:
                cid_int = int(class_id)
            except (TypeError, ValueError):
                raise HTTPException(status_code=400, detail="invalid class_id")
            cn = "class_name" if column_exists("classes", "class_name") else (
                "class_canonical" if column_exists("classes", "class_canonical") else None
            )
            if not cn:
                raise HTTPException(status_code=500, detail="classes.name column missing")
            cur.execute(
                f"SELECT class_id, TRIM(COALESCE({cn}::text, '')) AS class_name FROM public.classes WHERE class_id = %s LIMIT 1",
                (cid_int,),
            )
            crow = cur.fetchone()
            if not crow:
                raise HTTPException(status_code=404, detail="class not found")
            cname = (crow.get("class_name") or "").strip() or f"Class {cid_int}"
            cur.execute(
                """
                UPDATE public.regatta_blocks
                SET class_id = %s, class_canonical = %s, class_original = %s, fleet_label = %s
                WHERE regatta_id = %s AND block_id = %s
                """,
                (cid_int, cname, cname, cname, rid, block_id),
            )
            cur.execute(
                """
                UPDATE public.results
                SET class_id = %s, class_original = %s, fleet_label = %s
                WHERE regatta_id = %s AND block_id = %s
                """,
                (cid_int, cname, cname, rid, block_id),
            )
        conn.commit()
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        print(f"[api_super_admin_regatta_wc_fleet_block_patch] {e}", flush=True)
        raise HTTPException(status_code=500, detail="database error")
    finally:
        cur.close()
        return_db_connection(conn)
    return {"ok": True}


@app.post("/api/super-admin/clubs")
async def api_super_admin_clubs_create(request: Request, body: dict = Body(...)):
    """Super admin: insert clubs row (abbrev + fullname). WC host picker; rejects duplicates and reserved Unassigned."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    if not isinstance(body, dict):
        raise HTTPException(status_code=400, detail="JSON object expected")
    ab = (body.get("club_abbrev") or body.get("abbrev") or "").strip()
    fn = (body.get("club_fullname") or body.get("fullname") or "").strip()
    if not ab or not fn:
        raise HTTPException(status_code=400, detail="club_abbrev and club_fullname required")
    if len(ab) > 40 or len(fn) > 240:
        raise HTTPException(status_code=400, detail="club_abbrev or club_fullname too long")
    ab_l = ab.lower()
    fn_l = fn.lower()
    if ab_l == "unassigned" or fn_l == "unassigned":
        raise HTTPException(status_code=400, detail="reserved club name")
    if not table_exists("clubs"):
        raise HTTPException(status_code=500, detail="clubs table missing")
    conn = get_db_connection()
    cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
    try:
        cur.execute(
            """
            SELECT club_id FROM public.clubs
            WHERE lower(trim(COALESCE(club_abbrev, ''))) = %s
            LIMIT 1
            """,
            (ab_l,),
        )
        if cur.fetchone():
            raise HTTPException(status_code=409, detail="club code already exists")
        cur.execute(
            """
            SELECT club_id FROM public.clubs
            WHERE lower(trim(COALESCE(club_fullname, ''))) = %s
            LIMIT 1
            """,
            (fn_l,),
        )
        if cur.fetchone():
            raise HTTPException(status_code=409, detail="club full name already exists")
        cur.execute(
            """
            INSERT INTO public.clubs (club_abbrev, club_fullname)
            VALUES (%s, %s)
            RETURNING club_id
            """,
            (ab, fn),
        )
        row = cur.fetchone()
        conn.commit()
        cid = int(row["club_id"]) if row and row.get("club_id") is not None else None
        if not cid:
            raise HTTPException(status_code=500, detail="insert failed")
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        print(f"[api_super_admin_clubs_create] {e}", flush=True)
        raise HTTPException(status_code=500, detail="database error")
    finally:
        cur.close()
        return_db_connection(conn)
    slug_out = _club_slug_from_name(fn) or _club_slug_from_name(ab) or ""
    return {"ok": True, "club_id": cid, "code": ab, "name": fn, "slug": slug_out}


@app.patch("/api/super-admin/regatta/{regatta_id}/host-club")
async def api_super_admin_regatta_host_club_patch(request: Request, regatta_id: str, body: dict = Body(...)):
    """Super admin only. Pilot: set regattas.host_club_id for WC Dinghy Champs slug only."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise HTTPException(status_code=403, detail="not editable for this regatta yet")
    if not isinstance(body, dict):
        raise HTTPException(status_code=400, detail="JSON object expected")
    hid = body.get("host_club_id")
    if hid is None or (isinstance(hid, str) and not str(hid).strip().isdigit()):
        raise HTTPException(status_code=400, detail="host_club_id required")
    try:
        hid_int = int(hid)
    except (TypeError, ValueError):
        raise HTTPException(status_code=400, detail="host_club_id must be an integer")
    if hid_int < 1:
        raise HTTPException(status_code=400, detail="invalid host_club_id")
    if not table_exists("regattas") or not table_exists("clubs"):
        raise HTTPException(status_code=500, detail="database schema error")
    conn = get_db_connection()
    cur = conn.cursor()
    try:
        cur.execute("SELECT club_id FROM clubs WHERE club_id = %s LIMIT 1", (hid_int,))
        if not cur.fetchone():
            raise HTTPException(status_code=404, detail="club not found")
        cur.execute("UPDATE regattas SET host_club_id = %s WHERE regatta_id = %s", (hid_int, rid))
        n = cur.rowcount
        if n == 0:
            conn.rollback()
            raise HTTPException(status_code=404, detail="regatta not found")
        conn.commit()
    except HTTPException:
        conn.rollback()
        raise
    except Exception as e:
        conn.rollback()
        print(f"[api_super_admin_regatta_host_club_patch] {e}", flush=True)
        raise HTTPException(status_code=500, detail="database error")
    finally:
        cur.close()
        return_db_connection(conn)
    return {"ok": True, "host_club_id": hid_int}


@app.post("/api/super-admin/regatta/{regatta_id}/header-icon-upload")
async def api_super_admin_regatta_header_icon_upload(
    request: Request,
    regatta_id: str,
    slot: str = Query(..., description='left or right'),
    file: UploadFile = File(...),
):
    """WC pilot: upload left/right header image (same validation as hub hero image upload)."""
    if not _session_role_is_super_admin(request):
        raise HTTPException(status_code=403, detail="super_admin only")
    rid = str(regatta_id).strip()
    if rid != WC_DINGHY_CHAMPS_REGATTA_SLUG:
        raise HTTPException(status_code=403, detail="not editable for this regatta yet")
    sl = (slot or "").strip().lower()
    if sl not in ("left", "right"):
        raise HTTPException(status_code=400, detail='slot must be "left" or "right"')
    ext = _hub_upload_extension(file.content_type, file.filename)
    if not ext:
        raise HTTPException(
            status_code=400,
            detail="Use a photo file (JPEG, PNG, WebP, GIF, HEIC).",
        )
    dest_dir = Path(_static_dir()) / "assets" / "hub"
    dest_dir.mkdir(parents=True, exist_ok=True)
    name = f"wc-hdr-{sl}-{uuid.uuid4().hex[:14]}{ext}"
    dest = dest_dir / name
    size = 0
    try:
        with open(dest, "wb") as out:
            while True:
                chunk = await file.read(65536)
                if not chunk:
                    break
                size += len(chunk)
                if size > _HUB_UPLOAD_MAX:
                    out.close()
                    dest.unlink(missing_ok=True)
                    raise HTTPException(status_code=400, detail="file too large (max 4MB)")
                out.write(chunk)
    except HTTPException:
        raise
    except Exception as e:
        dest.unlink(missing_ok=True)
        raise HTTPException(status_code=500, detail=str(e))
    url_path = f"/assets/hub/{name}"
    _wc_regatta_header_icon_set(rid, sl, url_path)
    return {"ok": True, "url": url_path, "slot": sl}


