# ---------- SEO: clean /sailor/<slug> URLs; 301 from ?sas_id=; serve SPA for /sailor/:slug and /regatta/:slug ----------
# Absolute path so FileResponse works in worker context regardless of cwd.
_INDEX_HTML_PATH = str(Path(STATIC_DIR).resolve() / "index.html")
print(f"[STATIC DEBUG] STATIC_DIR = {STATIC_DIR}")
print(f"[STATIC DEBUG] INDEX_PATH = {_INDEX_HTML_PATH}")


def _normalise_class_slug_for_lookup(slug: str) -> str:
    """Normalise URL slug for class_name lookup: lowercase, hyphen to space."""
    if not slug or not isinstance(slug, str):
        return ""
    return slug.strip().lower().replace("-", " ")


def _class_canonical_slug(class_name: str) -> str:
    """Build canonical URL slug from class_name: lowercase, spaces to hyphens, alphanumeric + hyphen only."""
    if not class_name or not isinstance(class_name, str):
        return ""
    s = class_name.strip().lower().replace(" ", "-")
    s = re.sub(r"[^a-z0-9-]", "", s)
    return s.strip("-") or ""


def _get_class_by_name_slug(slug: str):
    """Lookup class by name-only slug (no leading id). Returns (class_id, class_name) or (None, None)."""
    norm = _normalise_class_slug_for_lookup(slug)
    if not norm:
        return (None, None)
    conn = None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        cur.execute(
            "SELECT class_id, class_name FROM classes WHERE LOWER(TRIM(class_name)) = %s LIMIT 1",
            (norm,),
        )
        row = cur.fetchone()
        if row:
            return (row["class_id"], row["class_name"])
    except Exception:
        pass
    finally:
        if conn:
            return_db_connection(conn)
    return (None, None)


def _get_class_name_by_id(class_id) -> Optional[str]:
    """Return class_name for class_id from classes table, or None."""
    if class_id is None:
        return None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("SELECT class_name FROM classes WHERE class_id = %s LIMIT 1", (int(class_id),))
            row = cur.fetchone()
            return (row.get("class_name") or "").strip() or None if row else None
        finally:
            cur.close()
            return_db_connection(conn)
    except Exception:
        return None


def root_maybe_redirect_sas_id(
    request: Request,
    sas_id: Optional[str] = None,
    sas_id_alt: Optional[str] = None,
):
    """If ?sas_id= present, 301 to /sailor/<slug>. Else serve index.html."""
    sas_id = sas_id or sas_id_alt or request.query_params.get("sas_id") or request.query_params.get("sas-id")
    if sas_id and str(sas_id).strip():
        full_name, canonical_slug = _get_sailor_by_sas_id_for_redirect(str(sas_id).strip())
        if canonical_slug:
            return RedirectResponse(url=f"/sailor/{canonical_slug}", status_code=301)
        return RedirectResponse(url="/", status_code=302)
    if os.path.isfile(_INDEX_HTML_PATH):
        return FileResponse(_INDEX_HTML_PATH, media_type="text/html")
    raise HTTPException(status_code=404, detail="index.html not found")


def index_html_maybe_redirect_sas_id(
    request: Request,
    sas_id: Optional[str] = None,
    sas_id_alt: Optional[str] = None,
):
    """If ?sas_id= present, 301 to /sailor/<slug>. Else serve index.html."""
    sas_id = sas_id or sas_id_alt or request.query_params.get("sas_id") or request.query_params.get("sas-id")
    if sas_id and str(sas_id).strip():
        full_name, canonical_slug = _get_sailor_by_sas_id_for_redirect(str(sas_id).strip())
        if canonical_slug:
            return RedirectResponse(url=f"/sailor/{canonical_slug}", status_code=301)
        return RedirectResponse(url="/", status_code=302)
    if os.path.isfile(_INDEX_HTML_PATH):
        return FileResponse(_INDEX_HTML_PATH, media_type="text/html")
    raise HTTPException(status_code=404, detail="index.html not found")


def _get_sailor_regattas_for_seo(sas_id: str, limit: int = 30):
    """Return list of (event_name, regatta_id) for sailor's regattas. Real anchors for crawlers (canonical /regatta/{id})."""
    if not sas_id:
        return []
    out = []
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT DISTINCT r.event_name, r.regatta_id
                FROM results res
                JOIN regattas r ON r.regatta_id = res.regatta_id
                WHERE (res.helm_sa_sailing_id::text = %s OR res.crew_sa_sailing_id::text = %s)
                  AND r.event_name IS NOT NULL AND TRIM(r.event_name) != ''
                ORDER BY r.end_date DESC NULLS LAST, r.start_date DESC NULLS LAST
                LIMIT %s
            """, (str(sas_id), str(sas_id), limit))
            for row in cur.fetchall() or []:
                ev_name = (row.get("event_name") or "").strip()
                rid = str(row.get("regatta_id") or "").strip()
                if ev_name and rid:
                    out.append((ev_name, rid))
        finally:
            cur.close()
            conn.close()
    except Exception:
        pass
    return out


def _get_sailor_club_for_seo(sas_id: str) -> str:
    """Return most common club name for sailor from results, or empty string."""
    if not sas_id:
        return ""
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT COALESCE(c.club_abbrev, c.club_fullname, r.club_raw) AS club_name
                FROM results r
                LEFT JOIN clubs c ON c.club_id = r.club_id
                WHERE r.helm_sa_sailing_id::text = %s AND (c.club_fullname IS NOT NULL OR c.club_abbrev IS NOT NULL OR r.club_raw IS NOT NULL)
                GROUP BY COALESCE(c.club_abbrev, c.club_fullname, r.club_raw)
                ORDER BY COUNT(*) DESC
                LIMIT 1
            """, (str(sas_id),))
            row = cur.fetchone()
            return (row.get("club_name") or "").strip() if row else ""
        finally:
            cur.close()
            conn.close()
    except Exception:
        return ""


def _get_sailor_club_slug_for_seo(sas_id: str) -> str:
    """Return canonical club slug for /club/{slug} from most common club_id in results (helm or crew), or empty."""
    if not sas_id:
        return ""
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT COALESCE(c.club_abbrev, c.club_fullname) AS club_name
                FROM results r
                LEFT JOIN clubs c ON c.club_id = r.club_id
                WHERE (r.helm_sa_sailing_id::text = %s OR r.crew_sa_sailing_id::text = %s)
                  AND r.club_id IS NOT NULL
                  AND (c.club_abbrev IS NOT NULL OR c.club_fullname IS NOT NULL)
                GROUP BY COALESCE(c.club_abbrev, c.club_fullname)
                ORDER BY COUNT(*) DESC
                LIMIT 1
            """, (str(sas_id), str(sas_id)))
            row = cur.fetchone()
            if not row:
                return ""
            name = (row.get("club_name") or "").strip()
            return _club_slug_from_name(name) if name else ""
        finally:
            cur.close()
            conn.close()
    except Exception:
        return ""


def _get_regatta_sailors_for_seo(regatta_id: str, limit: int = 150):
    """Return list of (display_name, sailor_slug) for distinct sailors in regatta results (helm + crew)."""
    if not regatta_id or not table_exists("results"):
        return []
    out = []
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT DISTINCT s.sa_sailing_id::text AS sas_id,
                       COALESCE(TRIM(s.full_name), TRIM(s.first_name || ' ' || COALESCE(s.last_name, ''))) AS full_name
                FROM results r
                JOIN sas_id_personal s ON (
                    r.helm_sa_sailing_id::text = s.sa_sailing_id::text
                    OR r.crew_sa_sailing_id::text = s.sa_sailing_id::text
                )
                WHERE r.regatta_id = %s
                  AND (s.full_name IS NOT NULL OR s.first_name IS NOT NULL OR s.last_name IS NOT NULL)
                ORDER BY full_name
                LIMIT %s
            """, (str(regatta_id), limit))
            rows = cur.fetchall() or []
            sas_ids = [str(r.get("sas_id") or "") for r in rows if r.get("sas_id")]
            slug_map = _batch_sailor_slugs_for_sas_ids(sas_ids) if sas_ids else {}
            for r in rows:
                nm = (r.get("full_name") or "").strip()
                sid = str(r.get("sas_id") or "")
                sl = slug_map.get(sid) if slug_map else None
                if nm and sl:
                    out.append((nm, sl))
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[seo] _get_regatta_sailors_for_seo: {e}")
    return out


def _regatta_seo_sailors_nav_html(regatta_id: str) -> str:
    """Visually hidden sailor links for regatta standalone pages (crawlers)."""
    rows = _get_regatta_sailors_for_seo(regatta_id, 150)
    if not rows:
        return ""
    items = "".join(
        f'<li><a href="/sailor/{html_module.escape(sl)}">{html_module.escape(nm)}</a></li>' for nm, sl in rows
    )
    return (
        '<div class="seo-regatta-sailors" aria-hidden="true" style="position:absolute;width:1px;height:1px;padding:0;'
        'margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0">'
        f'<nav aria-label="Sailors"><h2 style="font-size:1rem;margin:0;">Sailors</h2><ul style="list-style:none;padding:0;">{items}</ul></nav></div>'
    )


_SEO_DISCOVERY_CACHE = {"at": 0.0, "pairs": []}
_SEO_DISCOVERY_TTL_SEC = 120.0


def _dedupe_html_canonical_links(html: str) -> str:
    """Keep first <link rel=\"canonical\">; remove duplicates (SPA + server injections)."""
    pattern = re.compile(r"<link\s[^>]*\brel\s*=\s*[\"']canonical[\"'][^>]*>", re.I)
    parts = []
    pos = 0
    first = True
    for m in pattern.finditer(html):
        parts.append(html[pos : m.start()])
        if first:
            parts.append(m.group(0))
            first = False
        pos = m.end()
    parts.append(html[pos:])
    return "".join(parts)


def _seo_discovery_pairs_fetch():
    """Build mixed (href, label) for crawl discovery; relative paths only."""
    pairs = []
    conn = None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            if table_exists("regattas"):
                cur.execute("""
                    SELECT regatta_id, event_name FROM regattas
                    WHERE event_name IS NOT NULL AND TRIM(event_name) != ''
                    ORDER BY COALESCE(end_date, start_date) DESC NULLS LAST
                    LIMIT 5
                """)
                for r in cur.fetchall() or []:
                    rid = str(r.get("regatta_id") or "").strip()
                    if not rid:
                        continue
                    lab = (r.get("event_name") or "").strip() or rid
                    pairs.append((f"/regatta/{rid}", lab[:100]))
            if table_exists("results") and table_exists("sas_id_personal"):
                cur.execute("""
                    SELECT DISTINCT s.sa_sailing_id::text AS sas_id,
                           COALESCE(TRIM(s.full_name), TRIM(s.first_name || ' ' || COALESCE(s.last_name, ''))) AS full_name
                    FROM results r2
                    JOIN sas_id_personal s ON s.sa_sailing_id::text = r2.helm_sa_sailing_id::text
                    WHERE (s.full_name IS NOT NULL AND TRIM(s.full_name) != ''
                           OR s.first_name IS NOT NULL OR s.last_name IS NOT NULL)
                    ORDER BY s.sa_sailing_id::text
                    LIMIT 8
                """)
                srows = cur.fetchall() or []
                sids = [str(x.get("sas_id") or "") for x in srows if x.get("sas_id")]
                smap = _batch_sailor_slugs_for_sas_ids(sids) if sids else {}
                for r in srows:
                    sid = str(r.get("sas_id") or "")
                    nm = (r.get("full_name") or "").strip()
                    sl = smap.get(sid) if smap else None
                    if sid and nm and sl:
                        pairs.append((f"/sailor/{sl}", nm[:100]))
            if table_exists("clubs"):
                cur.execute("""
                    SELECT club_abbrev, club_fullname FROM clubs
                    WHERE (club_fullname IS NOT NULL AND TRIM(club_fullname) != ''
                           OR club_abbrev IS NOT NULL AND TRIM(club_abbrev) != '')
                      AND lower(trim(COALESCE(club_abbrev, ''))) != 'unassigned'
                    ORDER BY club_id
                    LIMIT 5
                """)
                for r in cur.fetchall() or []:
                    ab = (r.get("club_abbrev") or "").strip()
                    fn = (r.get("club_fullname") or "").strip()
                    disp = (ab + " – " + fn).strip(" –") if (ab and fn) else (ab or fn)
                    slug = _club_slug_from_name(ab) if ab else _club_slug_from_name(fn)
                    if slug and disp:
                        pairs.append((f"/club/{slug}", disp[:100]))
            if table_exists("classes"):
                cur.execute(
                    "SELECT class_id, class_name FROM classes WHERE class_id IS NOT NULL ORDER BY class_id LIMIT 5"
                )
                for r in cur.fetchall() or []:
                    cid = r.get("class_id")
                    name = (r.get("class_name") or "").strip()
                    if cid is None or not name:
                        continue
                    cslug = _class_canonical_slug(name)
                    path = f"/class/{cid}-{cslug}" if cslug else f"/class/{cid}"
                    pairs.append((path, name[:100]))
        finally:
            cur.close()
            return_db_connection(conn)
            conn = None
    except Exception as e:
        print(f"[seo] _seo_discovery_pairs_fetch: {e}")
        if conn:
            try:
                return_db_connection(conn)
            except Exception:
                pass
    return pairs


def _seo_discovery_pairs(min_count: int = 12, max_count: int = 20):
    """Cached discovery pairs; pad with safe directory links so every page has ≥min_count anchors."""
    import time

    t = time.time()
    raw = []
    if _SEO_DISCOVERY_CACHE["pairs"] and (t - _SEO_DISCOVERY_CACHE["at"]) < _SEO_DISCOVERY_TTL_SEC:
        raw = list(_SEO_DISCOVERY_CACHE["pairs"])
    else:
        raw = _seo_discovery_pairs_fetch()
        _SEO_DISCOVERY_CACHE["at"] = t
        _SEO_DISCOVERY_CACHE["pairs"] = list(raw)
    fillers = [
        ("/events", "Events"),
        ("/sailors", "Sailors"),
        ("/regattas", "Regattas"),
        ("/clubs", "Clubs"),
        ("/classes", "Classes"),
        ("/stats", "Statistics"),
        ("/about", "About"),
        ("/", "Home"),
    ]
    out = raw[:max_count]
    i = 0
    while len(out) < min_count and i < 80:
        out.append(fillers[i % len(fillers)])
        i += 1
    return out[:max_count]


def _seo_discovery_block_html(min_links: int = 12, max_links: int = 20) -> str:
    """Hidden block: 10–20 crawlable links (mixed entity types). Repeats safe links if DB sample is small."""
    pairs = _seo_discovery_pairs(min_links, max_links)
    inner = "".join(
        f'<a href="{html_module.escape(h)}">{html_module.escape(lab)}</a> ' for h, lab in pairs
    )
    css = (
        '<style id="seo-discovery-css">.seo-discovery-block{position:absolute;width:1px;height:1px;'
        "padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}</style>"
    )
    return f'{css}<nav class="seo-discovery-block" aria-hidden="true">{inner}</nav>'


def _get_sailor_bio_data(sas_id: str, full_name: str, club_name: str) -> dict:
    """Build bio_data dict for build_sailor_bio. Uses only real DB data; if something is missing we omit (None/[])."""
    if not sas_id:
        return {
            "name": full_name or "",
            "club": club_name or None,
            "province": None,
            "regattas": None,
            "races": None,
            "primary_class": None,
            "other_classes": [],
            "first_year": None,
            "highlight": None,
        }
    out = {
        "name": full_name or "",
        "club": club_name or None,
        "province": None,
        "regattas": None,
        "races": None,
        "primary_class": None,
        "other_classes": [],
        "first_year": None,
        "highlight": None,
    }
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            sid = str(sas_id)

            def _ordinal(n: int) -> str:
                if n % 100 in (11, 12, 13):
                    return f"{n}th"
                return f"{n}{ {1: 'st', 2: 'nd', 3: 'rd'}.get(n % 10, 'th') }"

            # Regattas count, races count, first year
            cur.execute("""
                SELECT
                    COUNT(DISTINCT res.regatta_id)::int AS regattas,
                    COUNT(*) FILTER (WHERE res.raced = TRUE)::int AS races,
                    MIN(EXTRACT(YEAR FROM COALESCE(r.end_date, r.start_date)))::int AS first_year
                FROM results res
                LEFT JOIN regattas r ON r.regatta_id = res.regatta_id
                WHERE res.helm_sa_sailing_id::text = %s OR res.crew_sa_sailing_id::text = %s
            """, (sid, sid))
            row = cur.fetchone()
            if row:
                out["regattas"] = row.get("regattas")
                out["races"] = row.get("races")
                fy = row.get("first_year")
                out["first_year"] = int(fy) if fy is not None else None
            # Primary class (most results) and other class names
            cur.execute("""
                SELECT c.class_name, COUNT(*) AS cnt
                FROM results res
                JOIN classes c ON c.class_id = res.class_id AND c.class_name IS NOT NULL AND TRIM(c.class_name) != '' AND c.class_name <> 'Unknown'
                WHERE (res.helm_sa_sailing_id::text = %s OR res.crew_sa_sailing_id::text = %s) AND res.raced = TRUE
                GROUP BY c.class_name
                ORDER BY COUNT(*) DESC
            """, (sid, sid))
            class_rows = cur.fetchall() or []
            if class_rows:
                out["primary_class"] = (class_rows[0].get("class_name") or "").strip()
                out["other_classes"] = [(r.get("class_name") or "").strip() for r in class_rows[1:11] if (r.get("class_name") or "").strip()]

            # Club (if not already known) + province (only when exists in DB)
            cur.execute("""
                SELECT COALESCE(c.club_abbrev, c.club_fullname, r.club_raw) AS club_name,
                       r.club_id
                FROM results r
                LEFT JOIN clubs c ON c.club_id = r.club_id
                WHERE r.helm_sa_sailing_id::text = %s OR r.crew_sa_sailing_id::text = %s
                GROUP BY COALESCE(c.club_abbrev, c.club_fullname, r.club_raw), r.club_id
                ORDER BY COUNT(*) DESC
                LIMIT 1
            """, (sid, sid))
            crow = cur.fetchone() or {}
            if not out.get("club"):
                out["club"] = (crow.get("club_name") or "").strip() or None
            club_id = crow.get("club_id")
            if club_id:
                try:
                    cur.execute("""
                        SELECT column_name
                        FROM information_schema.columns
                        WHERE table_schema='public' AND table_name='clubs'
                          AND column_name IN ('province', 'region')
                        ORDER BY CASE WHEN column_name='province' THEN 0 ELSE 1 END
                        LIMIT 1
                    """)
                    prow = cur.fetchone()
                    col = (prow.get("column_name") or "") if prow else ""
                    if col:
                        cur.execute(f"SELECT {col} FROM clubs WHERE club_id = %s LIMIT 1", (club_id,))
                        vrow = cur.fetchone()
                        out["province"] = (vrow.get(col) or "").strip() or None if vrow else None
                except Exception:
                    pass

            # Best result (best position): include event name, class, year, and position
            try:
                cur.execute("""
                    SELECT
                        res.rank::int AS position,
                        reg.event_name,
                        cls.class_name,
                        EXTRACT(YEAR FROM COALESCE(reg.end_date, reg.start_date))::int AS year
                    FROM results res
                    JOIN regattas reg ON reg.regatta_id = res.regatta_id
                    LEFT JOIN classes cls ON cls.class_id = res.class_id
                    WHERE (res.helm_sa_sailing_id::text = %s OR res.crew_sa_sailing_id::text = %s)
                      AND res.raced = TRUE
                      AND res.rank IS NOT NULL AND res.rank > 0
                      AND reg.event_name IS NOT NULL AND TRIM(reg.event_name) != ''
                      AND cls.class_name IS NOT NULL AND TRIM(cls.class_name) != '' AND cls.class_name <> 'Unknown'
                    ORDER BY res.rank ASC, year DESC NULLS LAST, COALESCE(reg.end_date, reg.start_date) DESC NULLS LAST
                    LIMIT 1
                """, (sid, sid))
                best = cur.fetchone() or {}
                if best.get("position") and best.get("event_name") and best.get("class_name") and best.get("year"):
                    out["highlight"] = f"{_ordinal(int(best['position']))} place at {best['event_name']} ({int(best['year'])}) in the {best['class_name']} fleet"
            except Exception:
                pass
        finally:
            cur.close()
            conn.close()
    except Exception:
        pass
    return out


def _get_sailor_sas_id_from_slug(slug: str) -> str:
    """Return sas_id for sailor slug or empty string. Used for SEO extras. Falls back to results when not in sas_id_personal."""
    if not slug or not slug.strip():
        return ""
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            m = re.match(r"^(.+)-(\d+)$", slug.strip())
            if m:
                sid = m.group(2)
                cur.execute("SELECT sa_sailing_id::text FROM sas_id_personal WHERE sa_sailing_id::text = %s LIMIT 1", (sid,))
                row = cur.fetchone()
                if row:
                    return (row.get("sa_sailing_id") or "") if row else ""
                # Fallback: sailor in results but not sas_id_personal
                cur.execute("SELECT 1 FROM results WHERE helm_sa_sailing_id::text = %s OR crew_sa_sailing_id::text = %s LIMIT 1", (sid, sid))
                return sid if cur.fetchone() else ""
            name_from_slug = re.sub(r"\s+", " ", slug.replace("-", " ").strip()).lower()
            cur.execute("""
                SELECT sa_sailing_id::text FROM sas_id_personal
                WHERE REGEXP_REPLACE(LOWER(TRIM(REPLACE(COALESCE(full_name, first_name || ' ' || COALESCE(last_name, '')), '-', ' '))), '\\s+', ' ', 'g') = %s
                LIMIT 1
            """, (name_from_slug,))
            row = cur.fetchone()
            if row:
                return (row.get("sa_sailing_id") or "")
            # Fallback: name-only slug from results
            _, sid = _get_sailor_by_name_slug_from_results(slug)
            return sid or ""
        finally:
            cur.close()
            conn.close()
    except Exception:
        return ""


def serve_sailor_spa(slug: str):
    """Serve SPA with server-side SEO: inject title, meta, canonical, h1, JSON-LD for crawlers; SPA loads normally. 404 if unknown slug."""
    if not os.path.isfile(_INDEX_HTML_PATH):
        raise HTTPException(status_code=404, detail="index.html not found")
    name, canonical_slug = _get_sailor_name_by_slug(slug)
    base_url = _canonical_base_url()
    if not name or not canonical_slug:
        raise HTTPException(status_code=404, detail="Sailor not found")
    # 301 to canonical URL when slug differs (e.g. tom-henshilwood -> tom-henshilwood-16401) for SEO
    if canonical_slug and slug.strip().lower() != canonical_slug.lower():
        return RedirectResponse(url=f"/sailor/{canonical_slug}", status_code=301)
    try:
        with open(_INDEX_HTML_PATH, "r", encoding="utf-8", errors="replace") as f:
            html = f.read()
        escaped_name = html_module.escape(name)
        seo_title = f"{escaped_name} | SailingSA"
        seo_desc = f"Official SailingSA profile for {escaped_name}. Results, rankings and regattas."
        canonical_url = f"{base_url}/sailor/{canonical_slug}"
        # Replace title (first occurrence)
        html = re.sub(r"<title>[^<]*</title>", f"<title>{seo_title}</title>", html, count=1)
        # Replace first meta name="description" (allow /> or >)
        html = re.sub(
            r'<meta\s+name="description"\s+content="[^"]*"\s*/?>',
            f'<meta name="description" content="{html_module.escape(seo_desc)}">',
            html,
            count=1,
        )
        # Replace canonical link (allow /> or >)
        html = re.sub(
            r'<link\s+rel="canonical"\s+href="[^"]*"\s*/?>',
            f'<link rel="canonical" href="{html_module.escape(canonical_url)}">',
            html,
            count=1,
        )
        # Regatta links (real anchors for crawlers - no popup/JS only)
        sas_id = _get_sailor_sas_id_from_slug(canonical_slug)
        regattas = _get_sailor_regattas_for_seo(sas_id, 30) if sas_id else []
        regatta_links = "".join(
            f'<li><a href="/regatta/{html_module.escape(rid)}">{html_module.escape(ev_name)}</a></li>'
            for ev_name, rid in regattas
        )
        regattas_block = f'<nav class="seo-regattas" aria-label="Regattas"><h2 style="font-size:1rem;margin:0.5rem 0;">Regattas</h2><ul style="list-style:none;padding:0;">{regatta_links or "<li>No regattas</li>"}</ul></nav>'
        club_slug_seo = _get_sailor_club_slug_for_seo(sas_id) if sas_id else ""
        club_name_seo = _get_sailor_club_for_seo(sas_id) if sas_id else ""
        club_block = ""
        if club_slug_seo and club_name_seo:
            club_block = f'<nav class="seo-club" aria-label="Club"><a href="/club/{html_module.escape(club_slug_seo)}">{html_module.escape(club_name_seo)}</a></nav>'

        # Inject h1 + regattas for crawlers only - visually hidden so SPA main header displays first
        seo_hidden_css = '<style id="seo-sailor-hidden">.seo-sailor-block{position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0}</style>'
        inject_html = f'<div class="seo-sailor-block" aria-hidden="true"><h1 class="seo-sailor-name">{escaped_name}</h1>{club_block}{regattas_block}</div>'
        html = re.sub(r"(<body[^>]*>)", f'\\1\n  {inject_html}', html, count=1)
        html = re.sub(r"</head>", f'{seo_hidden_css}\n</head>', html, count=1)

        # Inject JSON-LD Person schema before </head>
        club_name = _get_sailor_club_for_seo(sas_id) if sas_id else ""
        json_ld = {"@context": "https://schema.org", "@type": "Person", "name": name, "sport": "Sailing"}
        if club_name:
            json_ld["affiliation"] = {"@type": "SportsOrganization", "name": club_name}
        html = re.sub(r"</head>", f'<script type="application/ld+json">{json.dumps(json_ld)}</script>\n</head>', html, count=1)

        # Sailor bio: above stats section (after sailor-profile-header, before sailor-profile-tabs)
        if build_sailor_bio_from_db and sas_id:
            try:
                bio_text = build_sailor_bio_from_db(sas_id)
                bio_escaped = html_module.escape(bio_text)
                bio_block = f'<div class="sailor-bio"><p>{bio_escaped}</p></div>'
                # Insert after </section> that closes sailor-profile-header, before <div class="sailor-profile-tabs">
                html = re.sub(
                    r"(</section>\s*)(<div class=\"sailor-profile-tabs\"[^>]*>)",
                    r"\1" + bio_block + r"\n                        \2",
                    html,
                    count=1,
                )
            except Exception:
                pass  # omit bio on error; page still works

        html = _dedupe_html_canonical_links(html)
        _bod = html.rfind("</body>")
        if _bod != -1:
            html = html[:_bod] + _seo_discovery_block_html() + "\n" + html[_bod:]
        return HTMLResponse(html)
    except HTTPException:
        raise
    except Exception as e:
        print(f"[serve_sailor_spa] {e}", flush=True)
        if os.path.isfile(_INDEX_HTML_PATH):
            return FileResponse(_INDEX_HTML_PATH, media_type="text/html")
        return HTMLResponse(content=_HTML_SOFT_FAIL_200, status_code=200, media_type="text/html")


def serve_class_spa(class_slug: str):
    """Serve class route with server-side canonical/title tags for crawlers."""
    if not os.path.isfile(_INDEX_HTML_PATH):
        raise HTTPException(status_code=404, detail="index.html not found")
    class_id, class_name = _resolve_class_slug_to_class_id(class_slug)
    if not class_id or not class_name:
        raise HTTPException(status_code=404, detail="Class not found")
    canonical_slug = _class_canonical_slug(class_name or "")
    canonical_path = f"/class/{class_id}-{canonical_slug}" if canonical_slug else f"/class/{class_id}"
    req_slug = (class_slug or "").strip().lower()
    canon_slug = canonical_path.split("/class/", 1)[-1].lower()
    if req_slug != canon_slug:
        return RedirectResponse(url=canonical_path, status_code=301)
    base_url = _canonical_base_url()
    canonical_url = f"{base_url}{canonical_path}"
    try:
        with open(_INDEX_HTML_PATH, "r", encoding="utf-8", errors="replace") as f:
            html = f.read()
        escaped_name = html_module.escape(class_name)
        seo_title = f"{escaped_name} - Class | SailingSA"
        seo_desc = f"Official SailingSA class page for {escaped_name}. Regattas, sailors and race activity."
        html = re.sub(r"<title>[^<]*</title>", f"<title>{seo_title}</title>", html, count=1)
        html = re.sub(
            r'<meta\s+name="description"\s+content="[^"]*"\s*/?>',
            f'<meta name="description" content="{html_module.escape(seo_desc)}">',
            html,
            count=1,
        )
        html = re.sub(
            r'<link\s+rel="canonical"\s+href="[^"]*"\s*/?>',
            f'<link rel="canonical" href="{html_module.escape(canonical_url)}">',
            html,
            count=1,
        )
        html = _dedupe_html_canonical_links(html)
        return HTMLResponse(html)
    except HTTPException:
        raise
    except Exception as e:
        print(f"[serve_class_spa] {e}", flush=True)
        if os.path.isfile(_INDEX_HTML_PATH):
            return FileResponse(_INDEX_HTML_PATH, media_type="text/html")
        return HTMLResponse(content=_HTML_SOFT_FAIL_200, status_code=200, media_type="text/html")


def _club_slug_from_name(name: str) -> str:
    """Generate URL slug from club name. Same logic as regatta."""
    if not name or not isinstance(name, str):
        return ""
    s = re.sub(r"[^\w\s\-]", "", name).strip().lower()
    return re.sub(r"\s+", "-", s).strip("-")


