# Virtual club for SAS calendar events with no matched host (slug /club/unassigned)
_UNASSIGNED_CLUB_ABBREV = "Unassigned"
_UNASSIGNED_CLUB_FULLNAME = "Unassigned (SAS calendar)"


def _get_unassigned_club_id():
    """Return clubs.club_id for virtual Unassigned host; INSERT row if missing."""
    if not table_exists("clubs"):
        return None
    conn = None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        cur.execute(
            """
            SELECT club_id FROM clubs
            WHERE lower(trim(COALESCE(club_abbrev, ''))) = 'unassigned'
               OR lower(trim(COALESCE(club_fullname, ''))) = 'unassigned'
            LIMIT 1
            """
        )
        r = cur.fetchone()
        if r and r.get("club_id") is not None:
            cid = int(r["club_id"])
            cur.close()
            return_db_connection(conn)
            return cid
        try:
            cur.execute(
                """
                INSERT INTO clubs (club_abbrev, club_fullname)
                VALUES (%s, %s)
                RETURNING club_id
                """,
                (_UNASSIGNED_CLUB_ABBREV, _UNASSIGNED_CLUB_FULLNAME),
            )
            r = cur.fetchone()
            conn.commit()
            cid = int(r["club_id"]) if r and r.get("club_id") is not None else None
            cur.close()
            return_db_connection(conn)
            return cid
        except Exception as inserr:
            conn.rollback()
            cur.execute(
                """
                SELECT club_id FROM clubs
                WHERE lower(trim(COALESCE(club_abbrev, ''))) = 'unassigned'
                LIMIT 1
                """
            )
            r2 = cur.fetchone()
            cur.close()
            return_db_connection(conn)
            if r2 and r2.get("club_id") is not None:
                return int(r2["club_id"])
            print(f"[events] _get_unassigned_club_id insert failed: {inserr}")
            return None
    except Exception as e:
        print(f"[events] _get_unassigned_club_id: {e}")
        if conn:
            try:
                conn.rollback()
            except Exception:
                pass
            return_db_connection(conn)
    return None


def _unassigned_club_display_row(unassigned_id: int):
    """club_abbrev, club_fullname, club_slug for virtual unassigned host."""
    slug = _club_slug_from_name(_UNASSIGNED_CLUB_ABBREV)
    return {
        "host_club_id": unassigned_id,
        "club_abbrev": _UNASSIGNED_CLUB_ABBREV,
        "club_fullname": _UNASSIGNED_CLUB_FULLNAME,
        "club_slug": slug or "unassigned",
    }


def _apply_unassigned_host_fallback(upcoming_rows, past_rows):
    """After name resolution, set host_club_id to Unassigned for rows still without a club."""
    uid = _get_unassigned_club_id()
    if not uid:
        return
    urow = _unassigned_club_display_row(uid)
    for r in upcoming_rows + past_rows:
        if r.get("host_club_id"):
            continue
        r["host_club_id"] = urow["host_club_id"]
        r["club_abbrev"] = urow["club_abbrev"]
        r["club_fullname"] = urow["club_fullname"]
        r["club_slug"] = urow["club_slug"]


def _get_club_by_slug(slug: str):
    """Return (club_id, club_name, club_abbrev) for club slug or None. Resolves by club_abbrev, club_fullname (name slugs), then redirect to canonical club_code."""
    if not slug or not slug.strip():
        return None
    slug = slug.strip().lower()
    slug = CLUB_SLUG_ALIASES.get(slug, slug)
    try:
        if not table_exists("clubs"):
            return None
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            # Resolve: abbrev, or fullname with spaces replaced by hyphens (e.g. hermanus-yacht-club, Hermanus-Yacht-Club, hermanus)
            cur.execute("""
                SELECT club_id, club_abbrev, club_fullname
                FROM clubs
                WHERE lower(trim(COALESCE(club_abbrev, ''))) = %s
                   OR lower(replace(trim(COALESCE(club_fullname, '')), ' ', '-')) = %s
                LIMIT 1
            """, (slug, slug))
            r = cur.fetchone()
            if not r:
                return None
            club_name = (r.get("club_abbrev") or r.get("club_fullname") or "").strip()
            return (
                int(r.get("club_id") or 0),
                club_name,
                (r.get("club_abbrev") or "").strip(),
            )
        finally:
            cur.close()
            return_db_connection(conn)
    except Exception as e:
        print(f"[SEO] _get_club_by_slug: {e}")
    return None


def _slugify_event_name(name: str) -> str:
    """Safe slugify for event_name: strip, remove non-word (keep hyphen), lower, collapse spaces to single hyphen. No DB."""
    if not name:
        return ""
    s = (name or "").strip().lower()
    s = re.sub(r"[^\w\s\-]", "", s)
    s = re.sub(r"\s+", "-", s)
    s = re.sub(r"-{2,}", "-", s).strip("-")
    return s


def _get_regatta_by_regatta_id(param: str):
    """Return (regatta_id, event_name, start_date, end_date, host_club_name, host_club_id) when param equals regatta_id, else None."""
    if not param or not str(param).strip():
        return None
    param = str(param).strip()
    try:
        if not table_exists("regattas"):
            return None
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT r.regatta_id, r.event_name, r.start_date, r.end_date,
                       r.host_club_id,
                       COALESCE(c.club_abbrev, c.club_fullname, '') AS host_club_name
                FROM regattas r
                LEFT JOIN clubs c ON c.club_id = r.host_club_id
                WHERE LOWER(TRIM(r.regatta_id::text)) = LOWER(TRIM(%s))
            """, (param,))
            row = cur.fetchone()
        finally:
            cur.close()
            conn.close()
        if not row:
            return None
        return (
            str(row.get("regatta_id") or ""),
            (row.get("event_name") or "").strip(),
            row.get("start_date"),
            row.get("end_date"),
            (row.get("host_club_name") or "").strip(),
            row.get("host_club_id"),
        )
    except Exception as e:
        print(f"[SEO] _get_regatta_by_regatta_id: {e}")
    return None


def _get_regatta_by_event_name_slug(slug: str):
    """Return (regatta_id, event_name, ...) when slugified event_name matches slug; else None. Used for 301 fallback only."""
    if not slug or not slug.strip():
        return None
    slug_norm = slug.strip().lower()
    try:
        if not table_exists("regattas"):
            return None
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT r.regatta_id, r.event_name, r.start_date, r.end_date,
                       r.host_club_id,
                       COALESCE(c.club_abbrev, c.club_fullname, '') AS host_club_name
                FROM regattas r
                LEFT JOIN clubs c ON c.club_id = r.host_club_id
                WHERE r.event_name IS NOT NULL AND TRIM(r.event_name) != ''
            """)
            for r in cur.fetchall() or []:
                name = (r.get("event_name") or "").strip()
                rid = str(r.get("regatta_id") or "").strip()
                if rid and _slugify_event_name(rid) == slug_norm:
                    return (
                        rid,
                        name or rid,
                        r.get("start_date"),
                        r.get("end_date"),
                        (r.get("host_club_name") or "").strip(),
                        r.get("host_club_id"),
                    )
                if not name:
                    continue
                cand = _slugify_event_name(name)
                if cand == slug_norm:
                    return (
                        str(r.get("regatta_id") or ""),
                        name,
                        r.get("start_date"),
                        r.get("end_date"),
                        (r.get("host_club_name") or "").strip(),
                        r.get("host_club_id"),
                    )
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[SEO] _get_regatta_by_event_name_slug: {e}")
    return None


def _get_regatta_by_slug(slug: str):
    """Return (regatta_id, event_name, start_date, end_date, host_club_name, host_club_id) for regatta slug or None."""
    if not slug or not slug.strip():
        return None
    s = slug.strip()
    # Prefer direct regatta_id match (existing routing)
    reg = _get_regatta_by_regatta_id(s)
    if reg:
        return reg
    # Backward-compatible alias: numeric-prefix slugs can drift (e.g. 385-... -> 380-...).
    # If id-prefixed slug does not exist, match by suffix after the first dash.
    m = re.match(r"^\d+-(.+)$", s)
    if m:
        tail = (m.group(1) or "").strip()
        if tail:
            try:
                conn = get_db_connection()
                cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
                try:
                    cur.execute("""
                        SELECT r.regatta_id, r.event_name, r.start_date, r.end_date,
                               COALESCE(c.club_abbrev, c.club_fullname, '') AS host_club_name,
                               c.club_id AS host_club_id
                        FROM regattas r
                        LEFT JOIN clubs c ON c.club_id = r.host_club_id
                        WHERE r.regatta_id ILIKE %s
                        ORDER BY COALESCE(r.end_date, r.start_date) DESC NULLS LAST, r.regatta_id
                        LIMIT 1
                    """, ('%-' + tail,))
                    row = cur.fetchone()
                    if row:
                        return (
                            row.get("regatta_id"),
                            row.get("event_name"),
                            row.get("start_date"),
                            row.get("end_date"),
                            row.get("host_club_name"),
                            row.get("host_club_id"),
                        )
                finally:
                    cur.close()
                    conn.close()
            except Exception:
                pass
    # Else match by slugified event_name (used by sitemap / callers that want any match)
    return _get_regatta_by_event_name_slug(s)


def _format_rank(rank):
    """Format rank as 1st, 2nd, 3rd, 4th, ..."""
    if rank is None:
        return ""
    try:
        num = int(rank)
    except (TypeError, ValueError):
        return str(rank)
    if num % 100 in (11, 12, 13):
        return f"{num}th"
    if num % 10 == 1:
        return f"{num}st"
    if num % 10 == 2:
        return f"{num}nd"
    if num % 10 == 3:
        return f"{num}rd"
    return f"{num}th"


def _get_regatta_full_page_data(regatta_id: str):
    """Return (event_name, host_club_name, start_date, end_date, fleets, result_status, as_at_time, host_club_province, host_club_abbrev, host_club_fullname) for standalone regatta page.
    host_club_abbrev / host_club_fullname: from clubs join for 'CODE - Full name' header.
    fleets = [{name, races_sailed, discard_count, to_count, scoring_system, entries, rows}].
    Each row = {rank, sail_number, helm_name, club, total, nett, race_scores, raced, class_name}.
    result_status: from regattas.result_status.
    as_at_time: for status line; from results table (one row) per Result rule, fallback to regattas.as_at_time."""
    t0 = time.time()
    print(f"REGATTA_DATA: step=start time={time.time() - t0:.3f}", flush=True)
    if not regatta_id or not table_exists("regattas") or not table_exists("regatta_blocks") or not table_exists("results"):
        return None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            try:
                cur.execute("""
                    SELECT r.event_name, r.start_date, r.end_date,
                           COALESCE(c.club_abbrev, c.club_fullname, '') AS host_club_name,
                           TRIM(COALESCE(c.club_abbrev, '')) AS host_club_abbrev,
                           TRIM(COALESCE(c.club_fullname, '')) AS host_club_fullname,
                           c.province AS host_club_province,
                           r.result_status, r.as_at_time
                    FROM regattas r
                    LEFT JOIN clubs c ON c.club_id = r.host_club_id
                    WHERE r.regatta_id = %s
                """, (regatta_id,))
            except Exception:
                cur.execute("""
                    SELECT r.event_name, r.start_date, r.end_date,
                           COALESCE(c.club_abbrev, c.club_fullname, '') AS host_club_name,
                           TRIM(COALESCE(c.club_abbrev, '')) AS host_club_abbrev,
                           TRIM(COALESCE(c.club_fullname, '')) AS host_club_fullname,
                           c.province AS host_club_province
                    FROM regattas r
                    LEFT JOIN clubs c ON c.club_id = r.host_club_id
                    WHERE r.regatta_id = %s
                """, (regatta_id,))
            row = cur.fetchone()
            if not row:
                return None
            event_name = (row.get("event_name") or "").strip()
            host_club_name = (row.get("host_club_name") or "").strip()
            host_club_abbrev = (row.get("host_club_abbrev") or "").strip()
            host_club_fullname = (row.get("host_club_fullname") or "").strip()
            host_club_province = (row.get("host_club_province") or "").strip() or None
            start_date = row.get("start_date")
            end_date = row.get("end_date")
            result_status = (row.get("result_status") or "").strip() or "Final"
            as_at_time = row.get("as_at_time")
            print(f"REGATTA_DATA: step=after_regatta_meta time={time.time() - t0:.3f}", flush=True)
            # Status-line timestamp: prefer results table (per Result rule), fallback to regattas.as_at_time
            cur.execute("""
                SELECT as_at_time FROM results
                WHERE regatta_id = %s AND as_at_time IS NOT NULL
                ORDER BY result_id LIMIT 1
            """, (regatta_id,))
            res_row = cur.fetchone()
            if res_row and res_row.get("as_at_time"):
                as_at_time = res_row["as_at_time"]
            print(f"REGATTA_DATA: step=after_as_at_time time={time.time() - t0:.3f}", flush=True)

            cur.execute("""
                SELECT rb.block_id,
                       COALESCE(TRIM(rb.fleet_label), TRIM(rb.class_canonical), TRIM(rb.class_original), 'Fleet') AS fleet_name,
                       rb.fleet_label, rb.class_canonical,
                       rb.races_sailed, rb.discard_count, rb.to_count, rb.scoring_system,
                       res.result_id,
                       res.rank, res.sail_number, res.helm_name, res.crew_name,
                       res.boat_name, res.jib_no, res.bow_no, res.hull_no,
                       COALESCE(TRIM(c.club_abbrev), TRIM(res.club_raw), '') AS club,
                       res.club_id, COALESCE(c.club_abbrev, c.club_fullname) AS club_fullname,
                       res.helm_sa_sailing_id, res.crew_sa_sailing_id,
                       res.total_points_raw, res.nett_points_raw, res.race_scores, res.raced,
                       COALESCE(TRIM(c_res.class_name), TRIM(res.class_original), '') AS class_name,
                       COALESCE(res.class_id, rb.class_id) AS result_class_id
                FROM regatta_blocks rb
                JOIN results res ON res.block_id = rb.block_id AND res.regatta_id = rb.regatta_id
                LEFT JOIN clubs c ON c.club_id = res.club_id
                LEFT JOIN classes c_res ON c_res.class_id = res.class_id
                WHERE rb.regatta_id = %s
                ORDER BY rb.block_id, COALESCE(res.rank, 99999), res.result_id
            """, (regatta_id,))
            raw = cur.fetchall() or []
            print(f"REGATTA_DATA: step=after_main_join time={time.time() - t0:.3f}", flush=True)
            dup_names = set()
            cur.execute("""
                SELECT LOWER(TRIM(COALESCE(full_name, first_name || ' ' || COALESCE(last_name, '')))) AS n
                FROM sas_id_personal WHERE full_name IS NOT NULL OR first_name IS NOT NULL OR last_name IS NOT NULL
                GROUP BY LOWER(TRIM(COALESCE(full_name, first_name || ' ' || COALESCE(last_name, ''))))
                HAVING COUNT(*) > 1
            """)
            for row in cur.fetchall() or []:
                if row.get("n"):
                    dup_names.add(row["n"])
            # Batch name and slug lookups: one query for all sailor names, then slug in Python (no per-row DB)
            sas_ids = set()
            for r in raw:
                h, c = r.get("helm_sa_sailing_id"), r.get("crew_sa_sailing_id")
                if h is not None and str(h).strip().isdigit():
                    sas_ids.add(str(h).strip())
                if c is not None and str(c).strip().isdigit():
                    sas_ids.add(str(c).strip())
            name_map = {}
            slug_map = {}
            if sas_ids:
                cur.execute("""
                    SELECT sa_sailing_id::text AS sas_id,
                           COALESCE(TRIM(full_name), TRIM(first_name || ' ' || COALESCE(last_name, ''))) AS full_name
                    FROM sas_id_personal
                    WHERE sa_sailing_id::text = ANY(%s)
                """, (list(sas_ids),))
                for row in cur.fetchall() or []:
                    sid = str(row.get("sas_id") or "")
                    name_map[sid] = (row.get("full_name") or "").strip()
                for sid, nm in name_map.items():
                    has_dup = (nm.lower() in dup_names) if nm else False
                    slug_map[sid] = _sailor_canonical_slug(nm, sid, has_dup) if nm else None
            print(f"REGATTA_DATA: step=after_dup_names time={time.time() - t0:.3f}", flush=True)
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[regatta standalone] _get_regatta_full_page_data: {e}")
        return None
    print(f"REGATTA_DATA: step=after_db_calls time={time.time() - t0:.3f}", flush=True)
    fleets = []
    by_block = {}
    for r in raw:
        bid = r.get("block_id")
        rs = r.get("race_scores")
        if isinstance(rs, str) and rs:
            try:
                rs = json.loads(rs)
            except Exception:
                rs = {}
        if not isinstance(rs, dict):
            rs = {}
        if bid not in by_block:
            class_name_for_slug = (r.get("class_name") or "").strip()
            class_slug = _class_canonical_slug(class_name_for_slug) if class_name_for_slug else ""
            by_block[bid] = {
                "block_id": bid,
                "name": (r.get("fleet_name") or "Fleet").strip(),
                "fleet_label": (r.get("fleet_label") or r.get("class_canonical") or "").strip(),
                "races_sailed": r.get("races_sailed"),
                "discard_count": r.get("discard_count"),
                "to_count": r.get("to_count"),
                "scoring_system": r.get("scoring_system") or "Appendix A",
                "rows": [],
                "regatta_id": regatta_id,
                "class_slug": class_slug,
            }
        club_fn = (r.get("club_abbrev") or r.get("club_fullname") or "").strip()
        club_slug = _club_slug_from_name(club_fn or r.get("club") or "") if (r.get("club_id") and (club_fn or r.get("club"))) else None
        helm_name = r.get("helm_name")
        helm_sas_id = str(r.get("helm_sa_sailing_id") or "") if r.get("helm_sa_sailing_id") is not None else ""
        helm_norm = (helm_name or "").strip().lower() if helm_name else ""
        has_dup = helm_norm in dup_names or (helm_sas_id and helm_sas_id.isdigit())
        helm_slug = slug_map.get(helm_sas_id) if (helm_sas_id and helm_sas_id.isdigit()) else None
        if helm_slug is None and helm_sas_id and helm_sas_id.isdigit():
            nm = name_map.get(helm_sas_id) or helm_name
            if nm:
                helm_slug = _sailor_canonical_slug(nm, helm_sas_id, has_dup)
        crew_name = r.get("crew_name")
        crew_sas_id = str(r.get("crew_sa_sailing_id") or "") if r.get("crew_sa_sailing_id") is not None else ""
        crew_norm = (crew_name or "").strip().lower() if crew_name else ""
        crew_has_dup = crew_norm in dup_names or (crew_sas_id and crew_sas_id.isdigit())
        crew_slug = slug_map.get(crew_sas_id) if (crew_sas_id and crew_sas_id.isdigit()) else None
        if crew_slug is None and crew_sas_id and crew_sas_id.isdigit():
            nm = name_map.get(crew_sas_id) or crew_name
            if nm:
                crew_slug = _sailor_canonical_slug(nm, crew_sas_id, crew_has_dup)
        by_block[bid]["rows"].append({
            "result_id": r.get("result_id"),
            "rank": r.get("rank"),
            "sail_number": r.get("sail_number"),
            "helm_name": helm_name,
            "helm_slug": helm_slug,
            "helm_sa_sailing_id": r.get("helm_sa_sailing_id"),
            "crew_name": crew_name,
            "crew_slug": crew_slug,
            "crew_sa_sailing_id": r.get("crew_sa_sailing_id"),
            "boat_name": r.get("boat_name"),
            "jib_no": r.get("jib_no"),
            "bow_no": r.get("bow_no"),
            "hull_no": r.get("hull_no"),
            "club": r.get("club"),
            "club_id": r.get("club_id"),
            "club_slug": club_slug,
            "total": r.get("total_points_raw"),
            "nett": r.get("nett_points_raw"),
            "race_scores": rs,
            "raced": r.get("raced"),
            "class_name": (r.get("class_name") or "").strip(),
            "result_class_id": r.get("result_class_id"),
        })
    for bid in sorted(by_block.keys()):
        bl = by_block[bid]
        bl["entries"] = len(bl["rows"])
        fleets.append(bl)
    print(f"REGATTA_DATA: step=before_return time={time.time() - t0:.3f}", flush=True)
    return (
        event_name,
        host_club_name,
        start_date,
        end_date,
        fleets,
        result_status,
        as_at_time,
        host_club_province,
        host_club_abbrev,
        host_club_fullname,
    )


def _get_club_slug_by_id(club_id):
    """Return club slug for club_id or None."""
    if not club_id:
        return None
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute(
                "SELECT COALESCE(club_abbrev, club_fullname) AS name FROM clubs WHERE club_id = %s",
                (club_id,),
            )
            row = cur.fetchone()
            if row and row.get("name"):
                return _club_slug_from_name(str(row["name"]))
        finally:
            cur.close()
            return_db_connection(conn)
    except Exception:
        pass
    return None


def _get_regatta_seo_preview(regatta_id: str):
    """Return dict with num_classes, num_sailors, class_names[], top_results[] for server-rendered SEO block."""
    out = {"num_classes": 0, "num_sailors": 0, "class_names": [], "top_results": []}
    if not regatta_id or not table_exists("regattas") or not table_exists("regatta_blocks") or not table_exists("results"):
        return out
    try:
        conn = get_db_connection()
        cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
        try:
            cur.execute("""
                SELECT COALESCE(TRIM(rb.fleet_label), TRIM(rb.class_canonical), TRIM(rb.class_original), 'Class') AS class_name
                FROM regatta_blocks rb
                WHERE rb.regatta_id = %s
                ORDER BY rb.block_id
            """, (regatta_id,))
            rows = cur.fetchall() or []
            seen = set()
            for r in rows:
                name = (r.get("class_name") or "Class").strip()
                if name and name not in seen:
                    seen.add(name)
                    out["class_names"].append(name)
            out["num_classes"] = len(out["class_names"])

            cur.execute("""
                SELECT COUNT(DISTINCT res.helm_sa_sailing_id::text) AS cnt
                FROM results res
                WHERE res.regatta_id = %s AND res.helm_sa_sailing_id IS NOT NULL
            """, (regatta_id,))
            row = cur.fetchone()
            if row and row.get("cnt") is not None:
                out["num_sailors"] = int(row["cnt"])
            if out["num_sailors"] == 0:
                cur.execute("SELECT COUNT(*) AS cnt FROM results res WHERE res.regatta_id = %s", (regatta_id,))
                row = cur.fetchone()
                if row and row.get("cnt") is not None:
                    out["num_sailors"] = int(row["cnt"])

            cur.execute("""
                SELECT DISTINCT ON (res.block_id, res.rank)
                       COALESCE(TRIM(res.helm_name), '') AS helm_name,
                       COALESCE(TRIM(rb.fleet_label), TRIM(rb.class_canonical), TRIM(rb.class_original), '') AS class_name,
                       res.rank
                FROM results res
                JOIN regatta_blocks rb ON rb.block_id = res.block_id AND rb.regatta_id = res.regatta_id
                WHERE res.regatta_id = %s AND res.rank IN (1, 2, 3)
                ORDER BY res.block_id, res.rank
                LIMIT 15
            """, (regatta_id,))
            for r in cur.fetchall() or []:
                out["top_results"].append({
                    "class_name": (r.get("class_name") or "").strip() or "—",
                    "rank": r.get("rank") or 0,
                    "helm_name": (r.get("helm_name") or "").strip() or "—",
                })
        finally:
            cur.close()
            conn.close()
    except Exception as e:
        print(f"[SEO] _get_regatta_seo_preview: {e}")
    return out


