def _wc_fleet_editable_cell(
    wc_sa_fleet_edit: bool,
    result_id_row,
    *,
    public_inner_html: str,
    value_plain: str,
    data_field: Optional[str] = None,
    race_key: Optional[str] = None,
    maxlength: int = 220,
    wrap_autocomplete: Optional[str] = None,
    extra_input_attrs: str = "",
) -> str:
    """Wrap public table cell HTML with a super-admin-only text input (WC standalone)."""
    if not wc_sa_fleet_edit or not result_id_row:
        return public_inner_html
    rid_attr = html_module.escape(str(result_id_row), quote=True)
    vq = html_module.escape(value_plain or "", quote=True)
    if race_key:
        rk = html_module.escape(race_key, quote=True)
        extra = f' data-race="{rk}"'
    else:
        if not data_field:
            return public_inner_html
        fk = html_module.escape(data_field, quote=True)
        extra = f' data-field="{fk}"'
    xin = extra_input_attrs or ""
    ac_cls = "wc-result-field-input wc-sa-edit-only"
    if wrap_autocomplete and xin and (
        "data-resolved-club-id" in xin or "data-resolved-class-id" in xin or "data-resolved-person-key" in xin
    ):
        ac_cls += " wc-sa-input--valid"
    inp = (
        f'<input type="text" class="{ac_cls}" data-result-id="{rid_attr}"{extra}{xin} '
        f'data-original="{vq}" value="{vq}" maxlength="{maxlength}" autocomplete="off" />'
    )
    if wrap_autocomplete:
        ac = html_module.escape(wrap_autocomplete, quote=True)
        inp = (
            f'<div class="wc-sa-ac-wrap" data-wc-ac="{ac}">'
            f"{inp}"
            f'<div class="wc-sa-ac-preview"></div>'
            f'<ul class="wc-sa-ac-list" role="listbox" hidden></ul>'
            f"</div>"
        )
    return f'<span class="wc-sa-edit-hide">{public_inner_html}</span>' + inp


def _render_result_sheet_fleet(
    fleet: dict,
    standalone_class_page: bool = False,
    *,
    column_prefs: Optional[dict] = None,
    wc_sa_fleet_edit: bool = False,
) -> str:
    """Render one fleet as HTML using the same structure and class names as admin regatta_viewer result sheet popup.
    When standalone_class_page is True (e.g. /regatta/{id}/class-{slug}), header is class name only, no 'Fleet' suffix.
    When column_prefs is set (WC pilot), unchecked keys hide columns; checked keys show columns for everyone (admin and public).
    Optional columns (boat/jib/bow/hull/crew) show when the pref is on even if cells are empty.
    When column_prefs is None (other regattas), optional columns only appear when at least one row has data (legacy)."""
    prefs = column_prefs if isinstance(column_prefs, dict) else None

    def _pref_on(key: str) -> bool:
        if prefs is None:
            return True
        if key not in prefs:
            return True
        return bool(prefs.get(key))

    def _optional_col_visible(pref_key: str, has_data: bool) -> bool:
        """Legacy regattas: optional column only if has_data. WC prefs: follow checkbox only."""
        if prefs is None:
            return has_data
        return _pref_on(pref_key)

    fname = (fleet.get("name") or "Fleet").strip()
    fleet_label = (fleet.get("fleet_label") or "").strip()
    class_canonical = (fleet.get("class_canonical") or "").strip()
    # Header title: must show e.g. "420 Fleet" not just "Fleet". Use fleet_label or class_canonical from block/rows when name is fallback.
    if standalone_class_page:
        base = (fleet_label or class_canonical or fname).strip()
        fleet_header_title = base.replace(" Fleet", "").strip() or "Results"
    elif fname == "Fleet" and (fleet_label or class_canonical):
        fleet_header_title = (fleet_label or class_canonical) + (" Fleet" if not (fleet_label or class_canonical).endswith(" Fleet") else "")
    elif fname.endswith(" Fleet") or fname == "Fleet":
        fleet_header_title = fname
    else:
        fleet_header_title = fname + " Fleet" if not fname.endswith(" Fleet") else fname
    fleet_title_inner = fleet_header_title
    regatta_id = fleet.get("regatta_id")
    class_slug = (fleet.get("class_slug") or "").strip()
    if regatta_id and class_slug:
        fleet_header_title = f'<a href="/regatta/{html_module.escape(regatta_id)}/class-{html_module.escape(class_slug)}">{html_module.escape(fleet_title_inner)}</a>'
    else:
        fleet_header_title = html_module.escape(fleet_title_inner)
    block_id = (fleet.get("block_id") or "").strip()
    if wc_sa_fleet_edit and block_id and regatta_id:
        rid_s = html_module.escape(str(regatta_id))
        bid_s = html_module.escape(block_id)
        inner_s = html_module.escape(fleet_title_inner)
        fleet_header_html = (
            f'<div class="fleet-header-title-wrap">'
            f'<span class="fleet-title-public-nav">{fleet_header_title}</span>'
            f'<button type="button" class="fleet-sa-edit-hit" data-block-id="{bid_s}" data-regatta-id="{rid_s}" aria-label="Edit fleet or class">{inner_s}</button>'
            f"</div>"
        )
    else:
        fleet_header_html = fleet_header_title
    rows = fleet.get("rows") or []

    def _max_race_idx_from_result_rows(result_rows):
        """If block.races_sailed is 0 but JSON has R1..Rn, infer n so public sheet shows race columns."""
        m = 0
        for r in result_rows:
            rs = r.get("race_scores") or {}
            if isinstance(rs, str) and rs.strip():
                try:
                    rs = json.loads(rs)
                except Exception:
                    rs = {}
            if not isinstance(rs, dict):
                continue
            for k in rs:
                if not isinstance(k, str):
                    continue
                ku = k.upper()
                if ku.startswith("R") and len(ku) > 1 and ku[1:].isdigit():
                    m = max(m, int(ku[1:]))
        return m

    races_sailed_db = int(fleet.get("races_sailed") or 0)
    max_race_from_scores = _max_race_idx_from_result_rows(rows)
    races_sailed = max(races_sailed_db, max_race_from_scores)
    discard_count = fleet.get("discard_count") or 0
    to_count = fleet.get("to_count")
    if to_count is None and discard_count is not None:
        to_count = max(0, int(races_sailed) - int(discard_count))
    entries = fleet.get("entries") or 0
    scoring_system = fleet.get("scoring_system") or "Appendix A"
    sailed_line = f"Sailed: {races_sailed}, Discards: {discard_count}, To count: {to_count}, Entries: {entries}, Scoring system: {scoring_system}"

    def _row_has_crew(row):
        if (row.get("crew_name") or "").strip():
            return True
        cl = row.get("crew_list") or []
        return any((x.get("role") or "").strip().lower() == "crew" for x in cl)

    has_crew = any(_row_has_crew(r) for r in rows)
    has_boat_name = any((r.get("boat_name") or "").strip() for r in rows)
    has_jib_no = any((r.get("jib_no") or "").strip() for r in rows)
    has_bow_no = any((r.get("bow_no") or "").strip() for r in rows)
    has_hull_no = any((r.get("hull_no") or "").strip() for r in rows)
    race_columns = []
    if races_sailed:
        n = int(races_sailed)
        if prefs is None:
            for i in range(1, n + 1):
                rkey = f"R{i}"
                if any((r.get("race_scores") or {}).get(rkey, "").strip() for r in rows):
                    race_columns.append(rkey)
        elif _pref_on("race_scores"):
            for i in range(1, n + 1):
                race_columns.append(f"R{i}")

    show_boat = _optional_col_visible("boat_name", has_boat_name)
    show_jib = _optional_col_visible("jib", has_jib_no)
    show_bow = _optional_col_visible("bow", has_bow_no)
    show_hull = _optional_col_visible("hull", has_hull_no)
    show_crew_col = _optional_col_visible("crew", has_crew)
    show_races = bool(race_columns)

    thead = ""
    if _pref_on("rank"):
        thead += '<th class="rank-col">Rank</th>'
    if _pref_on("fleet"):
        thead += "<th>Fleet</th>"
    if _pref_on("class"):
        thead += "<th>Class</th>"
    if _pref_on("sail_no"):
        thead += '<th class="sail-col">Sail No</th>'
    if show_boat:
        thead += "<th>Boat Name</th>"
    if show_jib:
        thead += "<th>Jib No</th>"
    if show_bow:
        thead += "<th>Bow No</th>"
    if show_hull:
        thead += "<th>Hull No</th>"
    if _pref_on("club"):
        thead += '<th class="club-col">Club</th>'
    if _pref_on("helm"):
        thead += '<th class="helm-col">Helm</th>'
    if show_crew_col:
        thead += "<th>Crew</th>"
    if show_races:
        for rc in race_columns:
            thead += f"<th>{html_module.escape(rc)}</th>"
    if _pref_on("total"):
        thead += "<th>Total</th>"
    if _pref_on("nett"):
        thead += '<th class="nett-col">Nett</th>'

    trs = []
    for r in rows:
        race_scores = r.get("race_scores") or {}
        rank_num = int(r.get("rank")) if r.get("rank") is not None else 0
        medal_class = ""
        if rank_num == 1:
            medal_class = "medal-gold"
        elif rank_num == 2:
            medal_class = "medal-silver"
        elif rank_num == 3:
            medal_class = "medal-bronze"
        did_not_race = r.get("raced") is False or r.get("raced") == 0
        strike_class = "strike-out" if did_not_race else ""
        row_classes = " ".join(c for c in (medal_class, strike_class) if c)
        rank_str = _format_rank(r.get("rank"))
        fleet_str = html_module.escape(fleet_label)
        class_str = html_module.escape(r.get("class_name") or "")
        sail_str = html_module.escape(str(r.get("sail_number") or ""))
        club_raw = str(r.get("club") or "")
        club_slug = r.get("club_slug")
        club_link_html = (
            f'<a href="/club/{html_module.escape(club_slug)}">{html_module.escape(club_raw)}</a>'
            if club_slug and club_raw
            else html_module.escape(club_raw)
        )
        result_id_row = r.get("result_id")
        crew_list = r.get("crew_list") or []
        crew_raw_for_edit = ""
        if crew_list:
            helm_entries = [x for x in crew_list if (x.get("role") or "").strip().lower() == "helm"]
            crew_entries = [x for x in crew_list if (x.get("role") or "").strip().lower() == "crew"]
            helm_raw = (helm_entries[0].get("sailor_name") or "").strip() if helm_entries else str(r.get("helm_name") or "")
            helm_slug = r.get("helm_slug")
            helm_str = (
                f'<a href="/sailor/{html_module.escape(helm_slug)}">{html_module.escape(helm_raw)}</a>'
                if helm_slug and helm_raw
                else html_module.escape(helm_raw)
            )
            crew_names = [(x.get("sailor_name") or "").strip() for x in crew_entries if (x.get("sailor_name") or "").strip()]
            crew_raw_for_edit = ", ".join(crew_names) if crew_names else (r.get("crew_name") or "").strip()
            crew_str = "Crew: " + ", ".join(html_module.escape(n) for n in crew_names) if crew_names else ""
        else:
            helm_raw = str(r.get("helm_name") or "")
            helm_slug = r.get("helm_slug")
            helm_str = (
                f'<a href="/sailor/{html_module.escape(helm_slug)}">{html_module.escape(helm_raw)}</a>'
                if helm_slug and helm_raw
                else html_module.escape(helm_raw)
            )
            crew_raw = str(r.get("crew_name") or "")
            crew_raw_for_edit = crew_raw
            crew_slug = r.get("crew_slug")
            crew_str = (
                f'<a href="/sailor/{html_module.escape(crew_slug)}">{html_module.escape(crew_raw)}</a>'
                if crew_slug and crew_raw
                else html_module.escape(crew_raw)
            )

        def _wc_cell(
            inner_html: str,
            plain: str,
            field: Optional[str] = None,
            race_k: Optional[str] = None,
            mx: int = 220,
            ac: Optional[str] = None,
            xin: str = "",
        ) -> str:
            return _wc_fleet_editable_cell(
                wc_sa_fleet_edit,
                result_id_row,
                public_inner_html=inner_html,
                value_plain=plain,
                data_field=field,
                race_key=race_k,
                maxlength=mx,
                wrap_autocomplete=ac,
                extra_input_attrs=xin,
            )

        class_name_raw = (r.get("class_name") or "")
        club_row_id = r.get("club_id")
        club_xin = ""
        if club_row_id is not None and str(club_raw).strip():
            cs = str(club_raw).strip().upper()
            club_xin = (
                f' data-resolved-club-id="{html_module.escape(str(int(club_row_id)), quote=True)}"'
                f' data-original-resolved-club-id="{html_module.escape(str(int(club_row_id)), quote=True)}"'
                f' data-resolved-code="{html_module.escape(cs, quote=True)}"'
            )
        rcid = r.get("result_class_id")
        class_xin = ""
        if rcid is not None and (class_name_raw or "").strip():
            cn = (class_name_raw or "").strip()
            canon = _class_canonical_slug(cn)
            cpath = f"/class/{int(rcid)}-{canon}" if canon else f"/class/{int(rcid)}"
            class_xin = (
                f' data-resolved-class-id="{html_module.escape(str(int(rcid)), quote=True)}"'
                f' data-original-resolved-class-id="{html_module.escape(str(int(rcid)), quote=True)}"'
                f' data-class-path="{html_module.escape(cpath, quote=True)}"'
            )
        helm_xin = ""
        hs = r.get("helm_sa_sailing_id")
        if hs is not None and str(hs).strip().isdigit() and (helm_raw or "").strip():
            hk = f"SAS:{int(hs)}"
            hnm = (helm_raw or "").strip()
            helm_xin = (
                f' data-resolved-person-key="{html_module.escape(hk, quote=True)}"'
                f' data-original-resolved-person-key="{html_module.escape(hk, quote=True)}"'
                f' data-resolved-person-name="{html_module.escape(hnm, quote=True)}"'
            )
        crew_xin = ""
        csid = r.get("crew_sa_sailing_id")
        if csid is not None and str(csid).strip().isdigit() and crew_raw_for_edit.strip():
            ck = f"SAS:{int(csid)}"
            cnm = crew_raw_for_edit.strip()
            crew_xin = (
                f' data-resolved-person-key="{html_module.escape(ck, quote=True)}"'
                f' data-original-resolved-person-key="{html_module.escape(ck, quote=True)}"'
                f' data-resolved-person-name="{html_module.escape(cnm, quote=True)}"'
            )
        sail_raw = str(r.get("sail_number") or "")
        total_plain = str(r.get("total")) if r.get("total") is not None else ""
        nett_plain = str(r.get("nett")) if r.get("nett") is not None else ""
        rank_plain = "" if r.get("rank") is None else str(r.get("rank")).strip()
        total_str = html_module.escape(total_plain)
        nett_str = html_module.escape(nett_plain)
        row_html = f'<tr class="{row_classes}">'
        if _pref_on("rank"):
            row_html += f'<td class="rank-col">{_wc_cell(html_module.escape(rank_str), rank_plain, "rank", None, 8)}</td>'
        if _pref_on("fleet"):
            row_html += f"<td>{fleet_str}</td>"
        if _pref_on("class"):
            row_html += f"<td>{_wc_cell(class_str, class_name_raw, 'class_name', None, 64, 'class', class_xin)}</td>"
        if _pref_on("sail_no"):
            row_html += f'<td class="sail-col">{_wc_cell(sail_str, sail_raw, "sail_number", None, 32)}</td>'
        if show_boat:
            bn = str(r.get("boat_name") or "")
            row_html += f'<td>{_wc_cell(html_module.escape(bn), bn, "boat_name", None, 120)}</td>'
        if show_jib:
            jv = str(r.get("jib_no") or "")
            row_html += f'<td>{_wc_cell(html_module.escape(jv), jv, "jib_no", None, 32)}</td>'
        if show_bow:
            bv = str(r.get("bow_no") or "")
            row_html += f'<td>{_wc_cell(html_module.escape(bv), bv, "bow_no", None, 32)}</td>'
        if show_hull:
            hv = str(r.get("hull_no") or "")
            row_html += f'<td>{_wc_cell(html_module.escape(hv), hv, "hull_no", None, 32)}</td>'
        if _pref_on("club"):
            row_html += f'<td class="club-col">{_wc_cell(club_link_html, club_raw, "club_code", None, 32, "club", club_xin)}</td>'
        if _pref_on("helm"):
            row_html += f'<td class="helm-col">{_wc_cell(helm_str, helm_raw or "", "helm_name", None, 120, "helm", helm_xin)}</td>'
        if show_crew_col:
            row_html += f"<td>{_wc_cell(crew_str, crew_raw_for_edit, 'crew_name', None, 160, 'crew', crew_xin)}</td>"
        if show_races:
            for rkey in race_columns:
                score = (race_scores.get(rkey) or "").strip()
                is_discarded = score.startswith("(") and score.endswith(")")
                has_penalty = bool(re.search(r"\b(DNC|DNS|DNF|RET|DSQ|UFD|BFD|DPI|OCS)\b", score, re.I)) if score else False
                cell_class = "code" if has_penalty else ("disc" if is_discarded else ("score-counts" if score else ""))
                row_html += f'<td class="{cell_class}">{_wc_cell(html_module.escape(score), score, None, rkey, 48)}</td>'
        if _pref_on("total"):
            row_html += f'<td class="{strike_class}">{_wc_cell(total_str, total_plain, "total_points_raw", None, 24)}</td>'
        if _pref_on("nett"):
            row_html += f'<td class="nett-col {strike_class}">{_wc_cell(nett_str, nett_plain, "nett_points_raw", None, 24)}</td>'
        row_html += "</tr>"
        trs.append(row_html)
    table_html = f"<table><thead><tr>{thead}</tr></thead><tbody>{''.join(trs)}</tbody></table>"
    return (
        f'<div class="fleet-section">'
        f'<div class="class-header"><div class="fleet-title-row">{fleet_header_html}</div>'
        f'<div class="sailed-line">{html_module.escape(sailed_line)}</div></div>'
        f'<div class="table-wrapper">{table_html}</div></div>'
    )


